# ═══════════════════════════════════════════════════════════════════════════════
#       🔗 DÉTECTION DE LIENS MASQUÉS (Markdown [texte](url) phishing)
# ═══════════════════════════════════════════════════════════════════════════════

# Domaines de confiance utilisés par les scammers pour tromper
TRUSTED_DOMAINS_FOR_MASKING = [
    'discord.com', 'discord.gg', 'discord.gift', 'discordapp.com',
    'store.steampowered.com', 'steamcommunity.com',
    'roblox.com', 'twitter.com', 'x.com',
    'youtube.com', 'twitch.tv', 'tiktok.com',
]

def check_masked_links(content):
    """Détecte les liens markdown masqués : [texte légitime](url malveillante)"""
    # Pattern : [texte contenant un domaine](url réelle)
    masked = re.findall(r'\[([^\]]+)\]\((https?://[^)]+)\)', content)
    for display_text, real_url in masked:
        # Extraire le domaine du texte affiché (s'il contient un domaine)
        display_domains = re.findall(r'(?:https?://)?([a-zA-Z0-9][-a-zA-Z0-9]*\.(?:com|gg|gift|org|net|tv|io|co)(?:/\S*)?)', display_text)
        if not display_domains:
            continue
        # Extraire le domaine de l'URL réelle
        real_domain_match = re.search(r'https?://([^/\s]+)', real_url)
        if not real_domain_match:
            continue
        real_domain = real_domain_match.group(1).lower()
        # Vérifier si le texte prétend être un domaine de confiance mais l'URL est différente
        for disp_dom in display_domains:
            disp_dom_clean = disp_dom.split('/')[0].lower()
            # Le texte montre un domaine de confiance...
            if any(trusted in disp_dom_clean for trusted in TRUSTED_DOMAINS_FOR_MASKING):
                # ...mais l'URL réelle pointe vers un domaine différent
                if not any(trusted in real_domain for trusted in TRUSTED_DOMAINS_FOR_MASKING):
                    return True, f"Lien masqué: [{disp_dom_clean}] → {real_domain}"
    return False, None

# Cache pour détecter les comportements suspects
compromised_cache = {}  # {user_id: {'messages': [], 'flags': 0}}

# Initialiser les variables globales avec les nouvelles bases
PHISHING = PHISHING_DOMAINS
SCAM_PATTERNS = [re.compile(p, re.IGNORECASE) for p in COMPROMISED_PATTERNS]

# ═══════════════════════════════════════════════════════════════════════════════
#                           🛡️ FONCTIONS DE PROTECTION AVANCÉES
# ═══════════════════════════════════════════════════════════════════════════════

def advanced_phishing_check(content):
    """Vérifie le contenu pour détecter le phishing avec analyse avancée"""
    content_lower = content.lower()
    detected = []
    
    # 1. Vérifier les domaines de phishing connus
    urls = re.findall(r'https?://([^\s<>"\']+)', content_lower)
    for url in urls:
        domain = url.split('/')[0].split('?')[0]
        
        # Domaines exacts
        for phish_domain in PHISHING_DOMAINS:
            if phish_domain in domain:
                return True, f"Domaine phishing: {domain}", "domain"
        
        # Patterns d'URL suspects
        for pattern in PHISHING_URL_PATTERNS:
            if re.search(pattern, url):
                return True, f"URL suspecte: {url[:50]}", "url_pattern"
        
        # Typosquatting Discord
        if 'disc' in domain and 'discord.com' not in domain and 'discord.gg' not in domain:
            if any(x in domain for x in ['gift', 'nitro', 'free', 'claim', 'app']):
                return True, f"Typosquatting Discord: {domain}", "typosquatting"
        
        # Typosquatting Steam
        if 'steam' in domain and 'steampowered.com' not in domain and 'steamcommunity.com' not in domain:
            if any(x in domain for x in ['community', 'trade', 'gift', 'login']):
                return True, f"Typosquatting Steam: {domain}", "typosquatting"
        
        # TLD suspects avec mots-clés
        suspect_tlds = ['.ru', '.tk', '.ml', '.ga', '.cf', '.gq', '.xyz', '.top', '.buzz']
        if any(domain.endswith(tld) for tld in suspect_tlds):
            if any(kw in domain for kw in ['discord', 'nitro', 'steam', 'gift', 'free', 'crypto']):
                return True, f"TLD suspect: {domain}", "suspect_tld"
    
    # 2. Vérifier les patterns de messages phishing
    phishing_message_patterns = [
        r'(click|cliquez).*link.*claim',
        r'congratulations.*won',
        r'félicitations.*gagné',
        r'verify.*account.*http',
        r'vérifier.*compte.*http',
        r'@everyone.*free.*http',
        r'@here.*free.*http',
        r'limited.*time.*http',
        r'expire.*24.*hour',
    ]
    
    for pattern in phishing_message_patterns:
        if re.search(pattern, content_lower):
            return True, f"Pattern phishing: {pattern}", "message_pattern"
    
    return False, None, None

def advanced_scam_check(content):
    """Vérifie le contenu pour détecter les scams avec analyse avancée"""
    content_lower = content.lower()
    
    # 1. Vérifier les mots-clés de scam
    scam_score = 0
    detected_keywords = []
    
    for keyword in SCAM_KEYWORDS:
        if keyword in content_lower:
            scam_score += 10
            detected_keywords.append(keyword)
    
    # 2. Combinaisons dangereuses
    dangerous_combos = [
        (['free', 'nitro', 'http'], 30),
        (['@everyone', 'http'], 25),
        (['@here', 'http'], 25),
        (['free', 'gift', 'http'], 25),
        (['click', 'claim', 'http'], 20),
        (['dm', 'me', 'money'], 15),
        (['crypto', 'investment', 'profit'], 20),
        (['send', 'eth', 'receive'], 30),
        (['double', 'crypto'], 30),
    ]
    
    for combo, score in dangerous_combos:
        if all(word in content_lower for word in combo):
            scam_score += score
            detected_keywords.extend(combo)
    
    # 3. Urgence artificielle
    urgency_patterns = [
        r'(only|seulement)\s*\d+\s*(left|remaining|restant)',
        r'(expire|end)s?\s*(in|dans)\s*\d+',
        r'(hurry|vite|dépêche)',
        r'(last|dernier)\s*(chance|opportunit)',
        r'(act|agir)\s*(now|maintenant)',
    ]
    
    for pattern in urgency_patterns:
        if re.search(pattern, content_lower):
            scam_score += 10
    
    # Seuil de détection
    if scam_score >= 25:
        return True, ", ".join(set(detected_keywords[:5])), scam_score
    
    return False, None, 0

def check_compromised_behavior(user_id, guild_id, content, has_mentions_everyone=False):
    """Détecte si un compte semble compromis basé sur son comportement"""
    key = (guild_id, user_id)
    current_time = now()
    
    # Initialiser le cache
    if key not in compromised_cache:
        compromised_cache[key] = {
            'messages': [],
            'flags': 0,
            'last_flag': None
        }
    
    cache = compromised_cache[key]
    
    # Nettoyer les anciens messages (garder 5 min)
    cache['messages'] = [
        m for m in cache['messages']
        if (current_time - m['time']).total_seconds() < 300
    ]
    
    # Ajouter ce message
    cache['messages'].append({
        'time': current_time,
        'has_link': bool(re.search(r'https?://', content)),
        'has_everyone': has_mentions_everyone,
        'length': len(content)
    })
    
    # Analyser le comportement
    flags = 0
    reasons = []
    
    recent_messages = cache['messages']
    
    # 1. Plusieurs @everyone avec liens en peu de temps
    everyone_with_links = sum(1 for m in recent_messages if m['has_everyone'] and m['has_link'])
    if everyone_with_links >= 2:
        flags += 50
        reasons.append("Spam @everyone + liens")
    
    # 2. Messages identiques répétés
    if len(recent_messages) >= 3:
        # Vérifier si c'est le même pattern
        link_count = sum(1 for m in recent_messages if m['has_link'])
        if link_count >= 3:
            flags += 30
            reasons.append("Spam de liens")
    
    # 3. Comportement anormal (premier message = @everyone + lien)
    if len(recent_messages) == 1 and has_mentions_everyone and re.search(r'https?://', content):
        flags += 40
        reasons.append("Premier message suspect")
    
    cache['flags'] = flags
    
    return flags >= 40, reasons, flags

def check_dangerous_file(filename):
    """Vérifie si un fichier a une extension dangereuse"""
    filename_lower = filename.lower()
    for ext in DANGEROUS_EXTENSIONS:
        if filename_lower.endswith(ext):
            return True, ext
    return False, None

def check_qr_code_scam(content):
    """Détecte les tentatives de scam par QR code"""
    qr_patterns = [
        r'scan.*qr.*code',
        r'qr.*code.*scan',
        r'scanner.*code',
        r'discord.*token',
        r'login.*qr',
        r'authenticate.*qr',
        r'qr.*gift',
        r'qr.*nitro',
    ]
    
    content_lower = content.lower()
    for pattern in qr_patterns:
        if re.search(pattern, content_lower):
            return True, pattern
    
    return False, None

# ═══════════════════════════════════════════════════════════════════════════════
#                           👥 DÉTECTION COMPTES SECONDAIRES
# ═══════════════════════════════════════════════════════════════════════════════

def normalize_username(name):
    """Normalise un nom d'utilisateur pour comparaison"""
    name = name.lower()
    # Supprimer les chiffres à la fin
    name = re.sub(r'\d+$', '', name)
    # Supprimer les caractères spéciaux
    name = re.sub(r'[^a-z0-9]', '', name)
    # Remplacer les substitutions courantes
    replacements = {
        '0': 'o', '1': 'l', '3': 'e', '4': 'a', '5': 's',
        '7': 't', '8': 'b', '@': 'a', '$': 's'
    }
    for old, new in replacements.items():
        name = name.replace(old, new)
    return name

def levenshtein_distance(s1, s2):
    """Calcule la distance de Levenshtein entre deux chaînes"""
    if len(s1) < len(s2):
        return levenshtein_distance(s2, s1)
    
    if len(s2) == 0:
        return len(s1)
    
    previous_row = range(len(s2) + 1)
    for i, c1 in enumerate(s1):
        current_row = [i + 1]
        for j, c2 in enumerate(s2):
            insertions = previous_row[j + 1] + 1
            deletions = current_row[j] + 1
            substitutions = previous_row[j] + (c1 != c2)
            current_row.append(min(insertions, deletions, substitutions))
        previous_row = current_row
    
    return previous_row[-1]

def username_similarity(name1, name2):
    """Calcule la similarité entre deux noms d'utilisateur (0-100)"""
    n1 = normalize_username(name1)
    n2 = normalize_username(name2)
    
    if not n1 or not n2:
        return 0
    
    # Distance de Levenshtein
    distance = levenshtein_distance(n1, n2)
    max_len = max(len(n1), len(n2))
    
    if max_len == 0:
        return 0
    
    similarity = (1 - distance / max_len) * 100
    return max(0, min(100, similarity))

def get_avatar_hash(member):
    """Récupère le hash de l'avatar d'un membre"""
    if member.avatar:
        return str(member.avatar.key)
    return "default"

async def save_user_fingerprint(guild_id, member):
    """Sauvegarde l'empreinte d'un utilisateur pour détection future"""
    try:
        avatar_hash = get_avatar_hash(member)
        username_norm = normalize_username(member.name)
        created_ts = int(member.created_at.timestamp()) if member.created_at else 0
        joined_ts = int(member.joined_at.timestamp()) if member.joined_at else 0
        
        async with get_db() as db:
            await db.execute('''
                INSERT INTO user_fingerprints 
                (guild_id, user_id, avatar_hash, username_normalized, created_at_ts, joined_at_ts, updated_at)
                VALUES (?, ?, ?, ?, ?, ?, ?)
                ON CONFLICT(guild_id, user_id) DO UPDATE SET
                    avatar_hash = ?, username_normalized = ?, updated_at = ?
            ''', (guild_id, member.id, avatar_hash, username_norm, created_ts, joined_ts, now().isoformat(),
                  avatar_hash, username_norm, now().isoformat()))
            await db.commit()
    except Exception as ex:
        print(f"[ALT] Erreur save fingerprint: {ex}")

async def save_ban_info(guild_id, user_id, username, avatar_hash, reason):
    """Sauvegarde les infos d'un ban pour détection de contournement"""
    try:
        async with get_db() as db:
            await db.execute('''
                INSERT INTO ban_history (guild_id, user_id, username, avatar_hash, reason)
                VALUES (?, ?, ?, ?, ?)
            ''', (guild_id, user_id, username, avatar_hash, reason))
            await db.commit()
    except Exception as ex:
        print(f"[ALT] Erreur save ban: {ex}")

async def detect_alt_account(guild, new_member):
    """
    Détecte si un nouveau membre est potentiellement un compte secondaire.
    Retourne: (is_alt, confidence, main_account_id, reasons)
    """
    reasons = []
    confidence = 0
    main_account_id = None
    
    try:
        new_avatar = get_avatar_hash(new_member)
        new_username_norm = normalize_username(new_member.name)
        new_created_ts = int(new_member.created_at.timestamp()) if new_member.created_at else 0
        
        async with get_db() as db:
            # 1. Vérifier si l'avatar correspond à un utilisateur banni
            async with db.execute('''
                SELECT user_id, username FROM ban_history 
                WHERE guild_id = ? AND avatar_hash = ? AND avatar_hash != "default"
            ''', (guild.id, new_avatar)) as cursor:
                banned_match = await cursor.fetchone()
                if banned_match:
                    confidence += 60
                    main_account_id = banned_match[0]
                    reasons.append(f"Avatar identique à l'utilisateur banni {banned_match[1]} ({banned_match[0]})")
            
            # 2. Vérifier les noms similaires avec des utilisateurs bannis
            async with db.execute('''
                SELECT user_id, username FROM ban_history WHERE guild_id = ?
            ''', (guild.id,)) as cursor:
                banned_users = await cursor.fetchall()
                for banned_id, banned_name in banned_users:
                    sim = username_similarity(new_member.name, banned_name)
                    if sim >= 80:
                        confidence += 40
                        if not main_account_id:
                            main_account_id = banned_id
                        reasons.append(f"Nom similaire ({int(sim)}%) à l'utilisateur banni {banned_name}")
            
            # 3. Vérifier si l'avatar correspond à un membre existant (même avatar = même personne)
            async with db.execute('''
                SELECT user_id FROM user_fingerprints 
                WHERE guild_id = ? AND avatar_hash = ? AND avatar_hash != "default" AND user_id != ?
            ''', (guild.id, new_avatar, new_member.id)) as cursor:
                avatar_matches = await cursor.fetchall()
                for (existing_id,) in avatar_matches:
                    existing_member = guild.get_member(existing_id)
                    if existing_member:
                        confidence += 50
                        if not main_account_id:
                            main_account_id = existing_id
                        reasons.append(f"Avatar identique à {existing_member.name} ({existing_id})")
            
            # 4. Vérifier les noms très similaires avec des membres existants
            async with db.execute('''
                SELECT user_id, username_normalized FROM user_fingerprints 
                WHERE guild_id = ? AND user_id != ?
            ''', (guild.id, new_member.id)) as cursor:
                existing_users = await cursor.fetchall()
                for existing_id, existing_norm in existing_users:
                    if existing_norm and new_username_norm:
                        sim = username_similarity(new_member.name, existing_norm)
                        if sim >= 85:
                            existing_member = guild.get_member(existing_id)
                            if existing_member:
                                confidence += 30
                                if not main_account_id:
                                    main_account_id = existing_id
                                reasons.append(f"Nom très similaire ({int(sim)}%) à {existing_member.name}")
            
            # 5. Vérifier si le compte a été créé juste après un ban
            async with db.execute('''
                SELECT user_id, username, banned_at FROM ban_history 
                WHERE guild_id = ? 
                ORDER BY banned_at DESC LIMIT 10
            ''', (guild.id,)) as cursor:
                recent_bans = await cursor.fetchall()
                for banned_id, banned_name, banned_at in recent_bans:
                    try:
                        ban_ts = datetime.fromisoformat(banned_at).timestamp()
                        # Si le compte a été créé dans les 7 jours suivant un ban
                        if 0 < new_created_ts - ban_ts < 7 * 86400:
                            confidence += 25
                            if not main_account_id:
                                main_account_id = banned_id
                            reasons.append(f"Compte créé peu après le ban de {banned_name}")
                    except:
                        pass
            
            # 6. Compte très récent (moins de 7 jours) = plus suspect
            account_age_days = (now() - new_member.created_at.replace(tzinfo=timezone.utc)).days if new_member.created_at else 365
            if account_age_days < 1:
                confidence += 15
                reasons.append("Compte créé aujourd'hui")
            elif account_age_days < 7:
                confidence += 10
                reasons.append(f"Compte très récent ({account_age_days} jours)")
        
        # Plafonner la confiance à 100
        confidence = min(100, confidence)
        
        # Sauvegarder la détection si suffisamment confiant
        if confidence >= 40 and main_account_id:
            await save_alt_detection(guild.id, main_account_id, new_member.id, confidence, reasons)
        
        return confidence >= 40, confidence, main_account_id, reasons
        
    except Exception as ex:
        print(f"[ALT] Erreur détection: {ex}")
        return False, 0, None, []

async def save_alt_detection(guild_id, main_id, alt_id, confidence, reasons):
    """Sauvegarde une détection de compte secondaire"""
    try:
        async with get_db() as db:
            await db.execute('''
                INSERT INTO alt_accounts (guild_id, main_account_id, alt_account_id, confidence, reasons, status)
                VALUES (?, ?, ?, ?, ?, "suspected")
                ON CONFLICT(guild_id, main_account_id, alt_account_id) DO UPDATE SET
                    confidence = ?, reasons = ?, detected_at = CURRENT_TIMESTAMP
            ''', (guild_id, main_id, alt_id, confidence, json.dumps(reasons), confidence, json.dumps(reasons)))
            await db.commit()
    except Exception as ex:
        print(f"[ALT] Erreur save detection: {ex}")

async def get_alt_accounts(guild_id):
    """Récupère tous les comptes secondaires détectés pour un serveur"""
    try:
        async with get_db() as db:
            async with db.execute('''
                SELECT id, main_account_id, alt_account_id, confidence, reasons, status, detected_at, action_taken
                FROM alt_accounts WHERE guild_id = ?
                ORDER BY confidence DESC, detected_at DESC
            ''', (guild_id,)) as cursor:
                return await cursor.fetchall()
    except:
        return []

async def update_alt_status(guild_id, alt_id, status, action=""):
    """Met à jour le statut d'un compte secondaire"""
    try:
        async with get_db() as db:
            await db.execute('''
                UPDATE alt_accounts SET status = ?, action_taken = ?
                WHERE guild_id = ? AND alt_account_id = ?
            ''', (status, action, guild_id, alt_id))
            await db.commit()
    except Exception as ex:
        print(f"[ALT] Erreur update status: {ex}")

async def scan_all_members_for_alts(guild):
    """Scanne tous les membres du serveur pour détecter les comptes secondaires"""
    detected = []
    
    try:
        # D'abord, sauvegarder les fingerprints de tous les membres
        for member in guild.members:
            if not member.bot:
                await save_user_fingerprint(guild.id, member)
        
        # Ensuite, détecter les alts
        for member in guild.members:
            if not member.bot:
                is_alt, confidence, main_id, reasons = await detect_alt_account(guild, member)
                if is_alt:
                    detected.append({
                        'member': member,
                        'confidence': confidence,
                        'main_id': main_id,
                        'reasons': reasons
                    })
    except Exception as ex:
        print(f"[ALT] Erreur scan: {ex}")
    
    return detected

class MainPanel(View):
    def __init__(self, u, g):
        super().__init__(timeout=600)
        self.u = u
        self.g = g
    
    async def interaction_check(self, i):
        return i.user.id == self.u.id
    
    def embed(self):
        e = discord.Embed(color=0x2F3136)
        e.set_author(name=f"⚙️ Configuration — {self.g.name}", icon_url=self.g.icon.url if self.g.icon else None)
        
        # Stats serveur en haut
        online = sum(1 for m in self.g.members if m.status != discord.Status.offline and not m.bot)
        bots = sum(1 for m in self.g.members if m.bot)
        humans = self.g.member_count - bots
        boosts = self.g.premium_subscription_count or 0
        
        desc = (
            f"```ansi\n"
            f"\u001b[1;37m{'═' * 40}\n"
            f"\u001b[1;36m  👥 {humans} membres  •  🤖 {bots} bots  •  🟢 {online} en ligne\n"
            f"\u001b[1;33m  📺 {len(self.g.text_channels)} salons  •  🔊 {len(self.g.voice_channels)} vocaux  •  💎 {boosts} boosts\n"
            f"\u001b[1;37m{'═' * 40}\n"
            f"```\n"
            f"**🛡️ Sécurité** — Protection, Modération, Immunités\n"
            f"**🎫 Communauté** — Tickets, Niveaux, Commandes\n"
            f"**📢 Contenu** — Feeds sociaux, Stats, Aide auto\n"
            f"**🔧 Outils** — Salons, Vocaux, Config avancée\n\n"
            f"*▼ Sélectionnez un module ci-dessous*"
        )
        e.description = desc
        
        if self.g.icon:
            e.set_thumbnail(url=self.g.icon.url)
        
        # Banner du serveur si dispo
        if self.g.banner:
            e.set_image(url=self.g.banner.url)
        
        e.set_footer(
            text=f"👑 {self.u.display_name} • Owner only • Timeout 10min",
            icon_url=self.u.display_avatar.url
        )
        return e
    
    @discord.ui.select(
        placeholder="📂 Choisir un module à configurer...",
        options=[
            discord.SelectOption(label="Protection", value="prot", emoji="🛡️", description="Anti-spam, anti-raid, filtres"),
            discord.SelectOption(label="Modération", value="mod", emoji="🔨", description="Warn, mute, rôles modérateurs"),
            discord.SelectOption(label="Immunités", value="immune", emoji="👑", description="Rôles et utilisateurs immunisés"),
            discord.SelectOption(label="Commandes", value="cmds", emoji="⚡", description="Suggestions, trade, commandes"),
            discord.SelectOption(label="Config Salon", value="chan", emoji="📺", description="Configuration par salon"),
            discord.SelectOption(label="Tickets", value="tickets", emoji="🎫", description="Système de tickets complet"),
            discord.SelectOption(label="Publicité", value="ads", emoji="📢", description="YouTube, Twitch, TikTok, etc."),
            discord.SelectOption(label="Statistiques", value="stats", emoji="📊", description="Stats membres et serveur"),
            discord.SelectOption(label="Centre", value="centre", emoji="🎯", description="Annonces, giveaways, messages"),
            discord.SelectOption(label="Niveaux & Économie", value="levels", emoji="📈", description="XP, boutique, leaderboard"),
            discord.SelectOption(label="Vocaux Temporaires", value="voice", emoji="🔊", description="Hubs vocaux personnalisables"),
            discord.SelectOption(label="Aide Automatique", value="help", emoji="💡", description="FAQ et aide contextuelle"),
        ],
        row=0
    )
    async def module_select(self, i, s):
        val = s.values[0]
        panels = {
            'prot': lambda: ProtPanel(self.u, self.g),
            'mod': lambda: ModerationPanel(self.u, self.g),
            'immune': lambda: ImmunePanel(self.u, self.g),
            'cmds': lambda: CommandsPanel(self.u, self.g),
            'chan': lambda: ChanPanel(self.u, self.g),
            'tickets': lambda: TicketMainPanel(self.u, self.g),
            'ads': lambda: AdsPanel(self.u, self.g),
            'stats': lambda: StatPanel(self.u, self.g),
            'centre': lambda: CentrePanel(self.u, self.g),
            'levels': lambda: LevelSystemPanel(self.u, self.g),
            'voice': lambda: TempVoicePanel(self.u, self.g),
            'help': lambda: AutoHelpPanel(self.u, self.g),
        }
        v = panels[val]()
        emb = await v.embed() if asyncio.iscoroutinefunction(v.embed) else v.embed()
        await i.response.edit_message(embed=emb, view=v)
    
    @discord.ui.button(label="Fermer", emoji="✖️", style=discord.ButtonStyle.danger, row=1)
    async def close(self, i, b):
        # Phase 3.9 fix : i.message.delete() ne marche PAS sur les messages éphémères
        # et ne ack pas l'interaction → "Échec de l'interaction"
        # Pattern bulletproof : edit_message (ack + clear UI), fallback defer
        try:
            await i.response.edit_message(
                content="✅ Configuration fermée. Tu peux fermer ce message via *Dismiss*.",
                embed=None, embeds=[], view=None, attachments=[],
            )
        except discord.InteractionResponded:
            try:
                await i.edit_original_response(content="✅ Fermé", embed=None, view=None)
            except Exception:
                pass
        except Exception as ex:
            print(f"[V1 close] {ex}")
            try:
                if not i.response.is_done():
                    await i.response.defer()
            except Exception:
                pass


class MainPanelV2(LayoutView):
    """Panneau principal de configuration en Components V2 (Phase 4.0 — refonte épurée).

    5 modules essentiels seulement :
    🛡️ Sécurité · 🎫 Tickets · 📢 Publications · 📋 Logs · 🎮 Jeux

    Tous les autres modules (Stats, Niveaux, Vocaux, Centre, Aide, etc.)
    restent accessibles via leurs slash commands respectives mais sont
    retirés du menu central pour rester lisible et focus.
    """

    def __init__(self, u, g):
        super().__init__(timeout=600)
        self.u = u
        self.g = g
        self._build()

    async def interaction_check(self, i):
        return i.user.id == self.u.id

    def _build(self):
        # Stats serveur (compact)
        online = sum(1 for m in self.g.members if m.status != discord.Status.offline and not m.bot)
        humans = self.g.member_count - sum(1 for m in self.g.members if m.bot)
        boosts = self.g.premium_subscription_count or 0

        # En-tête avec icône
        if self.g.icon:
            head = v2_section(
                v2_title(f"⚙️ Configuration"),
                v2_subtitle(f"**{self.g.name}** · 👑 {self.u.display_name}"),
                accessory=v2_thumb(self.g.icon.url),
            )
            head_items = [head]
        else:
            head_items = [
                v2_title("⚙️ Configuration"),
                v2_subtitle(f"**{self.g.name}** · 👑 {self.u.display_name}"),
            ]

        # Stats compactes (1 ligne)
        stats_block = v2_body(
            f"👥 `{humans:,}` membres · 🟢 `{online}` en ligne · 💎 `{boosts}` boosts"
        )

        # Select des 5 modules essentiels
        sel = Select(
            placeholder="📂 Sélectionne un module…",
            options=[
                discord.SelectOption(
                    label="Modération & Sécurité", value="security", emoji="🛡️",
                    description="Sanctions · Protection · Immunités · AFK",
                ),
                discord.SelectOption(
                    label="Tickets", value="tickets", emoji="🎫",
                    description="Système de support du serveur",
                ),
                discord.SelectOption(
                    label="Réseaux Sociaux", value="publications", emoji="📢",
                    description="YouTube · Twitch · TikTok · Twitter · Roblox",
                ),
                discord.SelectOption(
                    label="Logs & Audit", value="logs", emoji="📋",
                    description="Un salon · tous les événements",
                ),
                discord.SelectOption(
                    label="Jeux & Concours", value="games", emoji="🎮",
                    description="Giveaways · Game deals",
                ),
                discord.SelectOption(
                    label="Distribution", value="delegations", emoji="🔑",
                    description="Déléguer la gestion d'un rôle à un utilisateur",
                ),
            ],
            custom_id="mpv2_module",
        )
        sel.callback = self._module_select

        # Bouton fermer (avec fix éphémère)
        close_btn = Button(
            label="Fermer",
            emoji="✖️",
            style=discord.ButtonStyle.danger,
            custom_id="mpv2_close",
        )
        close_btn.callback = self._close

        # Container final — minimal, élégant
        self.add_item(v2_container(
            *head_items,
            v2_divider(),
            stats_block,
            v2_divider(),
            discord.ui.ActionRow(sel),
            discord.ui.ActionRow(close_btn),
            color=Palette.PRIMARY,
        ))

    async def render_to(self, interaction: discord.Interaction, *, edit: bool = True):
        # Phase 4 : rebuild à chaque render pour stats fraîches
        self.clear_items()
        self._build()
        if edit:
            await interaction.response.edit_message(view=self, embed=None, attachments=[])
        else:
            await interaction.response.send_message(view=self, ephemeral=True)

    async def _module_select(self, i):
        val = i.data['values'][0]
        # Phase 4 : 5 modules essentiels uniquement
        v2_panels = {
            'security':     lambda: SecurityPanelV2(self.u, self.g),
            'tickets':      lambda: TicketMainPanelV2(self.u, self.g),
            'publications': lambda: AdsPanelV2(self.u, self.g),
            'logs':         lambda: LogsPanelV2(self.u, self.g),
            'games':        lambda: GamesPanelV2(self.u, self.g),
            'delegations':  lambda: DelegationsPanelV2(self.u, self.g),
        }
        if val in v2_panels:
            v = v2_panels[val]()
            await v.render_to(i, edit=True)
        else:
            # Si pour une raison le select retourne un truc inattendu, ack au minimum
            try:
                await i.response.defer()
            except Exception:
                pass

    async def _close(self, i):
        # Phase 3.9 fix : i.message.delete() échoue silencieusement sur ephemeral
        # et cause "Échec de l'interaction". Pattern bulletproof :
        try:
            await i.response.edit_message(
                content="✅ Configuration fermée. Tu peux fermer ce message via *Dismiss*.",
                embed=None, embeds=[], view=None, attachments=[],
            )
        except discord.InteractionResponded:
            try:
                await i.edit_original_response(content="✅ Fermé", embed=None, view=None)
            except Exception:
                pass
        except Exception as ex:
            print(f"[MainPanelV2 _close] {ex}")
            try:
                if not i.response.is_done():
                    await i.response.defer()
            except Exception:
                pass


# ═══════════════════════════════════════════════════════════════════════════════
#  🛡️ SÉCURITÉ — Panel V2 unifié (Phase 4.1)
#
#  Regroupe Modération + Protection + Immunités en un seul hub propre.
#  Navigation par boutons vers les sous-sections existantes (réutilise
#  ModerationPanelV2, ProtPanelV2, ImmunePanelV2 sans les dupliquer).
# ═══════════════════════════════════════════════════════════════════════════════

class SecurityPanelV2(LayoutView):
    """Hub Sécurité unifié — accès à Modération, Protection, Immunités."""

    def __init__(self, u, g):
        super().__init__(timeout=600)
        self.u = u
        self.g = g

    async def interaction_check(self, i):
        return i.user.id == self.u.id

    async def render_to(self, interaction: discord.Interaction, *, edit: bool = True):
        c = await cfg(self.g.id)

        # Stats rapides
        try:
            async with get_db() as db:
                async with db.execute('SELECT COUNT(*) FROM infractions WHERE guild_id=?', (self.g.id,)) as cur:
                    row = await cur.fetchone()
                    inf_count = row[0] if row else 0
        except Exception:
            inf_count = 0

        # Compteurs protection
        prot_on = sum(1 for k, _, _ in PROTS if c.get(k))
        prot_total = len(PROTS)

        # Compteurs immunités
        try:
            async with get_db() as db:
                async with db.execute('SELECT COUNT(*) FROM immune_roles WHERE guild_id=?', (self.g.id,)) as cur:
                    row = await cur.fetchone()
                    immune_roles_count = row[0] if row else 0
                async with db.execute('SELECT COUNT(*) FROM immune_users WHERE guild_id=?', (self.g.id,)) as cur:
                    row = await cur.fetchone()
                    immune_users_count = row[0] if row else 0
        except Exception:
            immune_roles_count = immune_users_count = 0

        # État rapide salon logs mod
        log_ch = self.g.get_channel(c.get('mod_log_channel', 0))

        # État AFK (Phase 4.6)
        afk_cfg = c.get('afk_role_config', {})
        afk_on = bool(afk_cfg.get('enabled', False))
        afk_role = self.g.get_role(afk_cfg.get('role', 0) or afk_cfg.get('role_id', 0))

        self.clear_items()
        items: list = []

        if self.g.icon:
            items.append(v2_section(
                v2_title("🛡️ Modération & Sécurité"),
                v2_subtitle("Sanctions · Protection · Immunités · AFK"),
                accessory=v2_thumb(self.g.icon.url),
            ))
        else:
            items.append(v2_title("🛡️ Modération & Sécurité"))
            items.append(v2_subtitle("Sanctions · Protection · Immunités · AFK"))

        items.append(v2_divider())
        items.append(v2_body(
            f"🔨 **Modération** · `{inf_count}` infractions · {'🟢' if log_ch else '🔴'} logs\n"
            f"🚨 **Protection** · `{prot_on}/{prot_total}` filtres actifs\n"
            f"👑 **Immunités** · `{immune_roles_count}` rôles · `{immune_users_count}` utilisateurs\n"
            f"💤 **AFK** · {('🔘 actif sur ' + afk_role.mention) if (afk_on and afk_role) else ('🔘 actif' if afk_on else '⚪ désactivé')}"
        ))
        items.append(v2_divider())

        # Boutons de navigation
        b_mod = Button(label="🔨 Modération", style=discord.ButtonStyle.primary, custom_id="secv2_mod")
        b_mod.callback = self._cb_mod
        b_prot = Button(label="🚨 Protection", style=discord.ButtonStyle.primary, custom_id="secv2_prot")
        b_prot.callback = self._cb_prot
        b_immune = Button(label="👑 Immunités", style=discord.ButtonStyle.primary, custom_id="secv2_immune")
        b_immune.callback = self._cb_immune
        b_afk = Button(label="💤 AFK", style=discord.ButtonStyle.primary, custom_id="secv2_afk")
        b_afk.callback = self._cb_afk
        b_back = Button(label="◀️ Retour", style=discord.ButtonStyle.secondary, custom_id="secv2_back")
        b_back.callback = self._cb_back

        items.append(discord.ui.ActionRow(b_mod, b_prot, b_immune, b_afk))
        items.append(discord.ui.ActionRow(b_back))

        self.add_item(v2_container(*items, color=Palette.DANGER))

        if edit:
            await interaction.response.edit_message(view=self, embed=None, attachments=[])
        else:
            await interaction.response.send_message(view=self, ephemeral=True)

    async def _cb_mod(self, i):
        v = ModerationPanelV2(self.u, self.g)
        await v.render_to(i, edit=True)

    async def _cb_prot(self, i):
        v = ProtPanelV2(self.u, self.g)
        await v.render_to(i, edit=True)

    async def _cb_immune(self, i):
        v = ImmunePanelV2(self.u, self.g)
        await v.render_to(i, edit=True)

    async def _cb_afk(self, i):
        # Phase 4.6 : accès au panel AFK depuis le hub Sécurité
        v = AfkRolePanelV2(self.u, self.g)
        await v.render_to(i, edit=True)

    async def _cb_back(self, i):
        v = MainPanelV2(self.u, self.g)
        await i.response.edit_message(view=v, embed=None, attachments=[])


