# ═══════════════════════════════════════════════════════════════════════════════
#  🔑 DÉLÉGATIONS — Owner crée des rôles délégués, managers utilisent /manage
#  Phase 18
# ═══════════════════════════════════════════════════════════════════════════════

class DelegationsPanelV2(LayoutView):
    """Hub Distribution — l'owner liste/crée/configure les rôles délégués."""

    def __init__(self, u, g):
        super().__init__(timeout=600)
        self.u = u
        self.g = g

    async def interaction_check(self, i):
        return i.user.id == self.u.id

    async def render_to(self, interaction: discord.Interaction, *, edit: bool = True):
        c = await cfg(self.g.id)
        delegations = delegations2026.list_delegations(c)

        # Liste compacte — Phase 18.2 multi-rôles
        if delegations:
            lines = []
            for d in delegations[:8]:
                emoji = d.get('emoji', '🔑')
                name = d.get('name', '?')
                managed_count = len(d.get('managed_role_ids') or [])
                mgr_user_count = len(d.get('manager_user_ids') or [])
                mgr_role_count = len(d.get('manager_role_ids') or [])
                bl_count = len(d.get('blacklist') or [])
                wl_count = len(d.get('whitelist') or [])

                # Format : "🎭 Nom · 🎭 N rôles · 👤 N · 🎖️ N · 🚫 N · ⭐ N"
                parts = [f"{emoji} **{name}**"]
                if managed_count:
                    parts.append(f"🎭 {managed_count}r gérés")
                else:
                    parts.append("⚪ _aucun rôle_")
                if mgr_user_count:
                    parts.append(f"👤 {mgr_user_count}")
                if mgr_role_count:
                    parts.append(f"🎖️ {mgr_role_count}")
                if bl_count:
                    parts.append(f"🚫 {bl_count}")
                if wl_count:
                    parts.append(f"⭐ {wl_count}")
                lines.append(" · ".join(parts))
            if len(delegations) > 8:
                lines.append(f"_… +{len(delegations) - 8}_")
            body_txt = "\n".join(lines)
        else:
            body_txt = "_Aucune distribution — clique ➕ Créer_"

        self.clear_items()

        items: list = []
        if self.g.icon:
            items.append(v2_section(
                v2_title("🔑 Distribution"),
                v2_subtitle(f"`{len(delegations)}` distribution(s) configurée(s)"),
                accessory=v2_thumb(self.g.icon.url),
            ))
        else:
            items.append(v2_title("🔑 Distribution"))
            items.append(v2_subtitle(f"`{len(delegations)}` distribution(s) configurée(s)"))

        items.append(v2_divider())
        items.append(v2_body(
            "Délègue à un utilisateur de confiance le droit de :\n"
            "▸ Donner / retirer un rôle spécifique aux membres\n"
            "▸ Voir l'activité des membres ayant ce rôle\n"
            "▸ Gérer une blacklist (🚫) et une whitelist (⭐)\n\n"
            "Le manager utilise `/manage` pour accéder à son panel."
        ))
        items.append(v2_divider())
        items.append(v2_title("Distributions configurées", level=3))
        items.append(v2_body(body_txt))
        items.append(v2_divider())

        b_add = Button(label="➕ Créer", style=discord.ButtonStyle.success, custom_id="delv2_add")
        b_add.callback = self._cb_add
        b_edit = Button(label="✏️ Modifier", style=discord.ButtonStyle.primary,
                        disabled=(not delegations), custom_id="delv2_edit")
        b_edit.callback = self._cb_edit
        b_remove = Button(label="🗑️ Retirer", style=discord.ButtonStyle.danger,
                          disabled=(not delegations), custom_id="delv2_remove")
        b_remove.callback = self._cb_remove
        b_back = Button(label="◀️ Retour", style=discord.ButtonStyle.secondary, custom_id="delv2_back")
        b_back.callback = self._cb_back

        items.append(discord.ui.ActionRow(b_add, b_edit, b_remove, b_back))

        self.add_item(v2_container(*items, color=Palette.ACCENT))

        if edit:
            await interaction.response.edit_message(view=self, embed=None, attachments=[])
        else:
            await interaction.response.send_message(view=self, ephemeral=True)

    async def _cb_add(self, i):
        try:
            await i.response.send_modal(DelegationCreateModal(self.u, self.g))
        except Exception as ex:
            print(f"[DelegationsPanelV2 _cb_add] {ex}")

    async def _cb_edit(self, i):
        try:
            c = await cfg(self.g.id)
            delegations = delegations2026.list_delegations(c)
            if not delegations:
                return await i.response.send_message("❌ Aucune distribution.", ephemeral=True)
            opts = []
            for d in delegations[:25]:
                role = self.g.get_role(d.get('role_id', 0))
                opts.append(discord.SelectOption(
                    label=d.get('name', '?')[:50],
                    value=d.get('id', ''),
                    description=(role.name[:50] if role else "rôle ?"),
                    emoji=d.get('emoji', '🔑'),
                ))
            v = View(timeout=120)
            sel = Select(placeholder="Choisir la distribution à modifier…", options=opts)

            async def _on_pick(ix):
                try:
                    delegation_id = ix.data['values'][0]
                    sub = DelegationConfigPanelV2(self.u, self.g, delegation_id)
                    await sub.render_to(ix, edit=True)
                except Exception as ex:
                    print(f"[delegation edit pick] {ex}")
                    try:
                        await ix.response.send_message(f"❌ Erreur : `{ex}`", ephemeral=True)
                    except Exception:
                        pass

            sel.callback = _on_pick
            v.add_item(sel)
            await i.response.send_message("✏️ Quelle distribution modifier ?", view=v, ephemeral=True)
        except Exception as ex:
            print(f"[DelegationsPanelV2 _cb_edit] {ex}")
            try:
                if not i.response.is_done():
                    await i.response.send_message(f"❌ Erreur : `{ex}`", ephemeral=True)
            except Exception:
                pass

    async def _cb_remove(self, i):
        try:
            c = await cfg(self.g.id)
            delegations = delegations2026.list_delegations(c)
            if not delegations:
                return await i.response.send_message("❌ Aucune distribution.", ephemeral=True)
            opts = []
            for d in delegations[:25]:
                role = self.g.get_role(d.get('role_id', 0))
                opts.append(discord.SelectOption(
                    label=d.get('name', '?')[:50],
                    value=d.get('id', ''),
                    description=(role.name[:50] if role else "rôle ?"),
                    emoji=d.get('emoji', '🔑'),
                ))
            v = View(timeout=120)
            sel = Select(placeholder="Choisir la distribution à supprimer…", options=opts)

            async def _on_pick(ix):
                try:
                    delegation_id = ix.data['values'][0]
                    cc = await cfg(self.g.id)
                    d_obj = delegations2026.get_delegation(cc, delegation_id)
                    name = d_obj.get('name', '?') if d_obj else '?'
                    delegations2026.remove_delegation(cc, delegation_id)
                    await db_set(self.g.id, delegations2026.CONFIG_KEY, cc.get(delegations2026.CONFIG_KEY, []))
                    await ix.response.send_message(
                        f"🗑️ Distribution **{name}** supprimée.",
                        ephemeral=True,
                    )
                    # Re-render
                    new_v = DelegationsPanelV2(self.u, self.g)
                    try:
                        await ix.edit_original_response(view=new_v)
                    except Exception:
                        pass
                except Exception as ex:
                    print(f"[delegation remove pick] {ex}")
                    try:
                        await ix.response.send_message(f"❌ Erreur : `{ex}`", ephemeral=True)
                    except Exception:
                        pass

            sel.callback = _on_pick
            v.add_item(sel)
            await i.response.send_message("🗑️ Quelle distribution supprimer ?", view=v, ephemeral=True)
        except Exception as ex:
            print(f"[DelegationsPanelV2 _cb_remove] {ex}")

    async def _cb_back(self, i):
        v = MainPanelV2(self.u, self.g)
        await i.response.edit_message(view=v, embed=None, attachments=[])


class DelegationCreateModal(Modal):
    """Modal Phase 18.2 — 3 champs basiques. Les rôles/users sont configurés
    ensuite dans le panel d'édition via des selects natifs (multi-select)."""

    def __init__(self, u, g):
        super().__init__(title="🔑 Créer une distribution")
        self.u = u
        self.g = g
        self.name_input = TextInput(
            label="Nom de la distribution",
            placeholder="Ex: Rell Seas Studio, Staff Helper…",
            max_length=50,
            required=True,
        )
        self.emoji_input = TextInput(
            label="Emoji (optionnel)",
            placeholder="🔑 (par défaut)",
            max_length=4,
            required=False,
            default="🔑",
        )
        self.threshold_input = TextInput(
            label="Seuil AFK en jours",
            placeholder="14 (par défaut)",
            max_length=3,
            required=False,
            default="14",
        )
        self.add_item(self.name_input)
        self.add_item(self.emoji_input)
        self.add_item(self.threshold_input)

    async def on_submit(self, i):
        try:
            await i.response.defer(ephemeral=True)

            name = self.name_input.value.strip()
            emoji = (self.emoji_input.value or "🔑").strip()
            threshold_str = (self.threshold_input.value or "14").strip()

            if not name:
                return await i.followup.send("❌ Nom requis.", ephemeral=True)
            try:
                threshold = int(threshold_str)
            except ValueError:
                threshold = 14

            # Création vide — les rôles/users à définir dans le panel d'édition
            c = await cfg(self.g.id)
            new_d = delegations2026.add_delegation(
                c,
                name=name,
                emoji=emoji,
                managed_role_ids=[],
                manager_user_ids=[],
                manager_role_ids=[],
                activity_threshold_days=threshold,
            )
            await db_set(self.g.id, delegations2026.CONFIG_KEY, c.get(delegations2026.CONFIG_KEY, []))

            await i.followup.send(
                f"✅ Distribution **{new_d['name']}** créée !\n\n"
                f"💡 Maintenant, configure-la dans le panel d'édition :\n"
                f"  ▸ Rôle(s) géré(s) — ce que la distribution administre\n"
                f"  ▸ Utilisateur(s) et/ou rôle(s) autorisé(s) — qui peut faire `/manage`\n"
                f"  ▸ Seuil AFK actuel : `{threshold}` jours",
                ephemeral=True,
            )

            # Redirection directe vers le panel de config de cette distribution
            try:
                v = DelegationConfigPanelV2(self.u, self.g, new_d['id'])
                await v.render_to(i, edit=True)
            except Exception:
                pass

        except Exception as ex:
            print(f"[DelegationCreateModal on_submit] {ex}")
            import traceback; traceback.print_exc()
            try:
                await i.followup.send(f"❌ Erreur : `{type(ex).__name__}: {ex}`", ephemeral=True)
            except Exception:
                pass


class DelegationConfigPanelV2(LayoutView):
    """Sous-panel Phase 18.2 — configuration détaillée d'une distribution.

    L'owner peut éditer ici :
    - 🎭 Rôle(s) géré(s) — multi-select natif
    - 👤 Utilisateur(s) autorisé(s) — multi-select natif
    - 🎖️ Rôle(s) autorisé(s) — multi-select natif
    """

    def __init__(self, u, g, delegation_id: str):
        super().__init__(timeout=600)
        self.u = u
        self.g = g
        self.delegation_id = delegation_id

    async def interaction_check(self, i):
        return i.user.id == self.u.id

    async def render_to(self, interaction: discord.Interaction, *, edit: bool = True):
        c = await cfg(self.g.id)
        d = delegations2026.get_delegation(c, self.delegation_id)
        if not d:
            try:
                await interaction.response.send_message("❌ Distribution introuvable.", ephemeral=True)
            except Exception:
                pass
            return

        # Phase 18.2 : listes multi
        managed_roles = [self.g.get_role(rid) for rid in d.get('managed_role_ids', []) if self.g.get_role(rid)]
        manager_users = [self.g.get_member(uid) for uid in d.get('manager_user_ids', []) if self.g.get_member(uid)]
        manager_roles = [self.g.get_role(rid) for rid in d.get('manager_role_ids', []) if self.g.get_role(rid)]

        def _list_mentions(items, fallback="⚪ _aucun_", max_show=5):
            if not items:
                return fallback
            mentions = [x.mention for x in items[:max_show]]
            txt = ", ".join(mentions)
            if len(items) > max_show:
                txt += f" · _+{len(items) - max_show}_"
            return txt

        self.clear_items()

        items: list = [
            v2_title(f"{d.get('emoji', '🔑')} {d.get('name', '?')}"),
            v2_subtitle("Configuration · multi-rôles et multi-utilisateurs"),
            v2_divider(),
            v2_body(
                f"🎭 **Rôle(s) géré(s)** *({len(managed_roles)})* · {_list_mentions(managed_roles)}\n"
                f"👤 **Utilisateur(s) autorisé(s)** *({len(manager_users)})* · {_list_mentions(manager_users)}\n"
                f"🎖️ **Rôle(s) autorisé(s)** *({len(manager_roles)})* · {_list_mentions(manager_roles)}\n"
                f"📅 **Seuil AFK** · `{d.get('activity_threshold_days', 14)}` jours"
            ),
            v2_divider(),
            v2_subtitle("✏️ Utilise les boutons pour modifier les rôles et utilisateurs autorisés."),
        ]

        # Boutons d'édition
        b_managed = Button(label="🎭 Rôles gérés", style=discord.ButtonStyle.primary, custom_id="delcfg_managed")
        b_managed.callback = self._cb_edit_managed_roles
        b_users = Button(label="👤 Users autorisés", style=discord.ButtonStyle.primary, custom_id="delcfg_users")
        b_users.callback = self._cb_edit_manager_users
        b_roles = Button(label="🎖️ Rôles autorisés", style=discord.ButtonStyle.primary, custom_id="delcfg_roles")
        b_roles.callback = self._cb_edit_manager_roles
        b_threshold = Button(label=f"📅 Seuil ({d.get('activity_threshold_days', 14)}j)",
                              style=discord.ButtonStyle.secondary, custom_id="delcfg_threshold")
        b_threshold.callback = self._cb_edit_threshold

        b_view = Button(label="👥 Voir les membres", style=discord.ButtonStyle.success, custom_id="delcfg_view")
        b_view.callback = self._cb_view_members
        b_back = Button(label="◀️ Retour", style=discord.ButtonStyle.secondary, custom_id="delcfg_back")
        b_back.callback = self._cb_back

        items.append(discord.ui.ActionRow(b_managed, b_users, b_roles, b_threshold))
        items.append(discord.ui.ActionRow(b_view, b_back))

        self.add_item(v2_container(*items, color=Palette.ACCENT))

        if edit:
            await interaction.response.edit_message(view=self, embed=None, attachments=[])
        else:
            await interaction.response.send_message(view=self, ephemeral=True)

    async def _cb_edit_managed_roles(self, i):
        """Multi-select Discord natif pour les rôles gérés."""
        try:
            await self._open_role_multiselect(
                i,
                field='managed_role_ids',
                title="🎭 Rôles gérés",
                placeholder="Choisis le(s) rôle(s) que cette distribution gère…",
            )
        except Exception as ex:
            print(f"[delcfg_managed] {ex}")

    async def _cb_edit_manager_users(self, i):
        """Multi-select Discord natif pour les users autorisés."""
        try:
            await self._open_user_multiselect(
                i,
                field='manager_user_ids',
                title="👤 Utilisateurs autorisés",
                placeholder="Choisis le(s) utilisateur(s) qui peuvent /manage…",
            )
        except Exception as ex:
            print(f"[delcfg_users] {ex}")

    async def _cb_edit_manager_roles(self, i):
        """Multi-select Discord natif pour les rôles autorisés."""
        try:
            await self._open_role_multiselect(
                i,
                field='manager_role_ids',
                title="🎖️ Rôles autorisés à utiliser /manage",
                placeholder="Choisis le(s) rôle(s) dont les porteurs peuvent /manage…",
            )
        except Exception as ex:
            print(f"[delcfg_roles] {ex}")

    async def _cb_edit_threshold(self, i):
        try:
            await i.response.send_modal(DelegationThresholdModal(self.u, self.g, self.delegation_id))
        except Exception as ex:
            print(f"[delcfg_threshold] {ex}")

    async def _open_role_multiselect(self, i, *, field: str, title: str, placeholder: str):
        """Affiche un RoleSelect (multi) pour éditer un champ list de role IDs."""
        c = await cfg(self.g.id)
        d = delegations2026.get_delegation(c, self.delegation_id) or {}
        current_ids = d.get(field, []) or []

        v = View(timeout=180)
        sel = discord.ui.RoleSelect(
            placeholder=placeholder,
            min_values=0,
            max_values=25,
        )

        async def _on_pick(ix):
            try:
                new_ids = [int(rid) for rid in ix.data.get('values', [])]
                cc = await cfg(self.g.id)
                delegations2026.update_delegation(cc, self.delegation_id, **{field: new_ids})
                await db_set(self.g.id, delegations2026.CONFIG_KEY, cc.get(delegations2026.CONFIG_KEY, []))
                await ix.response.send_message(
                    f"✅ Mis à jour : `{len(new_ids)}` rôle(s) sélectionné(s).",
                    ephemeral=True,
                )
                # Re-render le panel config
                try:
                    new_v = DelegationConfigPanelV2(self.u, self.g, self.delegation_id)
                    await ix.edit_original_response(view=new_v)
                except Exception:
                    pass
            except Exception as ex:
                print(f"[multiselect role pick] {ex}")
                try:
                    await ix.response.send_message(f"❌ Erreur : `{ex}`", ephemeral=True)
                except Exception:
                    pass

        sel.callback = _on_pick
        v.add_item(sel)

        current_str = ", ".join(f"<@&{rid}>" for rid in current_ids[:10]) if current_ids else "_aucun_"
        if len(current_ids) > 10:
            current_str += f" _+{len(current_ids) - 10}_"

        await i.response.send_message(
            f"**{title}**\n\n"
            f"Sélection actuelle : {current_str}\n\n"
            "_Tu peux cocher/décocher plusieurs rôles d'un coup. Décocher tout = liste vide._",
            view=v,
            ephemeral=True,
        )

    async def _open_user_multiselect(self, i, *, field: str, title: str, placeholder: str):
        """Affiche un UserSelect (multi) pour éditer un champ list de user IDs."""
        c = await cfg(self.g.id)
        d = delegations2026.get_delegation(c, self.delegation_id) or {}
        current_ids = d.get(field, []) or []

        v = View(timeout=180)
        sel = discord.ui.UserSelect(
            placeholder=placeholder,
            min_values=0,
            max_values=25,
        )

        async def _on_pick(ix):
            try:
                new_ids = [int(uid) for uid in ix.data.get('values', [])]
                cc = await cfg(self.g.id)
                delegations2026.update_delegation(cc, self.delegation_id, **{field: new_ids})
                await db_set(self.g.id, delegations2026.CONFIG_KEY, cc.get(delegations2026.CONFIG_KEY, []))
                await ix.response.send_message(
                    f"✅ Mis à jour : `{len(new_ids)}` utilisateur(s) sélectionné(s).",
                    ephemeral=True,
                )
                try:
                    new_v = DelegationConfigPanelV2(self.u, self.g, self.delegation_id)
                    await ix.edit_original_response(view=new_v)
                except Exception:
                    pass
            except Exception as ex:
                print(f"[multiselect user pick] {ex}")
                try:
                    await ix.response.send_message(f"❌ Erreur : `{ex}`", ephemeral=True)
                except Exception:
                    pass

        sel.callback = _on_pick
        v.add_item(sel)

        current_str = ", ".join(f"<@{uid}>" for uid in current_ids[:10]) if current_ids else "_aucun_"
        if len(current_ids) > 10:
            current_str += f" _+{len(current_ids) - 10}_"

        await i.response.send_message(
            f"**{title}**\n\n"
            f"Sélection actuelle : {current_str}\n\n"
            "_Tu peux cocher/décocher plusieurs utilisateurs d'un coup._",
            view=v,
            ephemeral=True,
        )

    async def _cb_view_members(self, i):
        try:
            c = await cfg(self.g.id)
            d = delegations2026.get_delegation(c, self.delegation_id)
            if not d:
                return await i.response.send_message("❌ Distribution introuvable.", ephemeral=True)
            v = DelegationMembersPanelV2(self.u, self.g, self.delegation_id, back_to_owner=True)
            await v.render_to(i, edit=True)
        except Exception as ex:
            print(f"[DelegationConfigPanelV2 _cb_view_members] {ex}")

    async def _cb_back(self, i):
        v = DelegationsPanelV2(self.u, self.g)
        await v.render_to(i, edit=True)


class DelegationThresholdModal(Modal):
    """Modal pour modifier le seuil AFK d'une distribution."""

    def __init__(self, u, g, delegation_id: str):
        super().__init__(title="📅 Seuil AFK")
        self.u = u
        self.g = g
        self.delegation_id = delegation_id
        self.threshold_input = TextInput(
            label="Seuil AFK en jours",
            placeholder="14",
            max_length=3,
            required=True,
        )
        self.add_item(self.threshold_input)

    async def on_submit(self, i):
        try:
            val = self.threshold_input.value.strip()
            try:
                threshold = int(val)
                threshold = max(1, min(365, threshold))
            except ValueError:
                return await i.response.send_message("❌ Valeur invalide.", ephemeral=True)
            c = await cfg(self.g.id)
            delegations2026.update_delegation(
                c, self.delegation_id, activity_threshold_days=threshold,
            )
            await db_set(self.g.id, delegations2026.CONFIG_KEY, c.get(delegations2026.CONFIG_KEY, []))
            v = DelegationConfigPanelV2(self.u, self.g, self.delegation_id)
            await v.render_to(i, edit=True)
        except Exception as ex:
            print(f"[DelegationThresholdModal] {ex}")
            try:
                if not i.response.is_done():
                    await i.response.send_message(f"❌ Erreur : `{ex}`", ephemeral=True)
            except Exception:
                pass


class DelegationMembersPanelV2(LayoutView):
    """Panel manager — Phase 18.1 : 3 sections (Membres / Blacklist / Whitelist).

    Utilisé par :
    - L'owner depuis DelegationConfigPanelV2 (visualisation + actions)
    - Le manager via /manage (actions : add/remove role, blacklist, whitelist)
    """

    def __init__(self, u, g, delegation_id: str, *, back_to_owner: bool = False):
        super().__init__(timeout=600)
        self.u = u
        self.g = g
        self.delegation_id = delegation_id
        self.back_to_owner = back_to_owner

    async def interaction_check(self, i):
        return i.user.id == self.u.id

    async def render_to(self, interaction: discord.Interaction, *, edit: bool = True):
        c = await cfg(self.g.id)
        d = delegations2026.get_delegation(c, self.delegation_id)
        if not d:
            try:
                await interaction.response.send_message("❌ Distribution introuvable.", ephemeral=True)
            except Exception:
                pass
            return

        # Phase 18.2 : multi-rôles gérés
        managed_role_ids = d.get('managed_role_ids', []) or []
        managed_roles = [self.g.get_role(rid) for rid in managed_role_ids if self.g.get_role(rid)]
        threshold_days = d.get('activity_threshold_days', 14)
        blacklist_ids = d.get('blacklist', []) or []
        whitelist_ids = d.get('whitelist', []) or []

        # Stats membres avec AU MOINS UN des rôles gérés + activité
        members_lines = []
        afk_count = 0
        active_count = 0
        members_with_role_count = 0

        if managed_roles:
            managed_role_set = set(r.id for r in managed_roles)
            members_with_role = [
                m for m in self.g.members
                if not m.bot and any(r.id in managed_role_set for r in m.roles)
            ]
            members_with_role_count = len(members_with_role)
            member_ids = [m.id for m in members_with_role]

            last_activity = {}
            if member_ids:
                placeholders = ','.join('?' * len(member_ids))
                try:
                    async with get_db() as db:
                        async with db.execute(
                            f'SELECT user_id, last_message FROM activity_tracking '
                            f'WHERE guild_id=? AND user_id IN ({placeholders})',
                            (self.g.id, *member_ids),
                        ) as cur:
                            rows = await cur.fetchall()
                            for uid, last_msg in rows:
                                last_activity[uid] = last_msg
                except Exception as ex:
                    print(f"[DelegationMembersPanelV2 activity fetch] {ex}")

            now_dt = now()
            for m in members_with_role[:12]:
                # Indicateurs blacklist/whitelist
                tag = ""
                if m.id in blacklist_ids:
                    tag = " 🚫"
                elif m.id in whitelist_ids:
                    tag = " ⭐"

                last_msg = last_activity.get(m.id)
                if last_msg:
                    try:
                        last_dt = datetime.fromisoformat(last_msg.replace('Z', '+00:00'))
                        last_dt_naive = last_dt.replace(tzinfo=None) if last_dt.tzinfo else last_dt
                        days_ago = (now_dt - last_dt_naive).days
                        if days_ago >= threshold_days:
                            members_lines.append(f"💤 {m.mention}{tag} · _AFK `{days_ago}j`_")
                            afk_count += 1
                        else:
                            members_lines.append(f"🟢 {m.mention}{tag} · `{days_ago}j`")
                            active_count += 1
                    except Exception:
                        members_lines.append(f"⚪ {m.mention}{tag} · _?_")
                else:
                    members_lines.append(f"⚪ {m.mention}{tag} · _jamais actif_")
                    afk_count += 1

            if len(members_with_role) > 12:
                members_lines.append(f"_… +{len(members_with_role) - 12}_")

        members_block = "\n".join(members_lines) if members_lines else "_Aucun membre avec ce rôle_"

        # Blacklist preview (max 5)
        bl_lines = []
        for uid in blacklist_ids[:5]:
            m = self.g.get_member(uid)
            bl_lines.append(f"🚫 {m.mention if m else f'`{uid}`'}")
        if len(blacklist_ids) > 5:
            bl_lines.append(f"_… +{len(blacklist_ids) - 5}_")
        bl_block = "\n".join(bl_lines) if bl_lines else "_Aucun_"

        # Whitelist preview (max 5)
        wl_lines = []
        for uid in whitelist_ids[:5]:
            m = self.g.get_member(uid)
            wl_lines.append(f"⭐ {m.mention if m else f'`{uid}`'}")
        if len(whitelist_ids) > 5:
            wl_lines.append(f"_… +{len(whitelist_ids) - 5}_")
        wl_block = "\n".join(wl_lines) if wl_lines else "_Aucun_"

        self.clear_items()

        # Subtitle : si plusieurs rôles gérés, montre le count
        if len(managed_roles) == 1:
            subtitle_text = f"🎭 {managed_roles[0].mention} · 👥 `{members_with_role_count}` membre(s)"
        elif len(managed_roles) > 1:
            subtitle_text = f"🎭 `{len(managed_roles)}` rôles gérés · 👥 `{members_with_role_count}` membre(s)"
        else:
            subtitle_text = f"⚪ Aucun rôle géré configuré · 👥 `{members_with_role_count}` membre(s)"

        items: list = [
            v2_title(f"{d.get('emoji', '🔑')} {d.get('name', '?')}"),
            v2_subtitle(subtitle_text),
            v2_divider(),
            v2_body(
                f"🟢 **{active_count}** actifs · 💤 **{afk_count}** inactifs · "
                f"📅 Seuil : `{threshold_days}j`"
            ),
            v2_divider(),
            v2_title("👥 Membres du rôle", level=3),
            v2_body(members_block),
            v2_divider(),
            v2_title(f"🚫 Blacklist ({len(blacklist_ids)})", level=3),
            v2_body(bl_block),
            v2_divider(),
            v2_title(f"⭐ Whitelist ({len(whitelist_ids)})", level=3),
            v2_body(wl_block),
            v2_divider(),
        ]

        # Boutons : 2 lignes
        b_add = Button(label="➕ Donner rôle", style=discord.ButtonStyle.success, custom_id="delmem_add")
        b_add.callback = self._cb_add_member
        b_remove = Button(label="🗑️ Retirer rôle", style=discord.ButtonStyle.danger, custom_id="delmem_remove")
        b_remove.callback = self._cb_remove_member
        b_refresh = Button(label="🔄 Actualiser", style=discord.ButtonStyle.secondary, custom_id="delmem_refresh")
        b_refresh.callback = self._cb_refresh

        b_bl_add = Button(label="🚫 Blacklist", style=discord.ButtonStyle.danger, custom_id="delmem_bl_add")
        b_bl_add.callback = self._cb_bl_add
        b_wl_add = Button(label="⭐ Whitelist", style=discord.ButtonStyle.primary, custom_id="delmem_wl_add")
        b_wl_add.callback = self._cb_wl_add
        b_manage_lists = Button(label="📋 Gérer listes", style=discord.ButtonStyle.secondary, custom_id="delmem_lists")
        b_manage_lists.callback = self._cb_manage_lists
        b_back = Button(label="◀️ Retour", style=discord.ButtonStyle.secondary, custom_id="delmem_back")
        b_back.callback = self._cb_back

        items.append(discord.ui.ActionRow(b_add, b_remove, b_refresh))
        items.append(discord.ui.ActionRow(b_bl_add, b_wl_add, b_manage_lists, b_back))

        self.add_item(v2_container(*items, color=Palette.ACCENT))

        if edit:
            await interaction.response.edit_message(view=self, embed=None, attachments=[])
        else:
            await interaction.response.send_message(view=self, ephemeral=True)

    async def _cb_add_member(self, i):
        """Phase 18.2 : si plusieurs rôles gérés, on demande lequel donner."""
        try:
            c = await cfg(self.g.id)
            d = delegations2026.get_delegation(c, self.delegation_id)
            if not d:
                return await i.response.send_message("❌ Distribution introuvable.", ephemeral=True)
            managed_roles = [self.g.get_role(rid) for rid in d.get('managed_role_ids', []) if self.g.get_role(rid)]
            if not managed_roles:
                return await i.response.send_message(
                    "❌ Aucun rôle géré configuré.\n"
                    "L'owner doit en ajouter via `/configure → 🔑 Distribution → ✏️`.",
                    ephemeral=True,
                )

            # Si plusieurs rôles : laisser le manager choisir
            if len(managed_roles) > 1:
                return await self._open_role_then_user_select(i, managed_roles, mode='add')

            # Un seul rôle : flow direct
            role = managed_roles[0]
            await self._open_user_select_for_add(i, role)
        except Exception as ex:
            print(f"[DelegationMembersPanelV2 _cb_add_member] {ex}")

    async def _open_role_then_user_select(self, i, managed_roles, mode='add'):
        """Étape 1 : choisir QUEL rôle parmi les rôles gérés. Étape 2 : choisir le membre."""
        opts = []
        for r in managed_roles[:25]:
            opts.append(discord.SelectOption(
                label=r.name[:50],
                value=str(r.id),
                description=f"{len([m for m in self.g.members if r in m.roles])} membre(s)"[:50],
            ))
        v = View(timeout=180)
        sel = Select(placeholder="Étape 1 : choisis le rôle…", options=opts)

        async def _on_role(ix):
            try:
                role_id = int(ix.data['values'][0])
                role = self.g.get_role(role_id)
                if not role:
                    return await ix.response.send_message("❌ Rôle introuvable.", ephemeral=True)
                if mode == 'add':
                    await self._open_user_select_for_add(ix, role)
                else:
                    await self._open_user_select_for_remove(ix, role)
            except Exception as ex:
                print(f"[role_then_user role pick] {ex}")
                try:
                    await ix.response.send_message(f"❌ Erreur : `{ex}`", ephemeral=True)
                except Exception:
                    pass

        sel.callback = _on_role
        v.add_item(sel)
        verb = "Donner" if mode == 'add' else "Retirer"
        await i.response.send_message(
            f"{verb} quel rôle ? Choisis parmi les {len(managed_roles)} rôles gérés :",
            view=v,
            ephemeral=True,
        )

    async def _open_user_select_for_add(self, i, role):
        """UserSelect pour donner un rôle spécifique."""
        v = View(timeout=120)
        user_select = discord.ui.UserSelect(
            placeholder=f"Donner @{role.name} à...",
            min_values=1, max_values=1,
        )

        async def _on_pick(ix):
            try:
                user_id = int(ix.data['values'][0])
                member = self.g.get_member(user_id)
                if not member:
                    return await ix.response.send_message("❌ Membre introuvable.", ephemeral=True)
                cc = await cfg(self.g.id)
                if delegations2026.is_blacklisted(cc, self.delegation_id, user_id):
                    return await ix.response.send_message(
                        f"🚫 {member.mention} est sur la **blacklist** de cette distribution.\n"
                        "Retire-le de la blacklist d'abord.",
                        ephemeral=True,
                    )
                if role in member.roles:
                    return await ix.response.send_message(
                        f"⚠️ {member.mention} a déjà le rôle {role.mention}.",
                        ephemeral=True,
                    )
                d = delegations2026.get_delegation(cc, self.delegation_id) or {}
                try:
                    await member.add_roles(role, reason=f"Distribution {d.get('name', '?')} par {i.user}")
                    await ix.response.send_message(
                        f"✅ {role.mention} donné à {member.mention}",
                        ephemeral=True,
                    )
                except discord.Forbidden:
                    await ix.response.send_message(
                        f"❌ Je n'ai pas les permissions pour donner {role.mention}.",
                        ephemeral=True,
                    )
            except Exception as ex:
                print(f"[user_select add pick] {ex}")
                try:
                    await ix.response.send_message(f"❌ Erreur : `{ex}`", ephemeral=True)
                except Exception:
                    pass

        user_select.callback = _on_pick
        v.add_item(user_select)
        if i.response.is_done():
            await i.followup.send(
                f"➕ À qui donner le rôle **{role.name}** ?",
                view=v,
                ephemeral=True,
            )
        else:
            await i.response.send_message(
                f"➕ À qui donner le rôle **{role.name}** ?",
                view=v,
                ephemeral=True,
            )

    async def _open_user_select_for_remove(self, i, role):
        """UserSelect pour retirer un rôle spécifique."""
        members_with_role = [m for m in self.g.members if role in m.roles and not m.bot]
        if not members_with_role:
            target_text = "❌ Aucun membre n'a actuellement ce rôle."
            if i.response.is_done():
                return await i.followup.send(target_text, ephemeral=True)
            return await i.response.send_message(target_text, ephemeral=True)

        v = View(timeout=120)
        user_select = discord.ui.UserSelect(
            placeholder=f"Retirer @{role.name} à...",
            min_values=1, max_values=1,
        )

        async def _on_pick(ix):
            try:
                user_id = int(ix.data['values'][0])
                member = self.g.get_member(user_id)
                if not member:
                    return await ix.response.send_message("❌ Membre introuvable.", ephemeral=True)
                if role not in member.roles:
                    return await ix.response.send_message(
                        f"⚠️ {member.mention} n'a pas ce rôle.",
                        ephemeral=True,
                    )
                cc = await cfg(self.g.id)
                d = delegations2026.get_delegation(cc, self.delegation_id) or {}
                try:
                    await member.remove_roles(role, reason=f"Distribution {d.get('name', '?')} par {i.user}")
                    await ix.response.send_message(
                        f"✅ {role.mention} retiré à {member.mention}",
                        ephemeral=True,
                    )
                except discord.Forbidden:
                    await ix.response.send_message("❌ Je n'ai pas les permissions.", ephemeral=True)
            except Exception as ex:
                print(f"[user_select remove pick] {ex}")
                try:
                    await ix.response.send_message(f"❌ Erreur : `{ex}`", ephemeral=True)
                except Exception:
                    pass

        user_select.callback = _on_pick
        v.add_item(user_select)
        if i.response.is_done():
            await i.followup.send(
                f"🗑️ À qui retirer le rôle **{role.name}** ?",
                view=v,
                ephemeral=True,
            )
        else:
            await i.response.send_message(
                f"🗑️ À qui retirer le rôle **{role.name}** ?",
                view=v,
                ephemeral=True,
            )

    async def _cb_bl_add(self, i):
        """Phase 18.1 : ajouter un user à la blacklist."""
        try:
            v = View(timeout=120)
            user_select = discord.ui.UserSelect(
                placeholder="Blacklist user...",
                min_values=1, max_values=1,
            )

            async def _on_pick(ix):
                try:
                    user_id = int(ix.data['values'][0])
                    member = self.g.get_member(user_id)
                    cc = await cfg(self.g.id)
                    added = delegations2026.add_to_blacklist(cc, self.delegation_id, user_id)
                    await db_set(self.g.id, delegations2026.CONFIG_KEY, cc.get(delegations2026.CONFIG_KEY, []))
                    if added:
                        # Si le membre a le rôle, on le retire automatiquement
                        d = delegations2026.get_delegation(cc, self.delegation_id)
                        role = self.g.get_role(d.get('role_id', 0)) if d else None
                        extra = ""
                        if role and member and role in member.roles:
                            try:
                                await member.remove_roles(role, reason=f"Blacklist {d.get('name', '?')}")
                                extra = f"\n_Le rôle {role.mention} lui a aussi été retiré._"
                            except Exception:
                                pass
                        await ix.response.send_message(
                            f"🚫 {member.mention if member else f'`{user_id}`'} ajouté à la blacklist.{extra}",
                            ephemeral=True,
                        )
                    else:
                        target_label = member.mention if member else "L'utilisateur"
                        await ix.response.send_message(
                            f"⚠️ {target_label} est déjà blacklist.",
                            ephemeral=True,
                        )
                except Exception as ex:
                    print(f"[delmem bl_add pick] {ex}")
                    try:
                        await ix.response.send_message(f"❌ Erreur : `{ex}`", ephemeral=True)
                    except Exception:
                        pass

            user_select.callback = _on_pick
            v.add_item(user_select)
            await i.response.send_message(
                "🚫 Qui ajouter à la **blacklist** ? (ne pourra plus recevoir le rôle)",
                view=v,
                ephemeral=True,
            )
        except Exception as ex:
            print(f"[DelegationMembersPanelV2 _cb_bl_add] {ex}")

    async def _cb_wl_add(self, i):
        """Phase 18.1 : ajouter un user à la whitelist."""
        try:
            v = View(timeout=120)
            user_select = discord.ui.UserSelect(
                placeholder="Whitelist user...",
                min_values=1, max_values=1,
            )

            async def _on_pick(ix):
                try:
                    user_id = int(ix.data['values'][0])
                    member = self.g.get_member(user_id)
                    cc = await cfg(self.g.id)
                    added = delegations2026.add_to_whitelist(cc, self.delegation_id, user_id)
                    await db_set(self.g.id, delegations2026.CONFIG_KEY, cc.get(delegations2026.CONFIG_KEY, []))
                    if added:
                        await ix.response.send_message(
                            f"⭐ {member.mention if member else f'`{user_id}`'} ajouté à la whitelist.",
                            ephemeral=True,
                        )
                    else:
                        target_label = member.mention if member else "L'utilisateur"
                        await ix.response.send_message(
                            f"⚠️ {target_label} est déjà whitelist.",
                            ephemeral=True,
                        )
                except Exception as ex:
                    print(f"[delmem wl_add pick] {ex}")
                    try:
                        await ix.response.send_message(f"❌ Erreur : `{ex}`", ephemeral=True)
                    except Exception:
                        pass

            user_select.callback = _on_pick
            v.add_item(user_select)
            await i.response.send_message(
                "⭐ Qui ajouter à la **whitelist** ? (membres validés / approuvés)",
                view=v,
                ephemeral=True,
            )
        except Exception as ex:
            print(f"[DelegationMembersPanelV2 _cb_wl_add] {ex}")

    async def _cb_manage_lists(self, i):
        """Phase 18.1 : panel pour retirer des entrées blacklist/whitelist."""
        try:
            c = await cfg(self.g.id)
            d = delegations2026.get_delegation(c, self.delegation_id)
            if not d:
                return await i.response.send_message("❌ Distribution introuvable.", ephemeral=True)
            bl = d.get('blacklist', []) or []
            wl = d.get('whitelist', []) or []
            if not bl and not wl:
                return await i.response.send_message(
                    "ℹ️ Aucune blacklist/whitelist configurée.",
                    ephemeral=True,
                )
            opts = []
            for uid in bl[:12]:
                m = self.g.get_member(uid)
                opts.append(discord.SelectOption(
                    label=f"🚫 {m.display_name if m else uid}"[:50],
                    value=f"bl:{uid}",
                    description="Retirer de la blacklist",
                ))
            for uid in wl[:12]:
                m = self.g.get_member(uid)
                opts.append(discord.SelectOption(
                    label=f"⭐ {m.display_name if m else uid}"[:50],
                    value=f"wl:{uid}",
                    description="Retirer de la whitelist",
                ))
            opts = opts[:25]
            v = View(timeout=120)
            sel = Select(placeholder="Choisir une entrée à retirer…", options=opts)

            async def _on_pick(ix):
                try:
                    val = ix.data['values'][0]
                    kind, uid_str = val.split(':', 1)
                    uid = int(uid_str)
                    cc = await cfg(self.g.id)
                    if kind == 'bl':
                        removed = delegations2026.remove_from_blacklist(cc, self.delegation_id, uid)
                        kind_label = "blacklist"
                    else:
                        removed = delegations2026.remove_from_whitelist(cc, self.delegation_id, uid)
                        kind_label = "whitelist"
                    if removed:
                        await db_set(self.g.id, delegations2026.CONFIG_KEY, cc.get(delegations2026.CONFIG_KEY, []))
                        m = self.g.get_member(uid)
                        await ix.response.send_message(
                            f"✅ {m.mention if m else f'`{uid}`'} retiré de la {kind_label}.",
                            ephemeral=True,
                        )
                    else:
                        await ix.response.send_message(
                            f"⚠️ Pas trouvé dans la {kind_label}.",
                            ephemeral=True,
                        )
                except Exception as ex:
                    print(f"[delmem manage_lists pick] {ex}")
                    try:
                        await ix.response.send_message(f"❌ Erreur : `{ex}`", ephemeral=True)
                    except Exception:
                        pass

            sel.callback = _on_pick
            v.add_item(sel)
            await i.response.send_message(
                f"📋 Blacklist `{len(bl)}` · Whitelist `{len(wl)}` — Choisis une entrée à retirer :",
                view=v,
                ephemeral=True,
            )
        except Exception as ex:
            print(f"[DelegationMembersPanelV2 _cb_manage_lists] {ex}")

    async def _cb_remove_member(self, i):
        """Phase 18.2 : multi-rôles → demander quel rôle retirer."""
        try:
            c = await cfg(self.g.id)
            d = delegations2026.get_delegation(c, self.delegation_id)
            if not d:
                return await i.response.send_message("❌ Distribution introuvable.", ephemeral=True)
            managed_roles = [self.g.get_role(rid) for rid in d.get('managed_role_ids', []) if self.g.get_role(rid)]
            if not managed_roles:
                return await i.response.send_message("❌ Aucun rôle géré configuré.", ephemeral=True)
            if len(managed_roles) > 1:
                return await self._open_role_then_user_select(i, managed_roles, mode='remove')
            await self._open_user_select_for_remove(i, managed_roles[0])
        except Exception as ex:
            print(f"[DelegationMembersPanelV2 _cb_remove_member] {ex}")

    async def _cb_refresh(self, i):
        try:
            await self.render_to(i, edit=True)
        except Exception as ex:
            print(f"[DelegationMembersPanelV2 _cb_refresh] {ex}")

    async def _cb_back(self, i):
        if self.back_to_owner:
            v = DelegationConfigPanelV2(self.u, self.g, self.delegation_id)
        else:
            # Pour le manager venant de /manage : retour à un message simple
            try:
                await i.response.edit_message(
                    content="✅ Panel fermé.",
                    view=None, embed=None, attachments=[],
                )
            except Exception:
                pass
            return
        await v.render_to(i, edit=True)


# ═══════════════════════════════════════════════════════════════════════════════
#  📋 LOGS UNIFIÉS — Panel V2 (Phase 3.8)
# ═══════════════════════════════════════════════════════════════════════════════

class LogsPanelV2(LayoutView):
    """Panneau Logs Unifiés : configurer le salon + catégories actives."""

    def __init__(self, u, g):
        super().__init__(timeout=600)
        self.u = u
        self.g = g

    async def interaction_check(self, i):
        return i.user.id == self.u.id

    async def render_to(self, interaction: discord.Interaction, *, edit: bool = True):
        chan_id = await ulogger2026.get_log_channel(self.g.id)
        cats_enabled = await ulogger2026.get_enabled_categories(self.g.id)
        all_cats = sorted(set(m["cat"] for m in ulogger2026.EVENT_META.values()))
        log_ch = self.g.get_channel(chan_id) if chan_id else None

        self.clear_items()

        # Section header
        items: list = []
        if self.g.icon:
            items.append(v2_section(
                v2_title("📋 Logs unifiés"),
                v2_subtitle("Un salon · tous les événements"),
                accessory=v2_thumb(self.g.icon.url),
            ))
        else:
            items.append(v2_title("📋 Logs unifiés"))
            items.append(v2_subtitle("Un salon · tous les événements"))
        items.append(v2_divider())

        # ─── État du salon (radio visuel) ───
        if log_ch:
            chan_line = f"🔘 **Salon actif** · {log_ch.mention}"
        elif chan_id:
            chan_line = f"⚠️ **Salon configuré mais introuvable** (`{chan_id}`)"
        else:
            chan_line = "⚪ **Salon non défini** — logs unifiés désactivés"
        items.append(v2_body(chan_line))

        # ─── Catégories (checkbox visuel) ───
        if log_ch:
            items.append(v2_divider())
            cat_emojis = {
                "Modération": "🔨", "Sécurité": "🛡️", "Membres": "👥",
                "Messages": "💬", "Vocal": "🎤", "Serveur": "🏷️",
                "Tickets": "🎫", "Config": "⚙️",
            }
            cats_lines = []
            for c in all_cats:
                icon = "✅" if c in cats_enabled else "☐"
                emoji = cat_emojis.get(c, "📋")
                cats_lines.append(f"{icon} {emoji} {c}")
            items.append(v2_title("Catégories", level=3))
            items.append(v2_body("\n".join(cats_lines)))

        items.append(v2_divider())

        # ─── Boutons ───
        if log_ch:
            b_chan = Button(label="📍 Changer salon", style=discord.ButtonStyle.primary, custom_id="logsv2_chan")
            b_chan.callback = self._cb_set_channel
            b_cats = Button(label="🎛️ Catégories", style=discord.ButtonStyle.primary, custom_id="logsv2_cats")
            b_cats.callback = self._cb_categories
            b_clear = Button(label="⚪ Désactiver", style=discord.ButtonStyle.danger, custom_id="logsv2_clear")
            b_clear.callback = self._cb_disable
            b_back = Button(label="◀️ Retour", style=discord.ButtonStyle.secondary, custom_id="logsv2_back")
            b_back.callback = self._cb_back
            items.append(discord.ui.ActionRow(b_chan, b_cats, b_clear))
            items.append(discord.ui.ActionRow(b_back))
        else:
            b_chan = Button(label="📍 Définir le salon", style=discord.ButtonStyle.success, custom_id="logsv2_chan")
            b_chan.callback = self._cb_set_channel
            b_back = Button(label="◀️ Retour", style=discord.ButtonStyle.secondary, custom_id="logsv2_back")
            b_back.callback = self._cb_back
            items.append(discord.ui.ActionRow(b_chan, b_back))

        self.add_item(v2_container(*items, color=Palette.INFO if log_ch else Palette.NEUTRAL))

        if edit:
            await interaction.response.edit_message(view=self, embed=None, attachments=[])
        else:
            await interaction.response.send_message(view=self, ephemeral=True)

    async def _cb_set_channel(self, i):
        async def _save_log_channel(guild_id: int, channel_id: int):
            await ulogger2026.set_log_channel(guild_id, channel_id)

        v = V2GenericChannelPicker(
            self.u, self.g,
            config_key="_unified_log_channel",  # ignored, save_fn handles it
            return_panel_factory=lambda: LogsPanelV2(self.u, self.g),
            title="📋 Salon de logs unifiés",
            description="Choisis le salon où arriveront tous les évènements.",
            color=0x3498DB,
            save_fn=_save_log_channel,
        )
        await v.render_to(i, edit=True)

    async def _cb_categories(self, i):
        v = LogsCategoriesPanelV2(self.u, self.g)
        await v.render_to(i, edit=True)

    async def _cb_disable(self, i):
        try:
            await ulogger2026.set_log_channel(self.g.id, 0)
        except Exception as ex:
            print(f"[LogsPanelV2 disable] {ex}")
        await self.render_to(i, edit=True)

    async def _cb_back(self, i):
        v = MainPanelV2(self.u, self.g)
        await i.response.edit_message(view=v, embed=None, attachments=[])


class LogsCategoriesPanelV2(LayoutView):
    """Sous-panel : toggle des catégories de logs."""

    def __init__(self, u, g):
        super().__init__(timeout=600)
        self.u = u
        self.g = g

    async def interaction_check(self, i):
        return i.user.id == self.u.id

    async def render_to(self, interaction: discord.Interaction, *, edit: bool = True):
        cats_enabled = await ulogger2026.get_enabled_categories(self.g.id)
        all_cats = sorted(set(m["cat"] for m in ulogger2026.EVENT_META.values()))

        self.clear_items()
        items: list = []
        items.append(v2_title("🎛️ Catégories de logs"))
        items.append(v2_subtitle("Coche/décoche les catégories à logger dans le salon unifié"))
        items.append(v2_divider())

        # Compter combien d'event types par catégorie
        cat_counts = {}
        for ev_type, meta in ulogger2026.EVENT_META.items():
            cat_counts[meta["cat"]] = cat_counts.get(meta["cat"], 0) + 1

        cat_emojis = {
            "Modération": "🔨", "Sécurité": "🛡️", "Membres": "👥",
            "Messages": "💬", "Vocal": "🎤", "Serveur": "🏷️",
            "Tickets": "🎫", "Config": "⚙️",
        }

        lines = []
        for c in all_cats:
            emoji = cat_emojis.get(c, "📋")
            count = cat_counts.get(c, 0)
            state = "✅ Activée" if c in cats_enabled else "❌ Désactivée"
            lines.append(f"{emoji} **{c}** · {count} types d'évènements · {state}")
        items.append(v2_body("\n".join(lines)))
        items.append(v2_divider())
        items.append(v2_subtitle("Utilise le menu ci-dessous pour cocher/décocher"))

        # Select multi avec defaults
        opts = []
        for c in all_cats:
            opts.append(discord.SelectOption(
                label=c,
                value=c,
                default=(c in cats_enabled),
                emoji=cat_emojis.get(c, "📋"),
                description=f"{cat_counts.get(c, 0)} types d'évènements",
            ))
        sel = Select(
            placeholder="Catégories actives…",
            min_values=0,
            max_values=len(opts),
            options=opts,
        )
        sel.callback = self._cb_select
        items.append(discord.ui.ActionRow(sel))

        b_back = Button(label="◀️ Retour", style=discord.ButtonStyle.secondary, custom_id="logsv2cats_back")
        b_back.callback = self._cb_back
        items.append(discord.ui.ActionRow(b_back))

        self.add_item(v2_container(*items, color=Palette.PRIMARY))

        if edit:
            await interaction.response.edit_message(view=self, embed=None, attachments=[])
        else:
            await interaction.response.send_message(view=self, ephemeral=True)

    async def _cb_select(self, i):
        try:
            chosen = set(i.data.get('values', []))
            await ulogger2026.set_enabled_categories(self.g.id, chosen)
        except Exception as ex:
            print(f"[LogsCategoriesPanelV2 _cb_select] {ex}")
        await self.render_to(i, edit=True)

    async def _cb_back(self, i):
        v = LogsPanelV2(self.u, self.g)
        await v.render_to(i, edit=True)


# ═══════════════════════════════════════════════════════════════════════════════
#                           🛡️ PROTECTION PANEL (REFAIT PROPREMENT)
# ═══════════════════════════════════════════════════════════════════════════════

class ProtPanel(View):
    def __init__(self, u, g):
        super().__init__(timeout=600)
        self.u = u
        self.g = g
    
    async def embed(self):
        c = await cfg(self.g.id)
        e = discord.Embed(color=0x3498DB)
        e.set_author(name="🛡️ Protection du Serveur", icon_url=self.g.icon.url if self.g.icon else None)
        
        enabled_count = 0
        lines = []
        for key, emoji, name in PROTS:
            is_on = c.get(key)
            if is_on:
                enabled_count += 1
            status = "🟢" if is_on else "🔴"
            log_ch = self.g.get_channel(c.get(f'log_{key}', 0))
            log_txt = f" → {log_ch.mention}" if log_ch else ""
            lines.append(f"{status} {emoji} **{name}**{log_txt}")
        
        # Barre de progression visuelle
        total = len(PROTS)
        bar_filled = round(enabled_count / total * 10) if total > 0 else 0
        bar = "█" * bar_filled + "░" * (10 - bar_filled)
        pct = round(enabled_count / total * 100) if total > 0 else 0
        
        desc = (
            f"**Score de protection : {pct}%**\n"
            f"`[{bar}]` {enabled_count}/{total} actives\n"
            f"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n"
        )
        desc += "\n".join(lines)
        desc += f"\n━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n"
        desc += "*▼ Sélectionnez une protection pour la configurer*"
        e.description = desc
        
        if self.g.icon:
            e.set_thumbnail(url=self.g.icon.url)
        e.set_footer(text=f"🛡️ Protection • {self.g.name}")
        return e
    
    @discord.ui.select(
        placeholder="🛡️ Sélectionner une protection...",
        options=[discord.SelectOption(label=nm, value=k, emoji=em) for k, em, nm in PROTS]
    )
    async def sel(self, i, s):
        prot = next(p for p in PROTS if p[0] == s.values[0])
        v = ProtDetail(self.u, self.g, prot)
        await i.response.edit_message(embed=await v.embed(), view=v)
    
    @discord.ui.button(label="◀️ Retour", style=discord.ButtonStyle.secondary, row=1)
    async def back(self, i, b):
        v = MainPanelV2(self.u, self.g)
        await v.render_to(i, edit=True)

class ProtPanelV2(LayoutView):
    """Panneau Protection du Serveur en V2."""

    def __init__(self, u, g):
        super().__init__(timeout=600)
        self.u = u
        self.g = g

    async def interaction_check(self, i):
        return i.user.id == self.u.id

    async def render_to(self, interaction: discord.Interaction, *, edit: bool = True):
        c = await cfg(self.g.id)

        enabled_count = 0
        lines_out = []
        for key, emoji, name in PROTS:
            is_on = bool(c.get(key))
            if is_on:
                enabled_count += 1
            # Phase 5.3 : radio-style 🔘 / ⚪ au lieu de feu 🟢 / 🔴
            dot = "🔘" if is_on else "⚪"
            lines_out.append(f"{dot} {emoji} **{name}**")

        total = len(PROTS)
        pct = round(enabled_count / total * 100) if total > 0 else 0

        sel = Select(
            placeholder="🛡️ Choisir une protection à configurer…",
            options=[discord.SelectOption(label=nm, value=k, emoji=em) for k, em, nm in PROTS],
            custom_id="ppv2_sel",
        )
        sel.callback = self._cb_sel
        b_back = Button(label="◀️ Retour", style=discord.ButtonStyle.secondary, custom_id="ppv2_back")
        b_back.callback = self._cb_back

        self.clear_items()
        items: list = []
        if self.g.icon:
            items.append(v2_section(
                v2_title("🛡️ Protection"),
                v2_subtitle(f"`{enabled_count}/{total}` filtres actifs · `{pct}%`"),
                accessory=v2_thumb(self.g.icon.url),
            ))
        else:
            items.append(v2_title("🛡️ Protection"))
            items.append(v2_subtitle(f"`{enabled_count}/{total}` filtres actifs · `{pct}%`"))

        items.append(v2_divider())
        items.append(v2_body("\n".join(lines_out)))
        items.append(v2_divider())
        items.append(discord.ui.ActionRow(sel))
        items.append(discord.ui.ActionRow(b_back))

        self.add_item(v2_container(*items, color=Palette.INFO))

        if edit:
            await interaction.response.edit_message(view=self, embed=None, attachments=[])
        else:
            await interaction.response.send_message(view=self, ephemeral=True)

    async def _cb_sel(self, interaction):
        val = interaction.data['values'][0]
        prot = next(p for p in PROTS if p[0] == val)
        v = ProtDetailV2(self.u, self.g, prot)
        await v.render_to(interaction, edit=True)

    async def _cb_back(self, i):
        # Phase 4 : retour vers SecurityPanelV2 (le hub Sécurité unifié)
        v = SecurityPanelV2(self.u, self.g)
        await v.render_to(i, edit=True)


class ProtDetail(View):
    def __init__(self, u, g, prot):
        super().__init__(timeout=600)
        self.u = u
        self.g = g
        self.prot = prot
        self.key = prot[0]
    
    async def embed(self):
        c = await cfg(self.g.id)
        on = bool(c.get(self.key))
        e = discord.Embed(
            title=f"{self.prot[1]} {self.prot[2]}",
            color=C.GREEN if on else C.RED
        )
        e.add_field(name="🔘 État", value="✅ ACTIVÉ" if on else "❌ DÉSACTIVÉ", inline=False)
        
        # ─── Helper pour afficher action + durée ───
        def _add_sanction_fields(embed, protection_key):
            acp = ActionConfigPanel(self.u, self.g, protection_key)
            ak = acp._get_action_key()
            dk = acp._get_duration_key()
            act = c.get(ak, acp._get_default_action())
            dur = c.get(dk, acp._get_default_duration())
            act_emoji = {'delete': '🗑️', 'mute': '🔇', 'kick': '👢', 'ban': '🔨'}.get(act, '⚡')
            embed.add_field(name="⚡ Sanction", value=f"{act_emoji} **{act.upper()}**", inline=True)
            if act == 'mute':
                embed.add_field(name="⏱️ Durée mute", value=f"`{dur}` min", inline=True)

        # Configs spécifiques
        if self.key == "anti_link":
            wl = c.get('link_whitelist', [])
            e.add_field(name="🌐 Whitelist domaines", value=f"`{', '.join(wl[:15])}`" if wl else "*Aucun domaine*", inline=False)
            chs = c.get('link_allowed_channels', [])
            ch_txt = ", ".join([f"<#{x}>" for x in chs[:10]]) if chs else "*Aucun salon*"
            e.add_field(name="📍 Salons autorisés", value=ch_txt, inline=False)
            _add_sanction_fields(e, self.key)

        elif self.key == "anti_image":
            items = c.get('image_allowed', [])
            fmts = ['png', 'jpg', 'jpeg', 'gif', 'webp', 'tenor', 'giphy']
            fmt_txt = " ".join([f"{'✅' if f in items else '❌'} `{f}`" for f in fmts])
            e.add_field(name="📁 Formats autorisés", value=fmt_txt, inline=False)
            _add_sanction_fields(e, self.key)

        elif self.key == "anti_badwords":
            words = c.get('badwords_list', [])
            if words:
                if len(words) <= 30:
                    words_txt = ", ".join([f"`{w}`" for w in words])
                else:
                    words_txt = ", ".join([f"`{w}`" for w in words[:30]]) + f"\n*... et {len(words) - 30} autres*"
                e.add_field(name=f"🚫 Mots interdits ({len(words)})", value=words_txt[:1024], inline=False)
            else:
                e.add_field(name="🚫 Mots interdits", value="*Aucun mot configuré*", inline=False)
            _add_sanction_fields(e, self.key)

        elif self.key == "anti_spam":
            e.add_field(name="📊 Max messages", value=str(c.get('spam_max', 5)), inline=True)
            e.add_field(name="⏱️ Intervalle (sec)", value=str(c.get('spam_interval', 5)), inline=True)
            _add_sanction_fields(e, self.key)

        elif self.key == "anti_caps":
            e.add_field(name="📊 Pourcentage max", value=f"{c.get('caps_percent', 70)}%", inline=True)
            _add_sanction_fields(e, self.key)

        elif self.key == "anti_mass_mention":
            max_mentions = c.get('mention_limit', 5)
            e.add_field(name="📊 Max mentions", value=f"`{max_mentions}` par message", inline=True)
            _add_sanction_fields(e, self.key)
            e.add_field(name="ℹ️ Info", value="Détecte @everyone, @here, et les mentions massives de membres/rôles", inline=False)

        elif self.key == "anti_newaccount":
            e.add_field(name="📅 Jours minimum", value=str(c.get('newaccount_days', 7)), inline=True)

        elif self.key in ["anti_phishing", "anti_scam"]:
            _add_sanction_fields(e, self.key)

        elif self.key == "anti_invite":
            _add_sanction_fields(e, self.key)
        
        elif self.key == "anti_raid":
            raid_cfg = c.get('raid_config', {})
            e.add_field(name="👥 Seuil de détection", value=f"`{raid_cfg.get('join_threshold', 10)}` membres en `{raid_cfg.get('join_interval', 10)}` sec", inline=False)
            e.add_field(name="📅 Âge compte min", value=f"`{raid_cfg.get('min_account_age', 7)}` jours", inline=True)
            e.add_field(name="🤖 Mode auto", value="✅ Oui" if raid_cfg.get('auto_mode', True) else "❌ Non", inline=True)
            e.add_field(name="🔒 Bloquer invitations", value="✅ Oui" if raid_cfg.get('block_invites', True) else "❌ Non", inline=True)
            action = raid_cfg.get('action', 'kick')
            e.add_field(name="⚡ Action", value=action.upper(), inline=True)
            
            # État du lockdown
            lockdown = raid_tracker.get(self.g.id, {}).get('lockdown', False)
            e.add_field(name="🚨 Lockdown actif", value="⚠️ **OUI**" if lockdown else "✅ Non", inline=True)
        
        elif self.key == "anti_compromised":
            e.description = "🔐 **Détection des comptes compromis/hackés**\n\nDétecte les comportements suspects indiquant qu'un compte a été compromis :\n• Spam de @everyone avec liens\n• Messages identiques répétés\n• Premier message = lien suspect"
            _add_sanction_fields(e, self.key)
            e.add_field(name="📊 Détections", value=f"`{len(PHISHING_DOMAINS)}` domaines\n`{len(SCAM_KEYWORDS)}` mots-clés\n`{len(COMPROMISED_PATTERNS)}` patterns", inline=True)

        elif self.key == "anti_qrcode":
            e.description = "📱 **Protection contre les scams par QR Code**\n\nDétecte les tentatives de vol de compte via QR code Discord :\n• Messages demandant de scanner un QR code\n• Faux QR codes de 'cadeaux'\n• Tentatives de vol de token"
            _add_sanction_fields(e, self.key)

        elif self.key == "anti_phishing":
            e.description = (
                "🎣 **Protection Anti-Phishing Avancée 2026**\n\nProtège contre :\n"
                "• Faux sites Discord/Steam/Nitro/Roblox\n"
                "• Typosquatting (dlscord, steampowored...)\n"
                "• Liens masqués [texte](url phishing)\n"
                "• Scam 'Verify age group' / Safeguard bot\n"
                "• IP grabbers et raccourcisseurs suspects\n"
                "• TLD dangereux (.ru, .tk, .xyz...)\n"
                "• URLs dans les embeds de messages"
            )
            _add_sanction_fields(e, self.key)
            e.add_field(name="📊 Base de données", value=f"`{len(PHISHING_DOMAINS)}` domaines blacklistés", inline=True)

        elif self.key == "anti_scam":
            e.description = (
                "🚨 **Protection Anti-Scam Avancée 2026**\n\nDétecte :\n"
                "• Free Nitro / Steam Gift scams\n"
                "• Crypto giveaway / Airdrop scams\n"
                "• Scam vérification âge Discord\n"
                "• Token grabbers / ClickFix\n"
                "• Faux jeux à tester (playtest)\n"
                "• Investment / Job / Romance scams\n"
                "• Urgence artificielle"
            )
            _add_sanction_fields(e, self.key)
            e.add_field(name="📊 Base de données", value=f"`{len(SCAM_KEYWORDS)}` mots-clés détectés", inline=True)
        
        elif self.key == "anti_alt":
            alt_cfg = c.get('alt_config', {})
            e.description = (
                "👥 **Détection des Comptes Secondaires**\n\n"
                "Détecte automatiquement les comptes secondaires (alts) :\n"
                "• Avatar identique à un membre existant/banni\n"
                "• Nom d'utilisateur similaire\n"
                "• Compte créé juste après un ban\n"
                "• Comportement suspect"
            )
            
            action = c.get('alt_action', 'kick')
            auto = alt_cfg.get('auto_action', False)
            min_conf = alt_cfg.get('min_confidence', 70)
            
            e.add_field(name="⚡ Action", value=action.upper(), inline=True)
            e.add_field(name="🤖 Action auto", value="✅ Activé" if auto else "❌ Désactivé", inline=True)
            e.add_field(name="📊 Confiance min.", value=f"{min_conf}%", inline=True)
            
            # Comptes secondaires détectés
            alts = await get_alt_accounts(self.g.id)
            suspected = len([a for a in alts if a[5] == 'suspected'])
            confirmed = len([a for a in alts if a[5] == 'confirmed'])
            e.add_field(name="🔍 Détections", value=f"⚠️ {suspected} suspects\n✅ {confirmed} confirmés", inline=False)
        
        # Salon de log
        log_ch = self.g.get_channel(c.get(f'log_{self.key}', 0))
        e.add_field(name="📜 Salon de log", value=log_ch.mention if log_ch else "❌ Non configuré", inline=False)
        
        return e
    
    @discord.ui.button(label="🔄 ON/OFF", style=discord.ButtonStyle.primary, row=0)
    async def toggle(self, i, b):
        c = await cfg(self.g.id)
        new_val = 0 if c.get(self.key) else 1
        await db_set(self.g.id, self.key, new_val)
        v = ProtDetail(self.u, self.g, self.prot)
        await i.response.edit_message(embed=await v.embed(), view=v)
    
    @discord.ui.button(label="⚙️ Configurer", style=discord.ButtonStyle.secondary, row=0)
    async def config(self, i, b):
        if self.key == "anti_image":
            v = ImageConfigPanel(self.u, self.g)
            await i.response.edit_message(embed=await v.embed(), view=v)
        elif self.key == "anti_badwords":
            v = BadwordsConfigPanel(self.u, self.g)
            await i.response.edit_message(embed=await v.embed(), view=v)
        elif self.key == "anti_link":
            v = LinkConfigPanel(self.u, self.g)
            await i.response.edit_message(embed=await v.embed(), view=v)
        elif self.key in ["anti_spam", "anti_caps", "anti_newaccount", "anti_mass_mention"]:
            await i.response.send_modal(NumberConfigModal(self.g, self.u, self.key))
        elif self.key == "anti_raid":
            v = AntiRaidConfigPanel(self.u, self.g)
            await i.response.edit_message(embed=await v.embed(), view=v)
        elif self.key == "anti_alt":
            v = AltConfigPanel(self.u, self.g)
            await i.response.edit_message(embed=await v.embed(), view=v)
        else:
            # Toutes les autres protections → ActionConfigPanel (action + durée mute)
            v = ActionConfigPanel(self.u, self.g, self.key)
            await i.response.edit_message(embed=await v.embed(), view=v)

    @discord.ui.button(label="⚡ Sanction", style=discord.ButtonStyle.danger, row=0)
    async def sanction_btn(self, i, b):
        """Ouvrir le panel de sanction pour n'importe quelle protection"""
        v = ActionConfigPanel(self.u, self.g, self.key)
        await i.response.edit_message(embed=await v.embed(), view=v)
    
    @discord.ui.button(label="📜 Définir Log", style=discord.ButtonStyle.secondary, row=0)
    async def set_log(self, i, b):
        try:
            total_channels = len(list(self.g.text_channels))
            v = LogSelectView(self.u, self.g, self.key, self.prot)
            await i.response.edit_message(
                embed=discord.Embed(
                    title="📜 Choisir le salon de log",
                    description=f"Pour la protection **{self.prot[2]}**\n\n📊 {total_channels} salons disponibles",
                    color=C.PURPLE
                ),
                view=v
            )
        except Exception as ex:
            print(f"[LOG SELECT ERROR] {ex}")
            await i.response.send_message(f"❌ Erreur: {ex}", ephemeral=True)
    
    @discord.ui.button(label="◀️ Retour", style=discord.ButtonStyle.secondary, row=1)
    async def back(self, i, b):
        v = ProtPanel(self.u, self.g)
        await i.response.edit_message(embed=await v.embed(), view=v)

