class ImmunePanel(View):
    def __init__(self, u, g):
        super().__init__(timeout=600)
        self.u = u
        self.g = g
    
    async def embed(self):
        async with get_db() as db:
            async with db.execute('SELECT role_id FROM immune_roles WHERE guild_id=?', (self.g.id,)) as c:
                rids = [r[0] for r in await c.fetchall()]
            async with db.execute('SELECT user_id FROM immune_users WHERE guild_id=?', (self.g.id,)) as c:
                uids = [r[0] for r in await c.fetchall()]
            async with db.execute('SELECT channel_id FROM immune_channels WHERE guild_id=?', (self.g.id,)) as c:
                chids = [r[0] for r in await c.fetchall()]
        
        total = len(rids) + len(uids) + len(chids)
        e = discord.Embed(color=0xF1C40F)
        e.set_author(name="👑 Immunités", icon_url=self.g.icon.url if self.g.icon else None)
        e.description = (
            f"**{total}** éléments immunisés au total\n"
            f"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n"
            f"✅ Liens, images, GIFs, invitations, majuscules\n"
            f"⚠️ **Phishing & Scams restent détectés**"
        )
        
        # Rôles
        roles_txt = ", ".join([f"<@&{r}>" for r in rids[:10]]) if rids else "*Aucun*"
        if len(rids) > 10: roles_txt += f"\n*... +{len(rids)-10} autres*"
        e.add_field(name=f"🎭 Rôles ({len(rids)})", value=roles_txt, inline=False)
        
        # Utilisateurs
        users_txt = ", ".join([f"<@{u}>" for u in uids[:10]]) if uids else "*Aucun*"
        if len(uids) > 10: users_txt += f"\n*... +{len(uids)-10} autres*"
        e.add_field(name=f"👤 Utilisateurs ({len(uids)})", value=users_txt, inline=False)
        
        # Salons
        chans_txt = ", ".join([f"<#{c}>" for c in chids[:10]]) if chids else "*Aucun*"
        if len(chids) > 10: chans_txt += f"\n*... +{len(chids)-10} autres*"
        e.add_field(name=f"📺 Salons ({len(chids)})", value=chans_txt, inline=False)
        
        e.set_footer(text="👑 Immunités • Les tickets sont automatiquement immunisés")
        return e
    
    @discord.ui.button(label="➕ Rôle", style=discord.ButtonStyle.success, row=0)
    async def add_role(self, i, b):
        total_roles = len([r for r in self.g.roles[1:] if not r.is_bot_managed()])
        v = PaginatedImmuneRoleView(self.u, self.g)
        await i.response.edit_message(
            embed=discord.Embed(
                title="👑 Ajouter un rôle immunisé",
                description=f"📊 {total_roles} rôles disponibles",
                color=C.YELLOW
            ),
            view=v
        )
    
    @discord.ui.button(label="➕ Utilisateur", style=discord.ButtonStyle.success, row=0)
    async def add_user(self, i, b):
        await i.response.send_modal(AddImmuneUserModal(self.g, self.u))
    
    @discord.ui.button(label="➕ Salon", style=discord.ButtonStyle.success, row=0)
    async def add_channel(self, i, b):
        total_channels = len(list(self.g.text_channels))
        v = PaginatedImmuneChannelView(self.u, self.g)
        await i.response.edit_message(
            embed=discord.Embed(
                title="📺 Ajouter un salon immunisé",
                description=f"Ce salon ignorera toutes les protections.\n\n📊 {total_channels} salons disponibles",
                color=C.YELLOW
            ),
            view=v
        )
    
    @discord.ui.button(label="🗑️ Supprimer", style=discord.ButtonStyle.danger, row=1)
    async def remove_item(self, i, b):
        # Créer une vue avec les options de suppression
        v = ImmuneRemoveView(self.u, self.g)
        await i.response.edit_message(embed=discord.Embed(title="🗑️ Supprimer une immunité", description="Choisissez le type d'élément à supprimer.", color=C.RED), view=v)
    
    @discord.ui.button(label="🗑️ Tout supprimer", style=discord.ButtonStyle.danger, row=1)
    async def clear(self, i, b):
        async with get_db() as db:
            await db.execute('DELETE FROM immune_roles WHERE guild_id=?', (self.g.id,))
            await db.execute('DELETE FROM immune_users WHERE guild_id=?', (self.g.id,))
            await db.execute('DELETE FROM immune_channels WHERE guild_id=?', (self.g.id,))
            await db.commit()
        v = ImmunePanelV2(self.u, self.g)
        await v.render_to(i, edit=True)
    
    @discord.ui.button(label="◀️ Retour", style=discord.ButtonStyle.secondary, row=2)
    async def back(self, i, b):
        v = MainPanelV2(self.u, self.g)
        await v.render_to(i, edit=True)

class ImmunePanelV2(LayoutView):
    """Panneau Immunités en V2."""

    def __init__(self, u, g):
        super().__init__(timeout=600)
        self.u = u
        self.g = g

    async def interaction_check(self, i):
        return i.user.id == self.u.id

    async def render_to(self, interaction: discord.Interaction, *, edit: bool = True):
        async with get_db() as db:
            async with db.execute('SELECT role_id FROM immune_roles WHERE guild_id=?', (self.g.id,)) as c:
                rids = [r[0] for r in await c.fetchall()]
            async with db.execute('SELECT user_id FROM immune_users WHERE guild_id=?', (self.g.id,)) as c:
                uids = [r[0] for r in await c.fetchall()]
            async with db.execute('SELECT channel_id FROM immune_channels WHERE guild_id=?', (self.g.id,)) as c:
                chids = [r[0] for r in await c.fetchall()]

        total = len(rids) + len(uids) + len(chids)

        # Phase 6 : affichage compact, 6 max par catégorie
        def _list(items, fmt, label):
            if not items:
                return f"⚪ _aucun {label}_"
            shown = ", ".join(fmt(x) for x in items[:6])
            if len(items) > 6:
                shown += f" *(+{len(items) - 6})*"
            return shown

        roles_txt = _list(rids, lambda r: f"<@&{r}>", "rôle")
        users_txt = _list(uids, lambda u: f"<@{u}>", "utilisateur")
        chans_txt = _list(chids, lambda c: f"<#{c}>", "salon")

        # Boutons
        self.clear_items()
        b_add_role = Button(label="➕ Rôle", style=discord.ButtonStyle.success, custom_id="ipv2_add_role")
        b_add_role.callback = self._cb_add_role
        b_add_user = Button(label="➕ Utilisateur", style=discord.ButtonStyle.success, custom_id="ipv2_add_user")
        b_add_user.callback = self._cb_add_user
        b_add_chan = Button(label="➕ Salon", style=discord.ButtonStyle.success, custom_id="ipv2_add_chan")
        b_add_chan.callback = self._cb_add_chan
        b_remove = Button(label="🗑️ Retirer", style=discord.ButtonStyle.danger, disabled=(total == 0), custom_id="ipv2_remove")
        b_remove.callback = self._cb_remove
        b_clear = Button(label="🧹 Tout effacer", style=discord.ButtonStyle.danger, disabled=(total == 0), custom_id="ipv2_clear")
        b_clear.callback = self._cb_clear
        b_back = Button(label="◀️ Retour", style=discord.ButtonStyle.secondary, custom_id="ipv2_back")
        b_back.callback = self._cb_back

        items: list = []
        if self.g.icon:
            items.append(v2_section(
                v2_title("👑 Immunités"),
                v2_subtitle(f"`{total}` élément(s) · bypass des filtres"),
                accessory=v2_thumb(self.g.icon.url),
            ))
        else:
            items.append(v2_title("👑 Immunités"))
            items.append(v2_subtitle(f"`{total}` élément(s) · bypass des filtres"))

        items.append(v2_divider())
        items.append(v2_body(
            f"🎭 **Rôles** *(`{len(rids)}`)* · {roles_txt}\n"
            f"👤 **Utilisateurs** *(`{len(uids)}`)* · {users_txt}\n"
            f"📺 **Salons** *(`{len(chids)}`)* · {chans_txt}"
        ))
        items.append(v2_divider())
        items.append(v2_body(
            "ℹ️ Les immunisés ignorent : liens, images, GIFs, invitations, majuscules.\n"
            "⚠️ **Phishing & scams restent détectés** pour tout le monde."
        ))
        items.append(v2_divider())
        items.append(discord.ui.ActionRow(b_add_role, b_add_user, b_add_chan))
        items.append(discord.ui.ActionRow(b_remove, b_clear, b_back))

        self.add_item(v2_container(*items, color=Palette.PREMIUM))

        if edit:
            await interaction.response.edit_message(view=self, embed=None, attachments=[])
        else:
            await interaction.response.send_message(view=self, ephemeral=True)

    async def _cb_add_role(self, i):
        total_roles = len([r for r in self.g.roles[1:] if not r.is_bot_managed()])
        v = PaginatedImmuneRoleView(self.u, self.g)
        await i.response.edit_message(
            embed=discord.Embed(
                title="👑 Ajouter un rôle immunisé",
                description=f"📊 {total_roles} rôles disponibles",
                color=0xF1C40F,
            ),
            view=v,
            attachments=[],
        )

    async def _cb_add_user(self, i):
        await i.response.send_modal(AddImmuneUserModal(self.g, self.u))

    async def _cb_add_chan(self, i):
        total_channels = len(list(self.g.text_channels))
        v = PaginatedImmuneChannelView(self.u, self.g)
        await i.response.edit_message(
            embed=discord.Embed(
                title="📺 Ajouter un salon immunisé",
                description=f"Ce salon ignorera toutes les protections.\n\n📊 {total_channels} salons disponibles",
                color=0xF1C40F,
            ),
            view=v,
            attachments=[],
        )

    async def _cb_remove(self, i):
        v = ImmuneRemoveViewV2(self.u, self.g)
        await v.render_to(i, edit=True)
        return  # short-circuit pour éviter le code legacy ci-dessous

    async def _cb_remove_legacy(self, i):
        v = ImmuneRemoveView(self.u, self.g)
        await i.response.edit_message(
            embed=discord.Embed(
                title="🗑️ Supprimer une immunité",
                description="Choisis le type d'élément à supprimer.",
                color=0xE74C3C,
            ),
            view=v,
            attachments=[],
        )

    async def _cb_clear(self, i):
        async with get_db() as db:
            await db.execute('DELETE FROM immune_roles WHERE guild_id=?', (self.g.id,))
            await db.execute('DELETE FROM immune_users WHERE guild_id=?', (self.g.id,))
            await db.execute('DELETE FROM immune_channels WHERE guild_id=?', (self.g.id,))
            await db.commit()
        new_panel = ImmunePanelV2(self.u, self.g)
        await new_panel.render_to(i, edit=True)

    async def _cb_back(self, i):
        # Phase 4 : retour vers SecurityPanelV2
        v = SecurityPanelV2(self.u, self.g)
        await v.render_to(i, edit=True)


class PaginatedImmuneRoleView(View):
    """Sélecteur de rôle paginé pour les immunités"""
    def __init__(self, u, g, page=0):
        super().__init__(timeout=180)
        self.u = u
        self.g = g
        self.page = page
        self.roles = [r for r in g.roles[1:] if not r.is_bot_managed()]
        self.max_page = max(0, (len(self.roles) - 1) // 24)
        self._build()
    
    def _build(self):
        self.clear_items()
        
        start = self.page * 24
        end = start + 24
        page_roles = self.roles[start:end]
        
        opts = []
        for r in page_roles:
            opts.append(discord.SelectOption(
                label=f"@{r.name}"[:25],
                value=str(r.id),
                description=f"{len(r.members)} membres"[:50]
            ))
        
        if opts:
            select = ImmuneRoleSelectMenu(self, opts)
            self.add_item(select)
        
        # Navigation
        if self.max_page > 0:
            prev_btn = discord.ui.Button(label="◀️", style=discord.ButtonStyle.primary, disabled=(self.page == 0), row=1)
            prev_btn.callback = self.prev_page
            self.add_item(prev_btn)
            
            page_btn = discord.ui.Button(label=f"{self.page + 1}/{self.max_page + 1}", style=discord.ButtonStyle.secondary, disabled=True, row=1)
            self.add_item(page_btn)
            
            next_btn = discord.ui.Button(label="▶️", style=discord.ButtonStyle.primary, disabled=(self.page >= self.max_page), row=1)
            next_btn.callback = self.next_page
            self.add_item(next_btn)
        
        back_btn = discord.ui.Button(label="◀️ Retour", style=discord.ButtonStyle.danger, row=2)
        back_btn.callback = self.go_back
        self.add_item(back_btn)
    
    async def prev_page(self, i):
        self.page -= 1
        self._build()
        await i.response.edit_message(view=self)
    
    async def next_page(self, i):
        self.page += 1
        self._build()
        await i.response.edit_message(view=self)
    
    async def go_back(self, i):
        v = ImmunePanelV2(self.u, self.g)
        await v.render_to(i, edit=True)

class ImmuneRoleSelectMenu(Select):
    def __init__(self, parent, opts):
        super().__init__(placeholder=f"Page {parent.page + 1}/{parent.max_page + 1} - Choisir un rôle...", options=opts)
        self.parent_view = parent
    
