class AdsGameUpdatesPanelV2(LayoutView):
    """Configuration du suivi des mises à jour de plateformes et jeux."""

    def __init__(self, u, g):
        super().__init__(timeout=600)
        self.u = u
        self.g = g

    async def interaction_check(self, i):
        return i.user.id == self.u.id

    async def render_to(self, interaction: discord.Interaction, *, edit: bool = True):
        c = await cfg(self.g.id)
        feeds = c.get('ads_updates_feeds', []) or []

        def dot(x):
            return f"🔘 {x.mention}" if x else "⚪ _non défini_"

        # Liste compacte des feeds configurés
        feed_lines = []
        for f in feeds[:8]:
            if not isinstance(f, dict):
                continue
            gk = f.get('game_key', '')
            chid = f.get('channel_id', 0)
            ch = self.g.get_channel(chid) if chid else None
            meta = gameupdates2026.get_game_meta(gk)
            feed_lines.append(
                f"• {meta['emoji']} **{meta['name']}** → {ch.mention if ch else '⚪ _salon ?_'}"
            )
        if len(feeds) > 8:
            feed_lines.append(f"_… +{len(feeds) - 8}_")
        feeds_block = "\n".join(feed_lines) if feed_lines else "_Aucun suivi configuré — clique ➕ Ajouter_"

        # Boutons
        self.clear_items()
        b_add = Button(label="➕ Ajouter", style=discord.ButtonStyle.success, custom_id="agupv2_add")
        b_add.callback = self._cb_add
        b_remove = Button(
            label="🗑️ Retirer",
            style=discord.ButtonStyle.danger,
            disabled=(not feeds),
            custom_id="agupv2_remove",
        )
        b_remove.callback = self._cb_remove
        b_back = Button(label="◀️ Retour", style=discord.ButtonStyle.secondary, custom_id="agupv2_back")
        b_back.callback = self._cb_back

        items: list = []
        if self.g.icon:
            items.append(v2_section(
                v2_title("🎮 Mises à jour"),
                v2_subtitle(f"`{len(feeds)}` plateforme(s)/jeu(x) suivi(s)"),
                accessory=v2_thumb(self.g.icon.url),
            ))
        else:
            items.append(v2_title("🎮 Mises à jour"))
            items.append(v2_subtitle(f"`{len(feeds)}` plateforme(s)/jeu(x) suivi(s)"))

        items.append(v2_divider())
        items.append(v2_body(
            "Suis les **vraies mises à jour officielles** (patch notes, dev updates) "
            "de plateformes (Roblox, Steam, Epic, Blizzard…) et jeux populaires "
            "(Subnautica 2, CS2, WoW, Genshin, Helldivers 2, …)."
        ))
        items.append(v2_divider())
        items.append(v2_title("Sources suivies", level=3))
        items.append(v2_body(feeds_block))
        items.append(v2_divider())
        items.append(v2_subtitle("🔄 Check toutes les 5 min · Dédup persistant · Pas d'événements ni de promos"))
        items.append(discord.ui.ActionRow(b_add, b_remove, b_back))

        self.add_item(v2_container(*items, color=Palette.INFO))

        if edit:
            await interaction.response.edit_message(view=self, embed=None, attachments=[])
        else:
            await interaction.response.send_message(view=self, ephemeral=True)

    async def _cb_add(self, i):
        try:
            v = AddGameUpdateView(self.u, self.g)
            await v.render_to(i, edit=True)
        except Exception as ex:
            print(f"[AdsGameUpdatesPanelV2 _cb_add] {ex}")
            try:
                if not i.response.is_done():
                    await i.response.send_message(f"❌ Erreur : `{ex}`", ephemeral=True)
            except Exception:
                pass

    async def _cb_remove(self, i):
        try:
            c = await cfg(self.g.id)
            feeds = c.get('ads_updates_feeds', []) or []
            if not feeds:
                return await i.response.send_message("❌ Aucun suivi à retirer", ephemeral=True)
            opts = []
            for idx, f in enumerate(feeds[:25]):
                if not isinstance(f, dict):
                    continue
                gk = f.get('game_key', '')
                meta = gameupdates2026.get_game_meta(gk)
                ch = self.g.get_channel(f.get('channel_id', 0))
                label = f"{meta['name']}"[:50]
                desc = (f"→ #{ch.name}" if ch else "salon ?")[:50]
                opts.append(discord.SelectOption(label=label, value=str(idx), description=desc, emoji=meta['emoji']))

            v = View(timeout=120)
            sel = Select(placeholder="Choisir le suivi à retirer…", options=opts)

            async def _on_remove(ix):
                try:
                    idx = int(ix.data['values'][0])
                    cc = await cfg(self.g.id)
                    ff = cc.get('ads_updates_feeds', []) or []
                    if 0 <= idx < len(ff):
                        removed = ff.pop(idx)
                        await db_set(self.g.id, 'ads_updates_feeds', ff)
                        meta = gameupdates2026.get_game_meta(removed.get('game_key', ''))
                        await ix.response.send_message(
                            f"✅ Suivi **{meta['name']}** retiré.",
                            ephemeral=True,
                        )
                        # Re-render le panel
                        new_v = AdsGameUpdatesPanelV2(self.u, self.g)
                        try:
                            await ix.edit_original_response(view=new_v)
                        except Exception:
                            pass
                except Exception as ex:
                    print(f"[remove update feed] {ex}")
                    try:
                        await ix.response.send_message(f"❌ Erreur : `{ex}`", ephemeral=True)
                    except Exception:
                        pass

            sel.callback = _on_remove
            v.add_item(sel)
            await i.response.send_message(
                "🗑️ Quel suivi retirer ?",
                view=v,
                ephemeral=True,
            )
        except Exception as ex:
            print(f"[AdsGameUpdatesPanelV2 _cb_remove] {ex}")
            try:
                if not i.response.is_done():
                    await i.response.send_message(f"❌ Erreur : `{ex}`", ephemeral=True)
            except Exception:
                pass

    async def _cb_back(self, i):
        v = AdsPanelV2(self.u, self.g)
        await v.render_to(i, edit=True)


class AddGameUpdateView(LayoutView):
    """Sub-panel : choisir un jeu/plateforme puis un salon pour le suivi."""

    def __init__(self, u, g):
        super().__init__(timeout=300)
        self.u = u
        self.g = g
        self.selected_game = None
        self._build()

    async def interaction_check(self, i):
        return i.user.id == self.u.id

    def _build(self):
        self.clear_items()
        games = gameupdates2026.list_available_games()
        # Discord limite à 25 options par Select
        # Plateformes (5) + jeux (limité à 20)
        opts = []
        for key, emoji, name in games[:25]:
            opts.append(discord.SelectOption(
                label=name[:100],
                value=key,
                emoji=emoji,
                default=(key == self.selected_game),
            ))

        sel = Select(
            placeholder="🎮 Choisir une plateforme ou un jeu…",
            options=opts,
            custom_id="agu_pick_game",
        )
        sel.callback = self._on_pick_game

        items = [
            v2_title("➕ Ajouter un suivi"),
            v2_subtitle("Étape 1 : choisir la plateforme ou le jeu"),
            v2_divider(),
            v2_body(
                "Sélectionne dans la liste. Le bot suivra ensuite les mises à jour "
                "officielles de cette source (patch notes, dev updates) et les "
                "publiera dans le salon que tu choisiras à l'étape 2."
            ),
            v2_divider(),
            discord.ui.ActionRow(sel),
        ]

        if self.selected_game:
            meta = gameupdates2026.get_game_meta(self.selected_game)
            items.append(v2_divider())
            items.append(v2_body(f"✅ Sélectionné : {meta['emoji']} **{meta['name']}**"))
            chan_sel = discord.ui.ChannelSelect(
                channel_types=[discord.ChannelType.text, discord.ChannelType.news],
                placeholder="📍 Étape 2 : choisir le salon de publication…",
                min_values=1, max_values=1,
            )
            chan_sel.callback = self._on_pick_channel
            items.append(discord.ui.ActionRow(chan_sel))

        b_back = Button(label="◀️ Annuler", style=discord.ButtonStyle.secondary, custom_id="agu_back")
        b_back.callback = self._on_back
        items.append(discord.ui.ActionRow(b_back))

        self.add_item(v2_container(*items, color=Palette.INFO))

    async def render_to(self, interaction, *, edit=True):
        if edit:
            await interaction.response.edit_message(view=self, embed=None, attachments=[])
        else:
            await interaction.response.send_message(view=self, ephemeral=True)

    async def _on_pick_game(self, i):
        try:
            self.selected_game = i.data.get('values', [None])[0]
            self._build()
            await i.response.edit_message(view=self, embed=None, attachments=[])
        except Exception as ex:
            print(f"[AddGameUpdateView _on_pick_game] {ex}")
            try:
                if not i.response.is_done():
                    await i.response.send_message(f"❌ Erreur : `{ex}`", ephemeral=True)
            except Exception:
                pass

    async def _on_pick_channel(self, i):
        try:
            channel_id = int(i.data.get('values', ['0'])[0])
            if not self.selected_game or not channel_id:
                return await i.response.send_message("❌ Sélection incomplète.", ephemeral=True)
            c = await cfg(self.g.id)
            feeds = c.get('ads_updates_feeds', []) or []
            # Évite les doublons (même game_key + même channel)
            for f in feeds:
                if isinstance(f, dict) and f.get('game_key') == self.selected_game and f.get('channel_id') == channel_id:
                    return await i.response.send_message(
                        "⚠️ Ce suivi existe déjà.", ephemeral=True,
                    )
            feeds.append({'game_key': self.selected_game, 'channel_id': channel_id})
            await db_set(self.g.id, 'ads_updates_feeds', feeds)
            meta = gameupdates2026.get_game_meta(self.selected_game)
            ch = self.g.get_channel(channel_id)
            await i.response.send_message(
                f"✅ Suivi ajouté : {meta['emoji']} **{meta['name']}** → {ch.mention if ch else 'salon ?'}\n"
                "Les prochaines mises à jour officielles seront postées automatiquement.",
                ephemeral=True,
            )
            # Re-render le panel
            try:
                v = AdsGameUpdatesPanelV2(self.u, self.g)
                await i.edit_original_response(view=v)
            except Exception:
                pass
        except Exception as ex:
            print(f"[AddGameUpdateView _on_pick_channel] {ex}")
            try:
                if not i.response.is_done():
                    await i.response.send_message(f"❌ Erreur : `{ex}`", ephemeral=True)
            except Exception:
                pass

    async def _on_back(self, i):
        try:
            v = AdsGameUpdatesPanelV2(self.u, self.g)
            await v.render_to(i, edit=True)
        except Exception as ex:
            print(f"[AddGameUpdateView _on_back] {ex}")


class AdsDealsPanel(View):
    def __init__(self, u, g):
        super().__init__(timeout=600)
        self.u = u
        self.g = g
    
    async def embed(self):
        c = await cfg(self.g.id)
        e = discord.Embed(color=0xFF6B35)
        e.set_author(name="━━━  Réductions de Jeux Vidéo  ━━━", icon_url=self.g.icon.url if self.g.icon else None)
        
        deals_ch = self.g.get_channel(c.get('ads_deals_channel', 0))
        deals_enabled = c.get('ads_deals_enabled', False)
        deals_min_discount = c.get('ads_deals_min_discount', 50)
        
        # Compter les deals actifs en DB
        active_deals = 0
        try:
            async with get_db() as db:
                async with db.execute('SELECT COUNT(*) FROM posted_deals WHERE guild_id=? AND expired=0', (self.g.id,)) as cur:
                    row = await cur.fetchone()
                    active_deals = row[0] if row else 0
        except:
            pass
        
        desc = "Recevez automatiquement les meilleures promotions !\n"
        desc += "Chaque jeu n'est publié **qu'une seule fois** et supprimé quand la promo expire.\n\n"
        desc += "─────────────────────────────────\n"
        desc += "🎮 **Steam** • **Epic Games** • **GOG**\n"
        desc += "🔵 **Ubisoft** • **EA/Origin** • **Battle.net**\n"
        desc += "🔑 **Humble** • **Fanatical** • **Green Man Gaming** • ...\n"
        desc += "─────────────────────────────────"
        e.description = desc
        
        status_emoji = "✅" if deals_enabled else "❌"
        e.add_field(name="📊 Statut", value=f"{status_emoji} {'Activé' if deals_enabled else 'Désactivé'}", inline=True)
        e.add_field(name="📍 Salon", value=deals_ch.mention if deals_ch else "❌ Non configuré", inline=True)
        e.add_field(name="🔻 Minimum", value=f"**-{deals_min_discount}%**", inline=True)
        e.add_field(name="📦 Deals actifs", value=f"**{active_deals}** jeu(x) en promo", inline=True)
        
        e.set_footer(text="🔄 Vérification toutes les 30 min  •  Anti-doublon en base de données")
        return e
    
    @discord.ui.button(label="📍 Salon", style=discord.ButtonStyle.primary, row=0)
    async def set_channel(self, i, b):
        v = PaginatedAdsChannelSelect(self.u, self.g, 'ads_deals_channel', 'deals')
        await i.response.edit_message(
            embed=discord.Embed(
                title="📍 Salon des Réductions",
                description="Où publier les promotions de jeux",
                color=0xFF6B35
            ),
            view=v
        )
    
    @discord.ui.button(label="✅ Activer", style=discord.ButtonStyle.success, row=0)
    async def enable(self, i, b):
        c = await cfg(self.g.id)
        if not c.get('ads_deals_channel'):
            return await i.response.send_message("❌ Configurez d'abord un salon!", ephemeral=True)
        await db_set(self.g.id, 'ads_deals_enabled', True)
        v = AdsDealsPanel(self.u, self.g)
        await i.response.edit_message(content="✅ Réductions activées!", embed=await v.embed(), view=v)
    
    @discord.ui.button(label="❌ Désactiver", style=discord.ButtonStyle.danger, row=0)
    async def disable(self, i, b):
        await db_set(self.g.id, 'ads_deals_enabled', False)
        v = AdsDealsPanel(self.u, self.g)
        await i.response.edit_message(content="❌ Réductions désactivées", embed=await v.embed(), view=v)
    
    @discord.ui.button(label="🔻 Réduction min", style=discord.ButtonStyle.secondary, row=1)
    async def set_min_discount(self, i, b):
        await i.response.send_modal(AdsDealsMinDiscountModal(self.g, self.u))
    
    @discord.ui.button(label="◀️ Retour", style=discord.ButtonStyle.secondary, row=1)
    async def back(self, i, b):
        v = AdsPanel(self.u, self.g)
        await i.response.edit_message(embed=await v.embed(), view=v)

class AdsDealsMinDiscountModal(Modal, title="🔻 Réduction Minimum"):
    discount = TextInput(label="Pourcentage minimum (ex: 50)", placeholder="50", default="50", max_length=3)
    
    def __init__(self, g, u):
        super().__init__()
        self.g = g
        self.u = u
    
    async def on_submit(self, i):
        try:
            value = int(self.discount.value)
            value = max(10, min(90, value))  # Entre 10% et 90%
            await db_set(self.g.id, 'ads_deals_min_discount', value)
            
            v = AdsDealsPanel(self.u, self.g)
            await i.response.edit_message(content=f"✅ Réduction minimum: **{value}%**", embed=await v.embed(), view=v)
        except:
            await i.response.send_message("❌ Entrez un nombre valide (10-90)", ephemeral=True)

# ─────────────────────────────── COMMON VIEWS ───────────────────────────────

class V2GenericChannelPicker(LayoutView):
    """Selecteur de salon V2 generique (Phase 3.0k).

    Utilisable depuis n'importe quel panel V2. Stocke le channel_id selectionne
    dans la config via la cle, puis retourne au panel parent (factory callable).

    Aucune transition V2->V1 (qui plantait en discord.py 2.7+).

    Usage:
        v = V2GenericChannelPicker(
            self.u, self.g,
            config_key='mod_logs_channel',
            return_panel_factory=lambda: ModerationPanelV2(self.u, self.g),
            title="📋 Salon des logs",
            description="Salon ou seront envoyes les logs.",
            color=0x9B59B6,
        )
        await v.render_to(i, edit=True)
    """

    def __init__(self, u, g, *, config_key: str = None, return_panel_factory,
                 title: str = "Choisir un salon",
                 description: str = "Selectionne un salon.",
                 color: int = 0x5865F2,
                 channel_types=None,
                 sub_dict_key: str = None,
                 save_fn=None):
        """sub_dict_key : si la cle est imbriquee (ex: 'level_config' avec sous-cle
        'announce_channel'), on stocke {sub_dict_key: {config_key: id}}.
        save_fn : async callable(guild_id, channel_id) optionnel pour cas custom
        (ex: save dans une nested dict, ou fait autre chose).
        """
        super().__init__(timeout=300)
        self.u = u
        self.g = g
        self.config_key = config_key
        self.return_panel_factory = return_panel_factory
        self.title = title
        self.description = description
        self.color = color
        self.channel_types = channel_types or [discord.ChannelType.text, discord.ChannelType.news]
        self.sub_dict_key = sub_dict_key
        self.save_fn = save_fn
        self._build()

    async def interaction_check(self, i):
        return i.user.id == self.u.id

    async def _save(self, channel_id: int):
        if self.save_fn is not None:
            await self.save_fn(self.g.id, channel_id)
        elif self.sub_dict_key:
            c = await cfg(self.g.id)
            sub = c.get(self.sub_dict_key, {}) or {}
            if not isinstance(sub, dict):
                sub = {}
            sub[self.config_key] = channel_id
            await db_set(self.g.id, self.sub_dict_key, sub)
        else:
            await db_set(self.g.id, self.config_key, channel_id)

    async def _return_to_parent(self, i: discord.Interaction):
        v = self.return_panel_factory()
        if hasattr(v, 'render_to'):
            await v.render_to(i, edit=True)
        elif hasattr(v, 'embed'):
            emb = await v.embed() if asyncio.iscoroutinefunction(v.embed) else v.embed()
            await i.response.edit_message(embed=emb, view=v, attachments=[])
        else:
            await i.response.edit_message(view=v, attachments=[])

    def _build(self):
        self.clear_items()

        sel = discord.ui.ChannelSelect(
            channel_types=self.channel_types,
            placeholder="📁 Choisir un salon...",
            min_values=1, max_values=1,
        )

        async def _on_select(i):
            try:
                ch = sel.values[0]
                channel_id = ch.id
                await self._save(channel_id)
                await self._return_to_parent(i)
                try:
                    await i.followup.send(f"✅ Salon défini : <#{channel_id}>", ephemeral=True)
                except Exception:
                    pass
            except Exception as ex:
                import traceback; traceback.print_exc()
                try:
                    await i.response.send_message(f"❌ Erreur : {ex}", ephemeral=True)
                except Exception:
                    pass
        sel.callback = _on_select

        b_none = Button(label="❌ Aucun (reset)", style=discord.ButtonStyle.secondary)
        async def _none(i):
            try:
                await self._save(0)
                await self._return_to_parent(i)
            except Exception as ex:
                import traceback; traceback.print_exc()
                try:
                    await i.response.send_message(f"❌ Erreur : {ex}", ephemeral=True)
                except Exception:
                    pass
        b_none.callback = _none

        b_back = Button(label="◀️ Retour", style=discord.ButtonStyle.danger)
        async def _back(i):
            try:
                await self._return_to_parent(i)
            except Exception as ex:
                import traceback; traceback.print_exc()
                try:
                    await i.response.send_message(f"❌ Erreur : {ex}", ephemeral=True)
                except Exception:
                    pass
        b_back.callback = _back

        items = [
            v2_title(self.title),
            v2_subtitle(self.description),
            v2_divider(),
            v2_subtitle(f"📂 {len(self.g.text_channels)} salons disponibles · scroll dans le menu"),
            v2_divider(),
            discord.ui.ActionRow(sel),
            discord.ui.ActionRow(b_none, b_back),
        ]
        self.add_item(v2_container(*items, color=discord.Color(self.color)))

    async def render_to(self, interaction, *, edit=True):
        if edit:
            await interaction.response.edit_message(view=self, embed=None, attachments=[])
        else:
            await interaction.response.send_message(view=self, ephemeral=True)


class V2GenericMultiChannelPicker(LayoutView):
    """Selecteur multi-salons V2 (Phase 4.5).

    Stocke une liste d'IDs de salons dans la config (clé directe ou sous-clé).
    Sélection vide acceptée = "tous les salons".
    """

    def __init__(self, u, g, *, config_key: str, return_panel_factory,
                 title: str = "Choisir des salons",
                 description: str = "Sélectionne les salons (vide = tous).",
                 color: int = 0x5865F2,
                 channel_types=None,
                 sub_dict_key: str = None,
                 max_values: int = 25):
        super().__init__(timeout=300)
        self.u = u
        self.g = g
        self.config_key = config_key
        self.return_panel_factory = return_panel_factory
        self.title = title
        self.description = description
        self.color = color
        self.channel_types = channel_types or [discord.ChannelType.text, discord.ChannelType.news]
        self.sub_dict_key = sub_dict_key
        self.max_values = min(25, max_values)
        self._build()

    async def interaction_check(self, i):
        return i.user.id == self.u.id

    async def _save(self, channel_ids: list[int]):
        if self.sub_dict_key:
            c = await cfg(self.g.id)
            sub = c.get(self.sub_dict_key, {}) or {}
            if not isinstance(sub, dict):
                sub = {}
            sub[self.config_key] = channel_ids
            await db_set(self.g.id, self.sub_dict_key, sub)
        else:
            await db_set(self.g.id, self.config_key, channel_ids)

    async def _return_to_parent(self, i: discord.Interaction):
        v = self.return_panel_factory()
        if hasattr(v, 'render_to'):
            await v.render_to(i, edit=True)
        elif hasattr(v, 'embed'):
            emb = await v.embed() if asyncio.iscoroutinefunction(v.embed) else v.embed()
            await i.response.edit_message(embed=emb, view=v, attachments=[])
        else:
            await i.response.edit_message(view=v, attachments=[])

    def _build(self):
        self.clear_items()
        sel = discord.ui.ChannelSelect(
            channel_types=self.channel_types,
            placeholder="📁 Sélectionne les salons (multi)...",
            min_values=0,
            max_values=self.max_values,
        )
        sel.callback = self._on_select

        b_clear = Button(label="🧹 Tout effacer", style=discord.ButtonStyle.danger, custom_id="v2mcp_clear")
        b_clear.callback = self._cb_clear
        b_back = Button(label="◀️ Annuler", style=discord.ButtonStyle.secondary, custom_id="v2mcp_back")
        b_back.callback = self._cb_back

        items = [
            v2_title(self.title),
            v2_subtitle(self.description),
            v2_divider(),
            v2_subtitle("Tu peux sélectionner plusieurs salons en une seule fois."),
            discord.ui.ActionRow(sel),
            discord.ui.ActionRow(b_clear, b_back),
        ]
        self.add_item(v2_container(*items, color=discord.Color(self.color)))

    async def render_to(self, interaction: discord.Interaction, *, edit: bool = True):
        if edit:
            await interaction.response.edit_message(view=self, embed=None, attachments=[])
        else:
            await interaction.response.send_message(view=self, ephemeral=True)

    async def _on_select(self, i):
        try:
            channel_ids = [int(c.id) for c in i.data.get('resolved', {}).get('channels', {}).values()] if False else []
            # discord.py expose les valeurs via i.data['values'] (liste d'IDs en str)
            raw_values = i.data.get('values', [])
            channel_ids = [int(v) for v in raw_values]
            await self._save(channel_ids)
            await self._return_to_parent(i)
        except Exception as ex:
            print(f"[V2GenericMultiChannelPicker] {ex}")
            try:
                if not i.response.is_done():
                    await i.response.send_message(f"❌ Erreur : `{ex}`", ephemeral=True)
            except Exception:
                pass

    async def _cb_clear(self, i):
        try:
            await self._save([])
            await self._return_to_parent(i)
        except Exception as ex:
            print(f"[V2GenericMultiChannelPicker clear] {ex}")
            try:
                if not i.response.is_done():
                    await i.response.defer()
            except Exception:
                pass

    async def _cb_back(self, i):
        await self._return_to_parent(i)


class V2GenericRolePicker(LayoutView):
    """Selecteur de role V2 generique (Phase 3.0k).

    Equivalent de V2GenericChannelPicker mais pour les roles.
    """

    def __init__(self, u, g, *, config_key: str = None, return_panel_factory,
                 title: str = "Choisir un rôle",
                 description: str = "Selectionne un rôle.",
                 color: int = 0x5865F2,
                 sub_dict_key: str = None,
                 save_fn=None):
        """save_fn : async callable(guild_id, role_id) optionnel pour cas custom."""
        super().__init__(timeout=300)
        self.u = u
        self.g = g
        self.config_key = config_key
        self.return_panel_factory = return_panel_factory
        self.title = title
        self.description = description
        self.color = color
        self.sub_dict_key = sub_dict_key
        self.save_fn = save_fn
        self._build()

    async def interaction_check(self, i):
        return i.user.id == self.u.id

    async def _save(self, role_id: int):
        if self.save_fn is not None:
            await self.save_fn(self.g.id, role_id)
        elif self.sub_dict_key:
            c = await cfg(self.g.id)
            sub = c.get(self.sub_dict_key, {}) or {}
            if not isinstance(sub, dict):
                sub = {}
            sub[self.config_key] = role_id
            await db_set(self.g.id, self.sub_dict_key, sub)
        else:
            await db_set(self.g.id, self.config_key, role_id)

    async def _return_to_parent(self, i: discord.Interaction):
        v = self.return_panel_factory()
        if hasattr(v, 'render_to'):
            await v.render_to(i, edit=True)
        elif hasattr(v, 'embed'):
            emb = await v.embed() if asyncio.iscoroutinefunction(v.embed) else v.embed()
            await i.response.edit_message(embed=emb, view=v, attachments=[])
        else:
            await i.response.edit_message(view=v, attachments=[])

    def _build(self):
        self.clear_items()

        sel = discord.ui.RoleSelect(
            placeholder="🎭 Choisir un rôle...",
            min_values=1, max_values=1,
        )

        async def _on_select(i):
            try:
                role = sel.values[0]
                await self._save(role.id)
                await self._return_to_parent(i)
                try:
                    await i.followup.send(f"✅ Rôle défini : {role.mention}", ephemeral=True)
                except Exception:
                    pass
            except Exception as ex:
                import traceback; traceback.print_exc()
                try:
                    await i.response.send_message(f"❌ Erreur : {ex}", ephemeral=True)
                except Exception:
                    pass
        sel.callback = _on_select

        b_none = Button(label="❌ Aucun (reset)", style=discord.ButtonStyle.secondary)
        async def _none(i):
            try:
                await self._save(0)
                await self._return_to_parent(i)
            except Exception as ex:
                import traceback; traceback.print_exc()
                try:
                    await i.response.send_message(f"❌ Erreur : {ex}", ephemeral=True)
                except Exception:
                    pass
        b_none.callback = _none

        b_back = Button(label="◀️ Retour", style=discord.ButtonStyle.danger)
        async def _back(i):
            try:
                await self._return_to_parent(i)
            except Exception as ex:
                import traceback; traceback.print_exc()
                try:
                    await i.response.send_message(f"❌ Erreur : {ex}", ephemeral=True)
                except Exception:
                    pass
        b_back.callback = _back

        items = [
            v2_title(self.title),
            v2_subtitle(self.description),
            v2_divider(),
            v2_subtitle(f"🎭 {len([r for r in self.g.roles if not r.is_bot_managed()])} rôles disponibles"),
            v2_divider(),
            discord.ui.ActionRow(sel),
            discord.ui.ActionRow(b_none, b_back),
        ]
        self.add_item(v2_container(*items, color=discord.Color(self.color)))

    async def render_to(self, interaction, *, edit=True):
        if edit:
            await interaction.response.edit_message(view=self, embed=None, attachments=[])
        else:
            await interaction.response.send_message(view=self, ephemeral=True)


class V2AdsChannelPicker(LayoutView):
    """Selecteur de salon V2 natif (Phase 3.0j).

    Utilise discord.ui.ChannelSelect qui est V2-compatible et evite la
    transition V2 LayoutView -> V1 View+embed qui plantait en discord.py 2.7.
    """

    def __init__(self, u, g, config_key: str, platform: str, *,
                 title: str = "Choisir un salon",
                 description: str = "Selectionne un salon pour les publications.",
                 color: int = 0x5865F2,
                 channel_types=None):
        super().__init__(timeout=300)
        self.u = u
        self.g = g
        self.config_key = config_key
        self.platform = platform
        self.title = title
        self.description = description
        self.color = color
        self.channel_types = channel_types or [discord.ChannelType.text, discord.ChannelType.news]
        self._build()

    async def interaction_check(self, i):
        return i.user.id == self.u.id

    def _build(self):
        self.clear_items()

        # ChannelSelect V2 natif - pas de pagination car Discord-side
        sel = discord.ui.ChannelSelect(
            channel_types=self.channel_types,
            placeholder="📁 Choisir un salon...",
            min_values=1,
            max_values=1,
        )
        async def _on_select(i):
            try:
                ch = sel.values[0]
                # Resoud channel_id
                channel_id = ch.id if hasattr(ch, 'id') else int(ch)
                await db_set(i.guild.id, self.config_key, channel_id)
                # Retour au panel parent
                v = self._get_return_panel()
                if hasattr(v, 'render_to'):
                    await v.render_to(i, edit=True)
                    try:
                        await i.followup.send(
                            f"✅ Salon défini : <#{channel_id}>",
                            ephemeral=True,
                        )
                    except Exception:
                        pass
                else:
                    await i.response.edit_message(
                        content=f"✅ Salon défini : <#{channel_id}>",
                        embed=await v.embed(),
                        view=v,
                        attachments=[],
                    )
            except Exception as ex:
                import traceback
                traceback.print_exc()
                try:
                    await i.response.send_message(f"❌ Erreur : {ex}", ephemeral=True)
                except Exception:
                    pass
        sel.callback = _on_select

        # Bouton "Aucun" pour reset le salon
        b_none = Button(label="❌ Aucun (reset)", style=discord.ButtonStyle.secondary)
        async def _none(i):
            try:
                await db_set(i.guild.id, self.config_key, 0)
                v = self._get_return_panel()
                if hasattr(v, 'render_to'):
                    await v.render_to(i, edit=True)
                else:
                    await i.response.edit_message(embed=await v.embed(), view=v, attachments=[])
            except Exception as ex:
                import traceback
                traceback.print_exc()
                try:
                    await i.response.send_message(f"❌ Erreur : {ex}", ephemeral=True)
                except Exception:
                    pass
        b_none.callback = _none

        # Bouton retour
        b_back = Button(label="◀️ Retour", style=discord.ButtonStyle.danger)
        async def _back(i):
            try:
                v = self._get_return_panel()
                if hasattr(v, 'render_to'):
                    await v.render_to(i, edit=True)
                else:
                    await i.response.edit_message(embed=await v.embed(), view=v, attachments=[])
            except Exception as ex:
                import traceback
                traceback.print_exc()
                try:
                    await i.response.send_message(f"❌ Erreur : {ex}", ephemeral=True)
                except Exception:
                    pass
        b_back.callback = _back

        items = [
            v2_title(self.title),
            v2_subtitle(self.description),
            v2_divider(),
            v2_subtitle(f"📂 {len(self.g.text_channels)} salons textuels disponibles · scroll dans le menu pour chercher"),
            v2_divider(),
            discord.ui.ActionRow(sel),
            discord.ui.ActionRow(b_none, b_back),
        ]
        self.add_item(v2_container(*items, color=discord.Color(self.color)))

    def _get_return_panel(self):
        # Meme dispatch que PaginatedAdsChannelSelect
        if self.platform == 'youtube':
            return AdsLivePlatformV2(self.u, self.g, 'youtube')
        elif self.platform == 'twitch':
            return AdsLivePlatformV2(self.u, self.g, 'twitch')
        elif self.platform == 'tiktok':
            return AdsLivePlatformV2(self.u, self.g, 'tiktok')
        elif self.platform == 'twitter':
            return AdsSimplePlatformV2(self.u, self.g, 'twitter')
        elif self.platform == 'reddit':
            return AdsSimplePlatformV2(self.u, self.g, 'reddit')
        elif self.platform == 'discord':
            return AdsSimplePlatformV2(self.u, self.g, 'discord')
        elif self.platform == 'rosocial':
            return AdsSimplePlatformV2(self.u, self.g, 'rosocial')
        elif self.platform == 'roblox':
            return AdsRobloxPanelV2(self.u, self.g)
        elif self.platform == 'deals':
            return AdsDealsPanelV2(self.u, self.g)
        else:
            return AdsPanelV2(self.u, self.g)

    async def render_to(self, interaction, *, edit=True):
        if edit:
            await interaction.response.edit_message(view=self, embed=None, attachments=[])
        else:
            await interaction.response.send_message(view=self, ephemeral=True)


class PaginatedAdsChannelSelect(View):
    """Sélecteur de salon paginé pour les Ads"""
    def __init__(self, u, g, key, platform, page=0):
        super().__init__(timeout=180)
        self.u = u
        self.g = g
        self.key = key
        self.platform = platform
        self.page = page
        self.channels = list(g.text_channels)
        self.max_page = max(0, (len(self.channels) - 1) // 24)
        self._build()
    
    def _get_return_panel(self):
        # Tous les V2 (Phase 3.0c)
        if self.platform == 'youtube':
            return AdsLivePlatformV2(self.u, self.g, 'youtube')
        elif self.platform == 'twitch':
            return AdsLivePlatformV2(self.u, self.g, 'twitch')
        elif self.platform == 'tiktok':
            return AdsLivePlatformV2(self.u, self.g, 'tiktok')
        elif self.platform == 'twitter':
            return AdsSimplePlatformV2(self.u, self.g, 'twitter')
        elif self.platform == 'reddit':
            return AdsSimplePlatformV2(self.u, self.g, 'reddit')
        elif self.platform == 'discord':
            return AdsSimplePlatformV2(self.u, self.g, 'discord')
        elif self.platform == 'rosocial':
            return AdsSimplePlatformV2(self.u, self.g, 'rosocial')
        elif self.platform == 'roblox':
            return AdsRobloxPanelV2(self.u, self.g)
        elif self.platform == 'deals':
            return AdsDealsPanelV2(self.u, self.g)
        else:
            # Fallback safe : retour au master panel
            return AdsPanelV2(self.u, self.g)
    
    def _build(self):
        self.clear_items()
        
        start = self.page * 24
        end = start + 24
        page_channels = self.channels[start:end]
        
        opts = []
        for ch in page_channels:
            desc = ch.category.name[:50] if ch.category else "Sans catégorie"
            opts.append(discord.SelectOption(
                label=f"# {ch.name}"[:25],
                value=str(ch.id),
                description=desc
            ))
        
        if opts:
            select = PaginatedAdsChannelMenu(self, opts)
            self.add_item(select)
        
        # Navigation
        if self.max_page > 0:
            prev_btn = discord.ui.Button(label="◀️", style=discord.ButtonStyle.primary, disabled=(self.page == 0), row=1)
            prev_btn.callback = self.prev_page
            self.add_item(prev_btn)
            
            page_btn = discord.ui.Button(label=f"{self.page + 1}/{self.max_page + 1}", style=discord.ButtonStyle.secondary, disabled=True, row=1)
            self.add_item(page_btn)
            
            next_btn = discord.ui.Button(label="▶️", style=discord.ButtonStyle.primary, disabled=(self.page >= self.max_page), row=1)
            next_btn.callback = self.next_page
            self.add_item(next_btn)
        
        back_btn = discord.ui.Button(label="◀️ Retour", style=discord.ButtonStyle.danger, row=2)
        back_btn.callback = self.go_back
        self.add_item(back_btn)
    
    async def prev_page(self, i):
        self.page -= 1
        self._build()
        await i.response.edit_message(view=self)
    
    async def next_page(self, i):
        self.page += 1
        self._build()
        await i.response.edit_message(view=self)
    
    async def go_back(self, i):
        v = self._get_return_panel()
        # V2-aware : si le panneau cible a render_to, on est en V2
        if hasattr(v, 'render_to'):
            await v.render_to(i, edit=True)
        else:
            await i.response.edit_message(embed=await v.embed(), view=v, attachments=[])

class PaginatedAdsChannelMenu(Select):
    def __init__(self, parent, opts):
        super().__init__(placeholder=f"Page {parent.page + 1}/{parent.max_page + 1} - Choisir un salon...", options=opts)
        self.parent_view = parent

    async def callback(self, i):
        await db_set(i.guild.id, self.parent_view.key, int(self.values[0]))
        ch = i.guild.get_channel(int(self.values[0]))
        v = self.parent_view._get_return_panel()
        # V2-aware : panneau V2 → render_to + followup confirmation
        if hasattr(v, 'render_to'):
            await v.render_to(i, edit=True)
            try:
                await i.followup.send(
                    f"✅ Salon défini: **{ch.mention if ch else 'Aucun'}**",
                    ephemeral=True,
                )
            except Exception:
                pass
        else:
            await i.response.edit_message(
                content=f"✅ Salon défini: **{ch.mention if ch else 'Aucun'}**",
                embed=await v.embed(), view=v, attachments=[]
            )

class AdsFeedChannelPaginatedView(View):
    """Sélecteur de salon paginé pour ajouter un feed (YouTube, Twitch, TikTok, etc.)
    Supporte TOUS les salons du serveur avec pagination."""
    def __init__(self, u, g, feed_data, feeds_config_key, page=0):
        super().__init__(timeout=180)
        self.u = u
        self.g = g
        self.feed_data = feed_data
        self.feeds_config_key = feeds_config_key  # ex: 'ads_youtube_feeds'
        self.page = page
        self.channels = list(g.text_channels)
        self.per_page = 23
        self.max_page = max(0, (len(self.channels) - 1) // self.per_page)
        self._build()

    def _build(self):
        self.clear_items()
        start = self.page * self.per_page
        end = start + self.per_page
        page_chs = self.channels[start:end]

        opts = []
        if self.page == 0:
            opts.append(discord.SelectOption(label="📍 Salon par défaut", value="0", description="Utiliser le salon par défaut configuré"))

        for ch in page_chs:
            desc = ch.category.name[:50] if ch.category else "Sans catégorie"
            opts.append(discord.SelectOption(label=f"# {ch.name}"[:25], value=str(ch.id), description=desc))

        if opts:
            select = AdsFeedChannelPaginatedSelect(self, opts)
            self.add_item(select)

        if self.max_page > 0:
            prev_btn = discord.ui.Button(label="◀️", style=discord.ButtonStyle.primary, disabled=(self.page == 0), row=1)
            prev_btn.callback = self._prev
            self.add_item(prev_btn)
            page_btn = discord.ui.Button(label=f"{self.page+1}/{self.max_page+1}", style=discord.ButtonStyle.secondary, disabled=True, row=1)
            self.add_item(page_btn)
            next_btn = discord.ui.Button(label="▶️", style=discord.ButtonStyle.primary, disabled=(self.page >= self.max_page), row=1)
            next_btn.callback = self._next
            self.add_item(next_btn)

    async def _prev(self, i):
        self.page -= 1
        self._build()
        await i.response.edit_message(view=self)

    async def _next(self, i):
        self.page += 1
        self._build()
        await i.response.edit_message(view=self)


class AdsFeedChannelPaginatedSelect(Select):
    def __init__(self, parent, opts):
        placeholder = f"Page {parent.page+1}/{parent.max_page+1} — Choisir un salon..."[:100]
        super().__init__(placeholder=placeholder, options=opts)
        self.parent_view = parent

    async def callback(self, i):
        channel_id = int(self.values[0])
        if channel_id > 0:
            self.parent_view.feed_data['channel_id'] = channel_id
        c = await cfg(self.parent_view.g.id)
        feeds = c.get(self.parent_view.feeds_config_key, [])
        feeds.append(self.parent_view.feed_data)
        await db_set(self.parent_view.g.id, self.parent_view.feeds_config_key, feeds)
        ch = self.parent_view.g.get_channel(channel_id) if channel_id else None
        salon_txt = ch.mention if ch else "salon par défaut"
        name = self.parent_view.feed_data.get('name') or self.parent_view.feed_data.get('username') or self.parent_view.feed_data.get('id', '?')
        await i.response.edit_message(content=f"✅ **{name}** ajouté ! Publications dans {salon_txt}", view=None)


