class AdsChannelSelect(Select):
    def __init__(self, u, g, opts, key, platform):
        super().__init__(placeholder="Choisir un salon...", options=opts)
        self.u = u
        self.g = g
        self.key = key
        self.platform = platform
    
    async def callback(self, i):
        await db_set(i.guild.id, self.key, int(self.values[0]))
        v = _get_ads_panel(self.platform, self.u, self.g)
        await i.response.edit_message(embed=await v.embed(), view=v)

def _get_ads_panel(platform, u, g):
    """Retourne le bon panel Ads selon la plateforme. Tous V2 (Phase 3.0c)."""
    if platform in ('youtube', 'twitch', 'tiktok'):
        return AdsLivePlatformV2(u, g, platform)
    if platform in ('twitter', 'reddit', 'discord', 'rosocial'):
        return AdsSimplePlatformV2(u, g, platform)
    if platform == 'roblox':
        return AdsRobloxPanelV2(u, g)
    if platform == 'deals':
        return AdsDealsPanelV2(u, g)
    # Fallback : master Ads
    return AdsPanelV2(u, g)

class AdsFeedRemoveView(View):
    def __init__(self, u, g, opts, key, platform):
        super().__init__(timeout=120)
        self.add_item(AdsFeedRemoveSelect(u, g, opts, key, platform))

class AdsFeedRemoveSelect(Select):
    def __init__(self, u, g, opts, key, platform):
        super().__init__(placeholder="Sélectionner à supprimer...", options=opts)
        self.u = u
        self.g = g
        self.key = key
        self.platform = platform
    
    async def callback(self, i):
        c = await cfg(self.g.id)
        feeds = c.get(self.key, [])
        idx = int(self.values[0])
        removed_label = None
        if 0 <= idx < len(feeds):
            removed = feeds.pop(idx)
            await db_set(self.g.id, self.key, feeds)
            # Aussi nettoyer le tracking_layer si on supprime un compte tracke
            try:
                if isinstance(removed, dict):
                    uname = removed.get('username') or removed.get('group_name') or removed.get('user_id') or removed.get('group_id')
                    if uname:
                        removed_label = str(uname)
            except Exception:
                pass

        v = _get_ads_panel(self.platform, self.u, self.g)
        # V2-aware navigation
        if hasattr(v, 'render_to'):
            await v.render_to(i, edit=True)
            try:
                await i.followup.send(
                    f"✅ {removed_label or 'Élément'} supprimé.",
                    ephemeral=True,
                )
            except Exception:
                pass
        else:
            await i.response.edit_message(embed=await v.embed(), view=v, attachments=[])

