def format_duration(seconds):
    """Formate une durée en texte lisible"""
    if seconds < 60:
        return f"{seconds}s"
    elif seconds < 3600:
        return f"{seconds // 60}min"
    elif seconds < 86400:
        hours = seconds // 3600
        mins = (seconds % 3600) // 60
        return f"{hours}h{mins}min" if mins else f"{hours}h"
    else:
        days = seconds // 86400
        hours = (seconds % 86400) // 3600
        return f"{days}j{hours}h" if hours else f"{days}j"

# Sélecteur de salons générique avec callback personnalisé
class PaginatedChannelSelectGeneric(View):
    def __init__(self, u, g, config_key, current_channels, return_panel_class, page=0):
        super().__init__(timeout=180)
        self.u = u
        self.g = g
        self.config_key = config_key
        self.current_channels = list(current_channels) if current_channels else []
        self.return_panel_class = return_panel_class
        self.page = page
        self.channels = list(g.text_channels)
        self.per_page = 23
        self.max_page = max(0, (len(self.channels) - 1) // self.per_page)
        self._build()
    
    def _build(self):
        self.clear_items()
        start = self.page * self.per_page
        end = start + self.per_page
        page_chs = self.channels[start:end]
        
        opts = []
        if self.page == 0:
            opts.append(discord.SelectOption(label="✅ Sauvegarder", value="save", emoji="💾"))
        
        for ch in page_chs:
            is_selected = ch.id in self.current_channels
            opts.append(discord.SelectOption(
                label=f"# {ch.name}"[:25], 
                value=str(ch.id),
                default=is_selected,
                emoji="✅" if is_selected else "⬜"
            ))
        
        if opts:
            select = Select(placeholder=f"Page {self.page+1}/{self.max_page+1}", options=opts, max_values=min(len(opts), 25))
            select.callback = self.select_callback
            self.add_item(select)
        
        if self.page > 0:
            btn = discord.ui.Button(label="◀️", style=discord.ButtonStyle.secondary, row=1)
            btn.callback = self.prev_page
            self.add_item(btn)
        
        if self.page < self.max_page:
            btn = discord.ui.Button(label="▶️", style=discord.ButtonStyle.secondary, row=1)
            btn.callback = self.next_page
            self.add_item(btn)
        
        back_btn = discord.ui.Button(label="◀️ Retour", style=discord.ButtonStyle.danger, row=1)
        back_btn.callback = self.go_back
        self.add_item(back_btn)
    
    async def select_callback(self, i):
        values = i.data['values']
        
        if 'save' in values:
            # Sauvegarder
            c = await cfg(self.g.id)
            level_cfg = c.get('level_config', {})
            level_cfg['allowed_channels'] = self.current_channels
            await db_set(self.g.id, 'level_config', level_cfg)
            v = self.return_panel_class(self.u, self.g)
            await i.response.edit_message(embed=await v.embed(), view=v)
            return
        
        for val in values:
            if val == 'save':
                continue
            ch_id = int(val)
            if ch_id in self.current_channels:
                self.current_channels.remove(ch_id)
            else:
                self.current_channels.append(ch_id)
        
        v = PaginatedChannelSelectGeneric(self.u, self.g, self.config_key, self.current_channels, self.return_panel_class, self.page)
        await i.response.edit_message(view=v)
    
    async def prev_page(self, i):
        v = PaginatedChannelSelectGeneric(self.u, self.g, self.config_key, self.current_channels, self.return_panel_class, self.page - 1)
        await i.response.edit_message(view=v)
    
    async def next_page(self, i):
        v = PaginatedChannelSelectGeneric(self.u, self.g, self.config_key, self.current_channels, self.return_panel_class, self.page + 1)
        await i.response.edit_message(view=v)
    
    async def go_back(self, i):
        v = self.return_panel_class(self.u, self.g)
        # V2-aware navigation (Phase 3.0d)
        if hasattr(v, 'render_to'):
            await v.render_to(i, edit=True)
        else:
            await i.response.edit_message(embed=await v.embed(), view=v, attachments=[])

# ═══════════════════════════════════════════════════════════════════════════════
#                           🔊 VOCAUX TEMPORAIRES
# ═══════════════════════════════════════════════════════════════════════════════

# Cache des vocaux temporaires : {channel_id: {'owner': user_id, 'created_at': datetime}}
temp_voice_channels = {}

class TempVoicePanel(View):
    def __init__(self, u, g):
        super().__init__(timeout=600)
        self.u = u
        self.g = g
    
    async def embed(self):
        c = await cfg(self.g.id)
        voice_cfg = c.get('temp_voice_config', {})
        hubs = voice_cfg.get('hubs', {})  # Nouveau format multi-hubs
        
        enabled = voice_cfg.get('enabled', False)
        e = discord.Embed(color=0x9B59B6)
        e.set_author(name="🔊 Vocaux Temporaires", icon_url=self.g.icon.url if self.g.icon else None)
        
        status_icon = "🟢" if enabled else "🔴"
        e.description = (
            f"{status_icon} **{'Système actif' if enabled else 'Système désactivé'}**\n"
            f"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n"
            f"✅ Détection vocale • ✅ Stream\n"
            f"❌ Écriture bloquée • 🗑️ Auto-delete si vide\n"
            f"🔒 Restriction par rôle disponible"
        )
        
        # État
        enabled = voice_cfg.get('enabled', False)
        e.add_field(name="État", value="✅ Activé" if enabled else "❌ Désactivé", inline=True)
        
        # Nombre de hubs configurés
        active_hubs = len([h for h_id, h in hubs.items() if self.g.get_channel(int(h_id))])
        e.add_field(name="🎤 Hubs configurés", value=str(active_hubs), inline=True)
        
        # Vocaux actifs
        active_count = len([ch for ch in temp_voice_channels.keys() if self.g.get_channel(ch)])
        e.add_field(name="📊 Vocaux actifs", value=str(active_count), inline=True)
        
        # Liste des hubs
        if hubs:
            hub_list = []
            for hub_id, hub_data in list(hubs.items())[:5]:  # Max 5 affichés
                hub_ch = self.g.get_channel(int(hub_id))
                if hub_ch:
                    role_id = hub_data.get('required_role', 0)
                    role = self.g.get_role(role_id) if role_id else None
                    if role:
                        role_txt = f"🔒 {role.name} (privé)"
                    else:
                        role_txt = "🔓 Public"
                    cat = self.g.get_channel(hub_data.get('category', 0))
                    cat_txt = cat.name if cat else "Non défini"
                    hub_list.append(f"🎤 **{hub_ch.name}**\n┗ {role_txt} • 📁 {cat_txt}")
            
            if len(hubs) > 5:
                hub_list.append(f"*... et {len(hubs) - 5} autres*")
            
            e.add_field(name="📋 Hubs configurés", value="\n".join(hub_list) if hub_list else "*Aucun*", inline=False)
        else:
            e.add_field(name="📋 Hubs configurés", value="*Aucun hub configuré*\nCliquez sur '➕ Ajouter Hub' pour commencer", inline=False)
        
        # Permissions du propriétaire
        perms = voice_cfg.get('owner_permissions', {})
        perm_list = []
        if perms.get('can_rename', True):
            perm_list.append("✏️ Renommer")
        if perms.get('can_limit', True):
            perm_list.append("🔢 Limite")
        if perms.get('can_mute', True):
            perm_list.append("🔇 Mute")
        if perms.get('can_kick', True):
            perm_list.append("👢 Expulser")
        
        e.add_field(name="👑 Permissions Propriétaire", value=" • ".join(perm_list) if perm_list else "*Aucune*", inline=False)
        
        e.set_footer(text="💡 Chaque hub peut avoir un rôle requis différent")
        return e
    
    @discord.ui.button(label="✅ Activer/Désactiver", style=discord.ButtonStyle.success, row=0)
    async def toggle(self, i, b):
        c = await cfg(self.g.id)
        voice_cfg = c.get('temp_voice_config', {})
        voice_cfg['enabled'] = not voice_cfg.get('enabled', False)
        await db_set(self.g.id, 'temp_voice_config', voice_cfg)
        v = TempVoicePanelV2(self.u, self.g)
        await v.render_to(i, edit=True)
    
    @discord.ui.button(label="➕ Ajouter Hub", style=discord.ButtonStyle.primary, row=0)
    async def add_hub(self, i, b):
        v = TempVoiceAddHubSelect(self.u, self.g)
        await i.response.edit_message(
            embed=discord.Embed(
                title="➕ Ajouter un Hub Vocal",
                description="**Étape 1/3** - Choisissez le salon vocal qui servira de hub.\n\nQuand un membre rejoindra ce salon, un vocal personnel sera créé.",
                color=0x9B59B6
            ),
            view=v
        )
    
    @discord.ui.button(label="📋 Gérer Hubs", style=discord.ButtonStyle.primary, row=0)
    async def manage_hubs(self, i, b):
        c = await cfg(self.g.id)
        voice_cfg = c.get('temp_voice_config', {})
        hubs = voice_cfg.get('hubs', {})
        
        if not hubs:
            return await i.response.send_message("❌ Aucun hub configuré. Ajoutez d'abord un hub.", ephemeral=True)
        
        v = TempVoiceHubsListPanel(self.u, self.g)
        await i.response.edit_message(embed=await v.embed(), view=v)
    
    @discord.ui.button(label="👑 Permissions", style=discord.ButtonStyle.secondary, row=1)
    async def set_permissions(self, i, b):
        v = TempVoicePermissionsPanel(self.u, self.g)
        await i.response.edit_message(embed=await v.embed(), view=v)
    
    @discord.ui.button(label="◀️ Retour", style=discord.ButtonStyle.secondary, row=2)
    async def back(self, i, b):
        v = MainPanelV2(self.u, self.g)
        await v.render_to(i, edit=True)

class TempVoicePanelV2(LayoutView):
    """Panneau Vocaux Temporaires en V2."""

    def __init__(self, u, g):
        super().__init__(timeout=600)
        self.u = u
        self.g = g

    async def interaction_check(self, i):
        return i.user.id == self.u.id

    async def render_to(self, interaction: discord.Interaction, *, edit: bool = True):
        c = await cfg(self.g.id)
        voice_cfg = c.get('temp_voice_config', {})
        hubs = voice_cfg.get('hubs', {})
        enabled = voice_cfg.get('enabled', False)

        # Hubs valides + actifs
        active_hubs = len([h_id for h_id in hubs if self.g.get_channel(int(h_id))])
        try:
            active_count = len([ch for ch in temp_voice_channels.keys() if self.g.get_channel(ch)])
        except Exception:
            active_count = 0

        # Liste des hubs
        hub_lines = []
        if hubs:
            for hub_id, hub_data in list(hubs.items())[:5]:
                hub_ch = self.g.get_channel(int(hub_id))
                if hub_ch:
                    role_id = hub_data.get('required_role', 0)
                    role = self.g.get_role(role_id) if role_id else None
                    role_txt = f"🔒 {role.mention} _(privé)_" if role else "🔓 _Public_"
                    cat = self.g.get_channel(hub_data.get('category', 0))
                    cat_txt = cat.name if cat else "_Non défini_"
                    hub_lines.append(f"🎤 **{hub_ch.name}** · {role_txt} · 📁 `{cat_txt}`")
            if len(hubs) > 5:
                hub_lines.append(f"_… + {len(hubs) - 5} autres_")
        hubs_block = "\n".join(hub_lines) if hub_lines else "_Aucun hub configuré · ajoute-en un avec ➕_"

        # Permissions
        perms = voice_cfg.get('owner_permissions', {})
        perm_chips = []
        if perms.get('can_rename', True): perm_chips.append("✏️ Renommer")
        if perms.get('can_limit', True): perm_chips.append("🔢 Limite")
        if perms.get('can_mute', True): perm_chips.append("🔇 Mute")
        if perms.get('can_kick', True): perm_chips.append("👢 Expulser")
        perms_txt = " · ".join(perm_chips) if perm_chips else "_Aucune permission accordée au propriétaire_"

        # Boutons
        self.clear_items()
        b_toggle = Button(
            label=("⏸️ Désactiver" if enabled else "▶️ Activer"),
            style=(discord.ButtonStyle.danger if enabled else discord.ButtonStyle.success),
            custom_id="tvpv2_toggle",
        )
        b_toggle.callback = self._cb_toggle
        b_add = Button(label="➕ Ajouter Hub", style=discord.ButtonStyle.primary, custom_id="tvpv2_add")
        b_add.callback = self._cb_add
        b_manage = Button(label="📋 Gérer Hubs", style=discord.ButtonStyle.primary, disabled=(active_hubs == 0), custom_id="tvpv2_manage")
        b_manage.callback = self._cb_manage
        b_perms = Button(label="👑 Permissions", style=discord.ButtonStyle.secondary, custom_id="tvpv2_perms")
        b_perms.callback = self._cb_perms
        b_back = Button(label="◀️ Retour", style=discord.ButtonStyle.secondary, custom_id="tvpv2_back")
        b_back.callback = self._cb_back

        items: list = []
        if self.g.icon:
            items.append(v2_section(
                v2_title("🔊 Vocaux Temporaires"),
                v2_subtitle(f"{'🔘 actif' if enabled else '⚪ désactivé'} · `{active_hubs}` hub(s) · `{active_count}` vocaux actifs"),
                accessory=v2_thumb(self.g.icon.url),
            ))
        else:
            items.append(v2_title("🔊 Vocaux Temporaires"))
            items.append(v2_subtitle(f"{'🔘 actif' if enabled else '⚪ désactivé'} · `{active_hubs}` hub(s) · `{active_count}` vocaux actifs"))

        items.append(v2_divider())
        items.append(v2_body(
            "✅ Détection vocale & stream  ·  ❌ Écriture bloquée\n"
            "🗑️ Auto-delete si vide  ·  🔒 Restriction par rôle"
        ))
        items.append(v2_divider())
        items.append(v2_title("📋 Hubs configurés", level=3))
        items.append(v2_body(hubs_block))
        items.append(v2_divider())
        items.append(v2_title("👑 Permissions du propriétaire", level=3))
        items.append(v2_body(perms_txt))
        items.append(v2_divider())
        items.append(discord.ui.ActionRow(b_toggle, b_add, b_manage))
        items.append(discord.ui.ActionRow(b_perms, b_back))

        self.add_item(v2_container(*items, color=Palette.ACCENT))

        if edit:
            await interaction.response.edit_message(view=self, embed=None, attachments=[])
        else:
            await interaction.response.send_message(view=self, ephemeral=True)

    async def _cb_toggle(self, i):
        c = await cfg(self.g.id)
        voice_cfg = c.get('temp_voice_config', {})
        voice_cfg['enabled'] = not voice_cfg.get('enabled', False)
        await db_set(self.g.id, 'temp_voice_config', voice_cfg)
        new_panel = TempVoicePanelV2(self.u, self.g)
        await new_panel.render_to(i, edit=True)

    async def _cb_add(self, i):
        v = TempVoiceAddHubSelectV2(self.u, self.g)
        await v.render_to(i, edit=True)

    async def _cb_manage(self, i):
        c = await cfg(self.g.id)
        voice_cfg = c.get('temp_voice_config', {})
        if not voice_cfg.get('hubs', {}):
            return await i.response.send_message("❌ Aucun hub configuré", ephemeral=True)
        v = TempVoiceHubsListPanelV2(self.u, self.g)
        await v.render_to(i, edit=True)

    async def _cb_perms(self, i):
        v = TempVoicePermissionsPanelV2(self.u, self.g)
        await v.render_to(i, edit=True)

    async def _cb_back(self, i):
        v = MainPanelV2(self.u, self.g)
        await i.response.edit_message(view=v, embed=None, attachments=[])


class TempVoiceAddHubSelectV2(LayoutView):
    """Etape 1/3 : choisir le salon hub (V2)."""

    def __init__(self, u, g, page=0):
        super().__init__(timeout=180)
        self.u = u
        self.g = g
        self.page = page
        self.voice_channels = [c for c in g.channels if isinstance(c, discord.VoiceChannel)]
        self.per_page = 23
        self.max_page = max(0, (len(self.voice_channels) - 1) // self.per_page)

    async def interaction_check(self, i):
        return i.user.id == self.u.id

    def _build(self):
        start = self.page * self.per_page
        end = start + self.per_page
        page_chs = self.voice_channels[start:end]
        opts = [
            discord.SelectOption(
                label=f"🔊 {c.name}"[:25],
                value=str(c.id),
                description=(c.category.name[:50] if c.category else "Sans catégorie"),
            )
            for c in page_chs
        ]
        sel = Select(placeholder=f"Page {self.page+1}/{self.max_page+1} — Salon vocal…", options=opts, custom_id="tvahsv2_sel") if opts else None
        if sel:
            sel.callback = self._cb_select

        self.clear_items()
        b_prev = Button(label="◀️", style=discord.ButtonStyle.secondary, disabled=(self.page <= 0), custom_id="tvahsv2_prev")
        b_prev.callback = self._cb_prev
        b_page = Button(label=f"Page {self.page + 1}/{self.max_page + 1}", style=discord.ButtonStyle.secondary, disabled=True, custom_id="tvahsv2_page")
        b_next = Button(label="▶️", style=discord.ButtonStyle.secondary, disabled=(self.page >= self.max_page), custom_id="tvahsv2_next")
        b_next.callback = self._cb_next
        b_back = Button(label="◀️ Retour", style=discord.ButtonStyle.secondary, custom_id="tvahsv2_back")
        b_back.callback = self._cb_back

        items: list = [
            v2_title("➕ Ajouter un Hub Vocal"),
            v2_subtitle("Étape 1/3 · Choisis le salon vocal qui servira de hub"),
            v2_divider(),
            v2_body(
                "Quand un membre rejoindra ce salon, un vocal personnel sera créé\n"
                "automatiquement dans la catégorie que tu choisiras à l'étape suivante."
            ),
            v2_divider(),
            v2_subtitle(f"`{len(self.voice_channels)}` salon(s) vocal(aux) disponible(s)"),
        ]
        if sel:
            items.append(discord.ui.ActionRow(sel))
        items.append(discord.ui.ActionRow(b_prev, b_page, b_next, b_back))

        self.add_item(v2_container(*items, color=Palette.ACCENT))

    async def render_to(self, interaction, *, edit=True):
        self._build()
        if edit:
            await interaction.response.edit_message(view=self, embed=None, attachments=[])
        else:
            await interaction.response.send_message(view=self, ephemeral=True)

    async def _cb_prev(self, i):
        if self.page > 0:
            self.page -= 1
        await self.render_to(i, edit=True)

    async def _cb_next(self, i):
        if self.page < self.max_page:
            self.page += 1
        await self.render_to(i, edit=True)

    async def _cb_back(self, i):
        v = TempVoicePanelV2(self.u, self.g)
        await v.render_to(i, edit=True)

    async def _cb_select(self, i):
        hub_id = int(i.data['values'][0])
        v = TempVoiceAddHubCategoryV2(self.u, self.g, hub_id)
        await v.render_to(i, edit=True)


class TempVoiceAddHubSelect(View):
    """Étape 1: Sélection du salon hub — Paginé"""
    def __init__(self, u, g, page=0):
        super().__init__(timeout=180)
        self.u = u
        self.g = g
        self.page = page
        self.voice_channels = [c for c in g.channels if isinstance(c, discord.VoiceChannel)]
        self.per_page = 23
        self.max_page = max(0, (len(self.voice_channels) - 1) // self.per_page)
        self._build()

    def _build(self):
        self.clear_items()
        start = self.page * self.per_page
        end = start + self.per_page
        page_chs = self.voice_channels[start:end]
        opts = [discord.SelectOption(label=f"🔊 {c.name}"[:25], value=str(c.id), description=(c.category.name[:50] if c.category else "Sans catégorie")) for c in page_chs]
        if opts:
            select = Select(placeholder=f"Page {self.page+1}/{self.max_page+1} — Salon vocal...", options=opts)
            select.callback = self.select_callback
            self.add_item(select)
        if self.max_page > 0:
            prev_btn = discord.ui.Button(label="◀️", style=discord.ButtonStyle.primary, disabled=(self.page == 0), row=1)
            prev_btn.callback = self._prev
            self.add_item(prev_btn)
            page_btn = discord.ui.Button(label=f"{self.page+1}/{self.max_page+1}", style=discord.ButtonStyle.secondary, disabled=True, row=1)
            self.add_item(page_btn)
            next_btn = discord.ui.Button(label="▶️", style=discord.ButtonStyle.primary, disabled=(self.page >= self.max_page), row=1)
            next_btn.callback = self._next
            self.add_item(next_btn)
        back_btn = discord.ui.Button(label="◀️ Retour", style=discord.ButtonStyle.secondary, row=2)
        back_btn.callback = self._back
        self.add_item(back_btn)

    async def _prev(self, i):
        self.page -= 1
        self._build()
        await i.response.edit_message(view=self)

    async def _next(self, i):
        self.page += 1
        self._build()
        await i.response.edit_message(view=self)

    async def _back(self, i):
        v = TempVoicePanelV2(self.u, self.g)
        await v.render_to(i, edit=True)

    async def select_callback(self, i):
        hub_id = int(i.data['values'][0])
        hub_ch = self.g.get_channel(hub_id)

        # Passer à l'étape 2: choisir la catégorie
        v = TempVoiceAddHubCategory(self.u, self.g, hub_id)
        await i.response.edit_message(
            embed=discord.Embed(
                title="➕ Ajouter un Hub Vocal",
                description=f"**Étape 2/3** - Choisissez la catégorie où les vocaux seront créés.\n\n🎤 Hub sélectionné: **{hub_ch.name}**",
                color=0x9B59B6
            ),
            view=v
        )

