class TempVoiceAddHubCategory(View):
    """Étape 2: Sélection de la catégorie — Paginé"""
    def __init__(self, u, g, hub_id, page=0):
        super().__init__(timeout=180)
        self.u = u
        self.g = g
        self.hub_id = hub_id
        self.page = page
        self.categories = list(g.categories)
        self.per_page = 23
        self.max_page = max(0, (len(self.categories) - 1) // self.per_page)
        self._build()

    def _build(self):
        self.clear_items()
        start = self.page * self.per_page
        end = start + self.per_page
        page_cats = self.categories[start:end]
        opts = [discord.SelectOption(label=f"📁 {c.name}"[:25], value=str(c.id)) for c in page_cats]
        if opts:
            select = Select(placeholder=f"Page {self.page+1}/{self.max_page+1} — Catégorie...", options=opts)
            select.callback = self.select_callback
            self.add_item(select)
        if self.max_page > 0:
            prev_btn = discord.ui.Button(label="◀️", style=discord.ButtonStyle.primary, disabled=(self.page == 0), row=1)
            prev_btn.callback = self._prev
            self.add_item(prev_btn)
            page_btn = discord.ui.Button(label=f"{self.page+1}/{self.max_page+1}", style=discord.ButtonStyle.secondary, disabled=True, row=1)
            self.add_item(page_btn)
            next_btn = discord.ui.Button(label="▶️", style=discord.ButtonStyle.primary, disabled=(self.page >= self.max_page), row=1)
            next_btn.callback = self._next
            self.add_item(next_btn)
    
    async def _prev(self, i):
        self.page -= 1
        self._build()
        await i.response.edit_message(view=self)

    async def _next(self, i):
        self.page += 1
        self._build()
        await i.response.edit_message(view=self)

    async def select_callback(self, i):
        cat_id = int(i.data['values'][0])
        cat = self.g.get_channel(cat_id)
        hub_ch = self.g.get_channel(self.hub_id)

        # Passer à l'étape 3: choisir le rôle requis (optionnel)
        v = TempVoiceAddHubRole(self.u, self.g, self.hub_id, cat_id)
        await i.response.edit_message(
            embed=discord.Embed(
                title="➕ Ajouter un Hub Vocal",
                description=(
                    f"**Étape 3/3** - Choisissez un rôle requis (optionnel).\n\n"
                    f"🎤 Hub: **{hub_ch.name}**\n"
                    f"📁 Catégorie: **{cat.name}**\n\n"
                    f"**🔒 Effet du rôle requis :**\n"
                    f"• Seuls les membres avec ce rôle peuvent créer un vocal\n"
                    f"• Le vocal créé sera **invisible** pour les autres membres\n"
                    f"• Seuls les membres avec le rôle peuvent voir/rejoindre le vocal"
                ),
                color=0x9B59B6
            ),
            view=v
        )

class TempVoiceAddHubRoleV2(LayoutView):
    """Etape 3/3 : rôle requis (V2). Une fois validé, sauvegarde le hub."""

    def __init__(self, u, g, hub_id, cat_id, page=0):
        super().__init__(timeout=300)
        self.u = u
        self.g = g
        self.hub_id = hub_id
        self.cat_id = cat_id
        self.page = page
        self.all_roles = [r for r in sorted(g.roles, key=lambda x: x.position, reverse=True) if not r.is_default() and not r.managed]
        self.per_page = 23
        self.max_page = max(0, (len(self.all_roles) - 1) // self.per_page) if self.all_roles else 0

    async def interaction_check(self, i):
        return i.user.id == self.u.id

    def _build(self):
        start = self.page * self.per_page
        end = start + self.per_page
        page_roles = self.all_roles[start:end]

        opts = []
        if self.page == 0:
            opts.append(discord.SelectOption(label="🔓 Public (tous)", value="0", description="Aucune restriction", emoji="✅"))
        for r in page_roles:
            if len(opts) >= 25:
                break
            opts.append(discord.SelectOption(label=r.name[:100], value=str(r.id), description="Réservé aux membres avec ce rôle", emoji="🔒"))

        sel = Select(placeholder=f"Page {self.page+1}/{self.max_page+1} — Rôle…", options=opts, custom_id="tvahrv2_sel") if opts else None
        if sel:
            sel.callback = self._cb_select

        hub_ch = self.g.get_channel(self.hub_id)
        cat = self.g.get_channel(self.cat_id)

        self.clear_items()
        b_prev = Button(label="◀️", style=discord.ButtonStyle.secondary, disabled=(self.page <= 0), custom_id="tvahrv2_prev")
        b_prev.callback = self._cb_prev
        b_page = Button(label=f"Page {self.page + 1}/{self.max_page + 1}", style=discord.ButtonStyle.secondary, disabled=True, custom_id="tvahrv2_page")
        b_next = Button(label="▶️", style=discord.ButtonStyle.secondary, disabled=(self.page >= self.max_page), custom_id="tvahrv2_next")
        b_next.callback = self._cb_next
        b_back = Button(label="◀️ Retour", style=discord.ButtonStyle.secondary, custom_id="tvahrv2_back")
        b_back.callback = self._cb_back

        items: list = [
            v2_title("➕ Ajouter un Hub Vocal"),
            v2_subtitle("Étape 3/3 · Rôle requis (optionnel)"),
            v2_divider(),
            v2_body(
                f"🎤 **Hub** · `{hub_ch.name if hub_ch else 'Inconnu'}`\n"
                f"📁 **Catégorie** · `{cat.name if cat else 'Inconnu'}`"
            ),
            v2_divider(),
            v2_body(
                "**🔒 Effet du rôle requis :**\n"
                "• Seuls les membres avec ce rôle peuvent créer un vocal\n"
                "• Le vocal créé sera **invisible** pour les autres membres\n"
                "• Seuls les membres avec le rôle peuvent voir/rejoindre le vocal"
            ),
            v2_divider(),
            v2_subtitle(f"`{len(self.all_roles)}` rôle(s) disponible(s) · Choisis 🔓 Public ou un rôle 🔒"),
        ]
        if sel:
            items.append(discord.ui.ActionRow(sel))
        items.append(discord.ui.ActionRow(b_prev, b_page, b_next, b_back))

        self.add_item(v2_container(*items, color=Palette.ACCENT))

    async def render_to(self, interaction, *, edit=True):
        self._build()
        if edit:
            await interaction.response.edit_message(view=self, embed=None, attachments=[])
        else:
            await interaction.response.send_message(view=self, ephemeral=True)

    async def _cb_prev(self, i):
        if self.page > 0:
            self.page -= 1
        await self.render_to(i, edit=True)

    async def _cb_next(self, i):
        if self.page < self.max_page:
            self.page += 1
        await self.render_to(i, edit=True)

    async def _cb_back(self, i):
        v = TempVoiceAddHubCategoryV2(self.u, self.g, self.hub_id)
        await v.render_to(i, edit=True)

    async def _cb_select(self, i):
        try:
            role_id = int(i.data['values'][0])
            c = await cfg(self.g.id)
            voice_cfg = c.get('temp_voice_config', {})
            hubs = voice_cfg.get('hubs', {})
            hubs[str(self.hub_id)] = {
                'category': self.cat_id,
                'required_role': role_id,
                'default_name': '🔊 Vocal de {user}',
            }
            voice_cfg['hubs'] = hubs
            voice_cfg.setdefault('enabled', True)
            await db_set(self.g.id, 'temp_voice_config', voice_cfg)
            # Retour au panel TempVoice V2 avec confirmation
            v = TempVoicePanelV2(self.u, self.g)
            await v.render_to(i, edit=True)
        except Exception as ex:
            print(f"[TempVoiceAddHubRoleV2._cb_select] {ex}")
            try:
                await i.response.send_message(f"❌ Erreur: {ex}", ephemeral=True)
            except Exception:
                pass


class TempVoiceAddHubRole(View):
    """Étape 3: Sélection du rôle requis avec pagination complète"""
    def __init__(self, u, g, hub_id, cat_id, page=0):
        super().__init__(timeout=300)
        self.u = u
        self.g = g
        self.hub_id = hub_id
        self.cat_id = cat_id
        self.page = page
        
        # Filtrer les rôles (exclure @everyone et les rôles de bot) - triés par position
        self.all_roles = [r for r in sorted(g.roles, key=lambda x: x.position, reverse=True) if not r.is_default() and not r.managed]
        self.per_page = 24  # Max 25 options par select, on garde 24 pour la marge
        self.max_page = max(0, len(self.all_roles) // self.per_page)
        
        self._build()
    
    def _build(self):
        self.clear_items()
        
        # Calculer les rôles pour cette page
        start = self.page * self.per_page
        end = min(start + self.per_page, len(self.all_roles))
        page_roles = self.all_roles[start:end]
        
        # Construire les options
        opts = []
        
        # Option "Public" seulement sur la première page
        if self.page == 0:
            opts.append(discord.SelectOption(
                label="🔓 Public (tous peuvent rejoindre)",
                value="0",
                description="Aucune restriction de rôle",
                emoji="✅"
            ))
        
        # Ajouter les rôles de cette page
        for r in page_roles:
            if len(opts) >= 25:
                break
            opts.append(discord.SelectOption(
                label=r.name[:100],
                value=str(r.id),
                description=f"Réservé aux membres avec ce rôle",
                emoji="🔒"
            ))
        
        # Créer le select si on a des options
        if opts:
            select = Select(
                placeholder=f"Sélectionner un rôle ({len(self.all_roles)} disponibles)...",
                options=opts,
                row=0
            )
            select.callback = self._on_select
            self.add_item(select)
        
        # Boutons de navigation si plusieurs pages
        if self.max_page > 0:
            # Bouton précédent
            prev_btn = Button(label="◀️ Précédent", style=discord.ButtonStyle.primary, row=1, disabled=(self.page == 0))
            prev_btn.callback = self._prev
            self.add_item(prev_btn)
            
            # Indicateur de page
            info_btn = Button(label=f"Page {self.page + 1}/{self.max_page + 1}", style=discord.ButtonStyle.secondary, row=1, disabled=True)
            self.add_item(info_btn)
            
            # Bouton suivant
            next_btn = Button(label="Suivant ▶️", style=discord.ButtonStyle.primary, row=1, disabled=(self.page >= self.max_page))
            next_btn.callback = self._next
            self.add_item(next_btn)
        
        # Bouton retour
        back_btn = Button(label="◀️ Retour", style=discord.ButtonStyle.secondary, row=2)
        back_btn.callback = self._back
        self.add_item(back_btn)
    
    async def _prev(self, i: discord.Interaction):
        # Répondre IMMÉDIATEMENT pour éviter le timeout
        try:
            await i.response.defer()
        except:
            pass
        
        if self.page > 0:
            self.page -= 1
            self._build()
        
        try:
            await i.edit_original_response(view=self)
        except:
            pass
    
    async def _next(self, i: discord.Interaction):
        try:
            await i.response.defer()
        except:
            pass
        
        if self.page < self.max_page:
            self.page += 1
            self._build()
        
        try:
            await i.edit_original_response(view=self)
        except:
            pass
    
    async def _back(self, i: discord.Interaction):
        try:
            await i.response.defer()
        except:
            pass
        
        try:
            v = TempVoiceAddHubCategory(self.u, self.g, self.hub_id)
            hub_ch = self.g.get_channel(self.hub_id)
            await i.edit_original_response(
                embed=discord.Embed(
                    title="➕ Ajouter un Hub Vocal",
                    description=f"**Étape 2/3** - Choisissez la catégorie.\n\n🎤 Hub: **{hub_ch.name if hub_ch else 'Inconnu'}**",
                    color=0x9B59B6
                ),
                view=v
            )
        except Exception as ex:
            print(f"[TempVoiceAddHubRole._back] {ex}")
    
    async def _on_select(self, i: discord.Interaction):
        # Répondre immédiatement
        try:
            await i.response.defer()
        except:
            pass
        
        try:
            role_id = int(i.data['values'][0])
            
            # Sauvegarder le hub
            c = await cfg(self.g.id)
            voice_cfg = c.get('temp_voice_config', {})
            hubs = voice_cfg.get('hubs', {})
            
            hubs[str(self.hub_id)] = {
                'category': self.cat_id,
                'required_role': role_id,
                'default_name': '🔊 Vocal de {user}'
            }
            
            voice_cfg['hubs'] = hubs
            await db_set(self.g.id, 'temp_voice_config', voice_cfg)
            
            # Confirmation
            hub_ch = self.g.get_channel(self.hub_id)
            cat = self.g.get_channel(self.cat_id)
            role = self.g.get_role(role_id) if role_id else None
            
            if role:
                visibility_txt = f"🔒 **PRIVÉ** - Réservé à @{role.name}\n*Les vocaux créés seront invisibles pour les autres*"
            else:
                visibility_txt = "🔓 **PUBLIC** - Tout le monde peut voir et rejoindre"
            
            v = TempVoicePanel(self.u, self.g)
            await i.edit_original_response(
                content=f"✅ **Hub ajouté avec succès !**\n\n🎤 Hub: **{hub_ch.name if hub_ch else 'Inconnu'}**\n📁 Catégorie: **{cat.name if cat else 'Inconnue'}**\n{visibility_txt}",
                embed=await v.embed(),
                view=v
            )
        except Exception as ex:
            print(f"[TempVoiceAddHubRole._on_select] {ex}")
            try:
                await i.edit_original_response(content="❌ Une erreur est survenue. Réessayez.")
            except:
                pass

class TempVoiceHubsListPanel(View):
    """Panel pour lister et gérer les hubs existants"""
    def __init__(self, u, g, page=0):
        super().__init__(timeout=300)
        self.u = u
        self.g = g
        self.page = page
        self.per_page = 5
    
    async def get_hubs(self):
        c = await cfg(self.g.id)
        voice_cfg = c.get('temp_voice_config', {})
        return voice_cfg.get('hubs', {})
    
    async def embed(self):
        hubs = await self.get_hubs()
        
        e = discord.Embed(title="📋 Liste des Hubs Vocaux", color=0x9B59B6)
        
        if not hubs:
            e.description = "*Aucun hub configuré*"
            return e
        
        # Pagination
        hub_items = list(hubs.items())
        start = self.page * self.per_page
        end = start + self.per_page
        page_hubs = hub_items[start:end]
        
        description_parts = []
        for idx, (hub_id, hub_data) in enumerate(page_hubs, start=start+1):
            hub_ch = self.g.get_channel(int(hub_id))
            if not hub_ch:
                description_parts.append(f"**{idx}.** ❌ *Salon supprimé* (ID: {hub_id})")
                continue
            
            cat = self.g.get_channel(hub_data.get('category', 0))
            role_id = hub_data.get('required_role', 0)
            role = self.g.get_role(role_id) if role_id else None
            default_name = hub_data.get('default_name', '🔊 Vocal de {user}')
            
            description_parts.append(
                f"**{idx}. 🎤 {hub_ch.name}**\n"
                f"┣ 📁 Catégorie: {cat.name if cat else '❌ Non définie'}\n"
                f"┣ 🔒 Rôle: {role.mention if role else '🔓 Aucun (tous)'}\n"
                f"┗ 📝 Nom: `{default_name}`"
            )
        
        e.description = "\n\n".join(description_parts)
        
        total_pages = max(1, (len(hubs) - 1) // self.per_page + 1)
        e.set_footer(text=f"Page {self.page + 1}/{total_pages} • {len(hubs)} hub(s) configuré(s)")
        
        return e
    
    @discord.ui.button(label="◀️", style=discord.ButtonStyle.secondary, row=0)
    async def prev_page(self, i, b):
        if self.page > 0:
            self.page -= 1
        await i.response.edit_message(embed=await self.embed(), view=self)
    
    @discord.ui.button(label="▶️", style=discord.ButtonStyle.secondary, row=0)
    async def next_page(self, i, b):
        hubs = await self.get_hubs()
        max_page = max(0, (len(hubs) - 1) // self.per_page)
        if self.page < max_page:
            self.page += 1
        await i.response.edit_message(embed=await self.embed(), view=self)
    
    @discord.ui.button(label="✏️ Modifier Hub", style=discord.ButtonStyle.primary, row=1)
    async def edit_hub(self, i, b):
        hubs = await self.get_hubs()
        if not hubs:
            return await i.response.send_message("❌ Aucun hub à modifier", ephemeral=True)
        
        v = TempVoiceHubEditSelect(self.u, self.g, hubs)
        await i.response.edit_message(
            embed=discord.Embed(
                title="✏️ Modifier un Hub",
                description="Sélectionnez le hub à modifier.",
                color=0x9B59B6
            ),
            view=v
        )
    
    @discord.ui.button(label="🗑️ Supprimer Hub", style=discord.ButtonStyle.danger, row=1)
    async def delete_hub(self, i, b):
        hubs = await self.get_hubs()
        if not hubs:
            return await i.response.send_message("❌ Aucun hub à supprimer", ephemeral=True)
        
        v = TempVoiceHubDeleteSelect(self.u, self.g, hubs)
        await i.response.edit_message(
            embed=discord.Embed(
                title="🗑️ Supprimer un Hub",
                description="Sélectionnez le hub à supprimer.",
                color=0xE74C3C
            ),
            view=v
        )
    
    @discord.ui.button(label="◀️ Retour", style=discord.ButtonStyle.secondary, row=2)
    async def back(self, i, b):
        v = TempVoicePanelV2(self.u, self.g)
        await v.render_to(i, edit=True)

class TempVoiceHubsListPanelV2(LayoutView):
    """Liste paginee des hubs vocaux en V2."""

    def __init__(self, u, g, page=0):
        super().__init__(timeout=300)
        self.u = u
        self.g = g
        self.page = page
        self.per_page = 5

    async def interaction_check(self, i):
        return i.user.id == self.u.id

    async def _get_hubs(self):
        c = await cfg(self.g.id)
        voice_cfg = c.get('temp_voice_config', {})
        return voice_cfg.get('hubs', {})

    async def render_to(self, interaction: discord.Interaction, *, edit: bool = True):
        hubs = await self._get_hubs()
        total = len(hubs)
        max_page = max(0, (total - 1) // self.per_page) if total else 0

        # Construction de la liste paginée
        hub_blocks = []
        if hubs:
            hub_items = list(hubs.items())
            start = self.page * self.per_page
            end = start + self.per_page
            for idx, (hub_id, hub_data) in enumerate(hub_items[start:end], start=start + 1):
                hub_ch = self.g.get_channel(int(hub_id))
                if not hub_ch:
                    hub_blocks.append(f"**{idx}.** ❌ _Salon supprimé_ (ID: `{hub_id}`)")
                    continue
                cat = self.g.get_channel(hub_data.get('category', 0))
                role_id = hub_data.get('required_role', 0)
                role = self.g.get_role(role_id) if role_id else None
                default_name = hub_data.get('default_name', '🔊 Vocal de {user}')
                hub_blocks.append(
                    f"**{idx}. 🎤 {hub_ch.name}**\n"
                    f"┣ 📁 Catégorie · `{cat.name if cat else 'Non définie'}`\n"
                    f"┣ 🔒 Rôle · {role.mention if role else '🔓 _Aucun (tous)_'}\n"
                    f"┗ 📝 Nom · `{default_name}`"
                )
        list_block = "\n\n".join(hub_blocks) if hub_blocks else "_Aucun hub configuré_"

        self.clear_items()
        b_prev = Button(label="◀️", style=discord.ButtonStyle.secondary, disabled=(self.page <= 0), custom_id="tvhlv2_prev")
        b_prev.callback = self._cb_prev
        b_page = Button(label=f"Page {self.page + 1}/{max_page + 1}", style=discord.ButtonStyle.secondary, disabled=True, custom_id="tvhlv2_page")
        b_next = Button(label="▶️", style=discord.ButtonStyle.secondary, disabled=(self.page >= max_page), custom_id="tvhlv2_next")
        b_next.callback = self._cb_next
        b_edit = Button(label="✏️ Modifier Hub", style=discord.ButtonStyle.primary, disabled=(not hubs), custom_id="tvhlv2_edit")
        b_edit.callback = self._cb_edit
        b_delete = Button(label="🗑️ Supprimer Hub", style=discord.ButtonStyle.danger, disabled=(not hubs), custom_id="tvhlv2_delete")
        b_delete.callback = self._cb_delete
        b_back = Button(label="◀️ Retour", style=discord.ButtonStyle.secondary, custom_id="tvhlv2_back")
        b_back.callback = self._cb_back

        items: list = [
            v2_title("📋 Liste des Hubs Vocaux"),
            v2_subtitle(f"`{total}` hub(s) configuré(s)"),
            v2_divider(),
            v2_body(list_block),
            v2_divider(),
            discord.ui.ActionRow(b_prev, b_page, b_next),
            discord.ui.ActionRow(b_edit, b_delete, b_back),
        ]

        self.add_item(v2_container(*items, color=Palette.ACCENT))

        if edit:
            await interaction.response.edit_message(view=self, embed=None, attachments=[])
        else:
            await interaction.response.send_message(view=self, ephemeral=True)

    async def _cb_prev(self, i):
        if self.page > 0:
            self.page -= 1
        await self.render_to(i, edit=True)

    async def _cb_next(self, i):
        hubs = await self._get_hubs()
        max_page = max(0, (len(hubs) - 1) // self.per_page) if hubs else 0
        if self.page < max_page:
            self.page += 1
        await self.render_to(i, edit=True)

    async def _cb_edit(self, i):
        hubs = await self._get_hubs()
        if not hubs:
            return await i.response.send_message("❌ Aucun hub à modifier", ephemeral=True)
        v = TempVoiceHubEditSelect(self.u, self.g, hubs)
        await i.response.edit_message(
            embed=discord.Embed(
                title="✏️ Modifier un Hub",
                description="Sélectionne le hub à modifier.",
                color=0x9B59B6,
            ),
            view=v,
            attachments=[],
        )

    async def _cb_delete(self, i):
        hubs = await self._get_hubs()
        if not hubs:
            return await i.response.send_message("❌ Aucun hub à supprimer", ephemeral=True)
        v = TempVoiceHubDeleteSelect(self.u, self.g, hubs)
        await i.response.edit_message(
            embed=discord.Embed(
                title="🗑️ Supprimer un Hub",
                description="Sélectionne le hub à supprimer.",
                color=0xE74C3C,
            ),
            view=v,
            attachments=[],
        )

    async def _cb_back(self, i):
        v = TempVoicePanelV2(self.u, self.g)
        await v.render_to(i, edit=True)


class TempVoiceHubEditSelect(View):
    """Sélection d'un hub à modifier"""
    def __init__(self, u, g, hubs):
        super().__init__(timeout=120)
        self.u = u
        self.g = g
        
        opts = []
        for hub_id, hub_data in list(hubs.items())[:25]:
            hub_ch = g.get_channel(int(hub_id))
            if hub_ch:
                role_id = hub_data.get('required_role', 0)
                role = g.get_role(role_id) if role_id else None
                label = f"🎤 {hub_ch.name}"[:25]
                desc = f"Rôle: {role.name if role else 'Aucun'}"[:50]
                opts.append(discord.SelectOption(label=label, value=hub_id, description=desc))
        
        if opts:
            select = Select(placeholder="Choisir un hub...", options=opts)
