class TempVoiceHubEditPanelV2(LayoutView):
    """Modifier un hub vocal en V2."""

    def __init__(self, u, g, hub_id):
        super().__init__(timeout=300)
        self.u = u
        self.g = g
        self.hub_id = hub_id

    async def interaction_check(self, i):
        return i.user.id == self.u.id

    async def _get_hub_data(self):
        c = await cfg(self.g.id)
        voice_cfg = c.get('temp_voice_config', {})
        hubs = voice_cfg.get('hubs', {})
        return hubs.get(str(self.hub_id), {})

    def _build(self):
        """Construit le LayoutView (sans l'envoyer)."""
        # On a besoin des données — donc cette fonction est async en réalité.
        # On la transforme en méthode async distincte _build_async.
        pass

    async def _build_async(self):
        hub_data = await self._get_hub_data()
        hub_ch = self.g.get_channel(int(self.hub_id))

        cat = self.g.get_channel(hub_data.get('category', 0))
        role_id = hub_data.get('required_role', 0)
        role = self.g.get_role(role_id) if role_id else None
        default_name = hub_data.get('default_name', '🔊 Vocal de {user}')

        if role:
            mode_line = f"🔒 **PRIVÉ** · {role.mention}"
            mode_desc = f"_Les vocaux créés seront invisibles pour les membres sans le rôle {role.name}._"
        else:
            mode_line = "🔓 **PUBLIC** · Tout le monde"
            mode_desc = "_Tout le monde peut voir et rejoindre les vocaux créés._"

        self.clear_items()
        b_cat = Button(label="📁 Catégorie", style=discord.ButtonStyle.primary, custom_id="tvhepv2_cat")
        b_cat.callback = self._cb_cat
        b_role = Button(label="🔐 Mode / Rôle", style=discord.ButtonStyle.primary, custom_id="tvhepv2_role")
        b_role.callback = self._cb_role
        b_name = Button(label="📝 Nom par défaut", style=discord.ButtonStyle.secondary, custom_id="tvhepv2_name")
        b_name.callback = self._cb_name
        b_back = Button(label="◀️ Retour", style=discord.ButtonStyle.secondary, custom_id="tvhepv2_back")
        b_back.callback = self._cb_back

        items: list = [
            v2_title(f"✏️ Modifier · {hub_ch.name if hub_ch else 'Hub'}"),
            v2_subtitle("Configuration spécifique de ce hub vocal"),
            v2_divider(),
            v2_body(
                f"📁 **Catégorie** · `{cat.name if cat else 'Non définie'}`\n"
                f"🔐 **Mode** · {mode_line}"
            ),
            v2_body(mode_desc),
            v2_divider(),
            v2_body(f"📝 **Nom par défaut** · `{default_name}`"),
            v2_divider(),
            discord.ui.ActionRow(b_cat, b_role, b_name, b_back),
        ]

        self.add_item(v2_container(*items, color=Palette.ACCENT))

    async def render_to(self, interaction: discord.Interaction, *, edit: bool = True):
        await self._build_async()
        if edit:
            await interaction.response.edit_message(view=self, embed=None, attachments=[])
        else:
            await interaction.response.send_message(view=self, ephemeral=True)

    async def render_after_defer(self, interaction: discord.Interaction, *, content=None):
        """À utiliser quand interaction.response.defer() a déjà été appelé."""
        await self._build_async()
        kwargs = dict(view=self, embed=None, attachments=[])
        if content is not None:
            kwargs['content'] = content
        await interaction.edit_original_response(**kwargs)

    async def _cb_cat(self, i):
        v = TempVoiceHubEditCategory(self.u, self.g, self.hub_id)
        await i.response.edit_message(
            embed=discord.Embed(
                title="📁 Changer la catégorie",
                description="Sélectionne la nouvelle catégorie.",
                color=0x9B59B6,
            ),
            view=v,
            attachments=[],
        )

    async def _cb_role(self, i):
        v = TempVoiceHubEditRole(self.u, self.g, self.hub_id)
        await i.response.edit_message(
            embed=discord.Embed(
                title="🔐 Changer le mode",
                description=(
                    "**🔓 Public** = Tout le monde voit/rejoint les vocaux\n"
                    "**🔒 Privé** = Seul le rôle choisi voit/rejoint les vocaux"
                ),
                color=0x9B59B6,
            ),
            view=v,
            attachments=[],
        )

    async def _cb_name(self, i):
        await i.response.send_modal(TempVoiceHubNameModal(self.g, self.u, self.hub_id))

    async def _cb_back(self, i):
        v = TempVoiceHubsListPanelV2(self.u, self.g)
        await v.render_to(i, edit=True)


class TempVoiceHubEditCategory(View):
    """Modifier la catégorie d'un hub — Paginé"""
    def __init__(self, u, g, hub_id, page=0):
        super().__init__(timeout=180)
        self.u = u
        self.g = g
        self.hub_id = hub_id
        self.page = page
        self.categories = list(g.categories)
        self.per_page = 23
        self.max_page = max(0, (len(self.categories) - 1) // self.per_page)
        self._build()

    def _build(self):
        self.clear_items()
        start = self.page * self.per_page
        end = start + self.per_page
        page_cats = self.categories[start:end]
        opts = [discord.SelectOption(label=f"📁 {c.name}"[:25], value=str(c.id)) for c in page_cats]
        if opts:
            select = Select(placeholder=f"Page {self.page+1}/{self.max_page+1} — Catégorie...", options=opts)
            select.callback = self.select_callback
            self.add_item(select)
        if self.max_page > 0:
            prev_btn = discord.ui.Button(label="◀️", style=discord.ButtonStyle.primary, disabled=(self.page == 0), row=1)
            prev_btn.callback = self._prev
            self.add_item(prev_btn)
            page_btn = discord.ui.Button(label=f"{self.page+1}/{self.max_page+1}", style=discord.ButtonStyle.secondary, disabled=True, row=1)
            self.add_item(page_btn)
            next_btn = discord.ui.Button(label="▶️", style=discord.ButtonStyle.primary, disabled=(self.page >= self.max_page), row=1)
            next_btn.callback = self._next
            self.add_item(next_btn)
        back_btn = discord.ui.Button(label="◀️ Retour", style=discord.ButtonStyle.secondary, row=2)
        back_btn.callback = self._back
        self.add_item(back_btn)

    async def _prev(self, i):
        self.page -= 1
        self._build()
        await i.response.edit_message(view=self)

    async def _next(self, i):
        self.page += 1
        self._build()
        await i.response.edit_message(view=self)

    async def _back(self, i):
        v = TempVoiceHubEditPanelV2(self.u, self.g, self.hub_id)
        await v.render_to(i, edit=True)

    async def select_callback(self, i):
        cat_id = int(i.data['values'][0])
        c = await cfg(self.g.id)
        voice_cfg = c.get('temp_voice_config', {})
        hubs = voice_cfg.get('hubs', {})
        if str(self.hub_id) in hubs:
            hubs[str(self.hub_id)]['category'] = cat_id
            voice_cfg['hubs'] = hubs
            await db_set(self.g.id, 'temp_voice_config', voice_cfg)
        cat = self.g.get_channel(cat_id)
        v = TempVoiceHubEditPanelV2(self.u, self.g, self.hub_id)
        await v.render_to(i, edit=True)

class TempVoiceHubEditRole(View):
    """Modifier le rôle requis d'un hub avec pagination complète"""
    def __init__(self, u, g, hub_id, page=0):
        super().__init__(timeout=300)
        self.u = u
        self.g = g
        self.hub_id = hub_id
        self.page = page
        
        # Filtrer les rôles
        self.all_roles = [r for r in sorted(g.roles, key=lambda x: x.position, reverse=True) if not r.is_default() and not r.managed]
        self.per_page = 24
        self.max_page = max(0, len(self.all_roles) // self.per_page)
        
        self._build()
    
    def _build(self):
        self.clear_items()
        
        start = self.page * self.per_page
        end = min(start + self.per_page, len(self.all_roles))
        page_roles = self.all_roles[start:end]
        
        opts = []
        if self.page == 0:
            opts.append(discord.SelectOption(
                label="🔓 Public (tous peuvent rejoindre)",
                value="0",
                description="Aucune restriction de rôle",
                emoji="✅"
            ))
        
        for r in page_roles:
            if len(opts) >= 25:
                break
            opts.append(discord.SelectOption(
                label=r.name[:100],
                value=str(r.id),
                description="Réservé aux membres avec ce rôle",
                emoji="🔒"
            ))
        
        if opts:
            select = Select(
                placeholder=f"Sélectionner un rôle ({len(self.all_roles)} disponibles)...",
                options=opts,
                row=0
            )
            select.callback = self._on_select
            self.add_item(select)
        
        if self.max_page > 0:
            prev_btn = Button(label="◀️ Précédent", style=discord.ButtonStyle.primary, row=1, disabled=(self.page == 0))
            prev_btn.callback = self._prev
            self.add_item(prev_btn)
            
            info_btn = Button(label=f"Page {self.page + 1}/{self.max_page + 1}", style=discord.ButtonStyle.secondary, row=1, disabled=True)
            self.add_item(info_btn)
            
            next_btn = Button(label="Suivant ▶️", style=discord.ButtonStyle.primary, row=1, disabled=(self.page >= self.max_page))
            next_btn.callback = self._next
            self.add_item(next_btn)
        
        back_btn = Button(label="◀️ Retour", style=discord.ButtonStyle.secondary, row=2)
        back_btn.callback = self._back
        self.add_item(back_btn)
    
    async def _prev(self, i: discord.Interaction):
        try:
            await i.response.defer()
        except:
            pass
        
        if self.page > 0:
            self.page -= 1
            self._build()
        
        try:
            await i.edit_original_response(view=self)
        except:
            pass
    
    async def _next(self, i: discord.Interaction):
        try:
            await i.response.defer()
        except:
            pass
        
        if self.page < self.max_page:
            self.page += 1
            self._build()
        
        try:
            await i.edit_original_response(view=self)
        except:
            pass
    
    async def _back(self, i: discord.Interaction):
        try:
            await i.response.defer()
        except:
            pass
        
        try:
            v = TempVoiceHubEditPanelV2(self.u, self.g, self.hub_id)
            # response déjà deferred → on construit la View puis edit_original_response
            await v.render_after_defer(i)
        except Exception as ex:
            print(f"[VoiceHubEditRole back] {ex}")
    
    async def _on_select(self, i: discord.Interaction):
        try:
            await i.response.defer()
        except:
            pass
        
        try:
            role_id = int(i.data['values'][0])
            
            c = await cfg(self.g.id)
            voice_cfg = c.get('temp_voice_config', {})
            hubs = voice_cfg.get('hubs', {})
            
            if str(self.hub_id) in hubs:
                hubs[str(self.hub_id)]['required_role'] = role_id
                voice_cfg['hubs'] = hubs
                await db_set(self.g.id, 'temp_voice_config', voice_cfg)
            
            role = self.g.get_role(role_id) if role_id else None
            
            if role:
                msg = f"✅ **Rôle changé: @{role.name}**\n🔒 Les vocaux seront invisibles pour les membres sans ce rôle"
            else:
                msg = f"✅ **Mode PUBLIC activé**\n🔓 Tout le monde peut voir et rejoindre les vocaux créés"
            
            v = TempVoiceHubEditPanelV2(self.u, self.g, self.hub_id)
            # response deferred → render via edit_original_response
            await v.render_after_defer(i, content=msg)
        except Exception as ex:
            print(f"[TempVoiceHubEditRole._on_select] {ex}")

