class TicketMainPanelV2(LayoutView):
    """Panneau Tickets en V2."""

    def __init__(self, u, g):
        super().__init__(timeout=600)
        self.u = u
        self.g = g

    async def interaction_check(self, i):
        return i.user.id == self.u.id

    async def render_to(self, interaction: discord.Interaction, *, edit: bool = True):
        c = await cfg(self.g.id)
        staff = self.g.get_role(c.get('ticket_staff', 0))
        lch = self.g.get_channel(c.get('ticket_log', 0))
        blacklist_role = self.g.get_role(c.get('ticket_blacklist_role', 0))
        panels = c.get('ticket_panels', {})

        def dot(item, fallback="_non défini_"):
            return f"🔘 {item.mention}" if item else f"⚪ {fallback}"

        # Liste compacte des panels (max 8)
        panel_lines = []
        if panels:
            for pid, pd in list(panels.items())[:8]:
                cat = self.g.get_channel(pd.get('category', 0))
                q_count = len(pd.get('questions', []))
                max_t = pd.get('max', 1)
                bl_count = len(pd.get('blacklist', []))
                bl_txt = f" · 🚫 `{bl_count}`" if bl_count > 0 else ""
                panel_lines.append(
                    f"• **{pd.get('name', pid)[:24]}** → {cat.mention if cat else '⚪ _catégorie ?_'} "
                    f"· `{q_count}` Q · max `{max_t}`{bl_txt}"
                )
            if len(panels) > 8:
                panel_lines.append(f"_… + {len(panels) - 8} autres_")
        panels_block = "\n".join(panel_lines) if panel_lines else "_Aucun panel — clique ➕ Nouveau panel_"

        # Boutons
        self.clear_items()
        b_staff = Button(label="👮 Staff", style=discord.ButtonStyle.primary, custom_id="tmpv2_staff")
        b_staff.callback = self._cb_staff
        b_logs = Button(label="📜 Logs", style=discord.ButtonStyle.primary, custom_id="tmpv2_logs")
        b_logs.callback = self._cb_logs
        b_blacklist = Button(label="🚫 Blacklist", style=discord.ButtonStyle.primary, custom_id="tmpv2_blacklist")
        b_blacklist.callback = self._cb_blacklist
        b_new = Button(label="➕ Nouveau panel", style=discord.ButtonStyle.success, custom_id="tmpv2_new")
        b_new.callback = self._cb_new
        b_edit = Button(label="📝 Modifier", style=discord.ButtonStyle.secondary, disabled=(not panels), custom_id="tmpv2_edit")
        b_edit.callback = self._cb_edit
        b_back = Button(label="◀️ Retour", style=discord.ButtonStyle.secondary, custom_id="tmpv2_back")
        b_back.callback = self._cb_back

        items: list = []
        if self.g.icon:
            items.append(v2_section(
                v2_title("🎫 Tickets"),
                v2_subtitle(f"`{len(panels)}` panel(s) · système de support"),
                accessory=v2_thumb(self.g.icon.url),
            ))
        else:
            items.append(v2_title("🎫 Tickets"))
            items.append(v2_subtitle(f"`{len(panels)}` panel(s) · système de support"))

        items.append(v2_divider())
        items.append(v2_body(
            f"👮 **Staff** · {dot(staff)}\n"
            f"📜 **Logs** · {dot(lch)}\n"
            f"🚫 **Blacklist** · {dot(blacklist_role, '_Staff par défaut_')}"
        ))
        items.append(v2_divider())
        items.append(v2_title("Panels de tickets", level=3))
        items.append(v2_body(panels_block))
        items.append(v2_divider())
        items.append(discord.ui.ActionRow(b_staff, b_logs, b_blacklist))
        items.append(discord.ui.ActionRow(b_new, b_edit, b_back))

        self.add_item(v2_container(*items, color=Palette.ACCENT))

        if edit:
            await interaction.response.edit_message(view=self, embed=None, attachments=[])
        else:
            await interaction.response.send_message(view=self, ephemeral=True)

    async def _cb_staff(self, i):
        # Phase 3.0k : V2 native picker
        v = V2GenericRolePicker(
            self.u, self.g,
            config_key='ticket_staff',
            return_panel_factory=lambda: TicketMainPanelV2(self.u, self.g),
            title="👮 Rôle Staff Tickets",
            description="Ce rôle aura accès à tous les tickets.",
            color=0x9B59B6,
        )
        await v.render_to(i, edit=True)

    async def _cb_logs(self, i):
        # Phase 5.2 fix : cohérence — la clé est 'ticket_log' (pas 'ticket_log_channel')
        # car le reste du code lit `c.get('ticket_log', 0)`.
        v = V2GenericChannelPicker(
            self.u, self.g,
            config_key='ticket_log',
            return_panel_factory=lambda: TicketMainPanelV2(self.u, self.g),
            title="📜 Salon des logs Tickets",
            description="Salon où sont enregistrés les événements tickets.",
            color=0x9B59B6,
        )
        await v.render_to(i, edit=True)

    async def _cb_blacklist(self, i):
        # Phase 3.0k : V2 native picker
        v = V2GenericRolePicker(
            self.u, self.g,
            config_key='ticket_blacklist_role',
            return_panel_factory=lambda: TicketMainPanelV2(self.u, self.g),
            title="🚫 Rôle /ticketblacklist",
            description="Ce rôle pourra utiliser /ticketblacklist. Aucun = seuls Staff et Admins.",
            color=0xE74C3C,
        )
        await v.render_to(i, edit=True)


    async def _cb_new(self, i):
        await i.response.send_modal(NewPanelModal(self.u, self.g))

    async def _cb_edit(self, i):
        c = await cfg(self.g.id)
        panels = c.get('ticket_panels', {})
        if not panels:
            return await i.response.send_message("❌ Aucun panel créé", ephemeral=True)
        opts = [discord.SelectOption(label=pd.get('name', pid)[:25], value=pid) for pid, pd in list(panels.items())[:25]]
        v = EditPanelSelectViewV2(self.u, self.g, opts)
        await v.render_to(i, edit=True)

    async def _cb_refresh(self, i):
        new_panel = TicketMainPanelV2(self.u, self.g)
        await new_panel.render_to(i, edit=True)

    async def _cb_back(self, i):
        v = MainPanelV2(self.u, self.g)
        await i.response.edit_message(view=v, embed=None, attachments=[])


class TkStaffView(View):
    def __init__(self, u, g, opts):
        super().__init__(timeout=120)
        self.add_item(TkStaffSel(u, g, opts))

class PaginatedRoleSelectForStaffGlobal(View):
    """Sélecteur de rôle staff global avec pagination"""
    def __init__(self, u, g, page=0):
        super().__init__(timeout=180)
        self.u = u
        self.g = g
        self.page = page
        self.roles = [r for r in g.roles[1:] if not r.is_bot_managed()]
        self.per_page = 24
        self.max_page = max(0, (len(self.roles) - 1) // self.per_page)
        self._build()
    
    def _build(self):
        self.clear_items()
        start = self.page * self.per_page
        end = start + self.per_page
        page_roles = self.roles[start:end]
        
        opts = []
        for r in page_roles:
            color_hex = f"#{r.color.value:06x}" if r.color.value else "Défaut"
            opts.append(discord.SelectOption(
                label=f"@{r.name}"[:25], 
                value=str(r.id),
                description=f"Couleur: {color_hex}"[:50]
            ))
        
        if opts:
            self.add_item(StaffGlobalRoleSelect(self, opts))
        
        # Boutons de pagination
        if self.page > 0:
            btn = discord.ui.Button(label="◀️ Page préc.", style=discord.ButtonStyle.secondary, row=1)
            btn.callback = self.prev_page
            self.add_item(btn)
        
        if self.page < self.max_page:
            btn = discord.ui.Button(label="▶️ Page suiv.", style=discord.ButtonStyle.secondary, row=1)
            btn.callback = self.next_page
            self.add_item(btn)
        
        back_btn = discord.ui.Button(label="◀️ Retour", style=discord.ButtonStyle.danger, row=1)
        back_btn.callback = self.go_back
        self.add_item(back_btn)
    
    async def prev_page(self, i):
        v = PaginatedRoleSelectForStaffGlobal(self.u, self.g, self.page - 1)
        embed = discord.Embed(
            title="👮 Choisir le rôle Staff", 
            description=f"**{len(self.roles)} rôles** disponibles • Page {self.page}/{self.max_page + 1}\n\nCe rôle aura accès à **tous** les tickets.",
            color=C.PURPLE
        )
        await i.response.edit_message(embed=embed, view=v)
    
    async def next_page(self, i):
        v = PaginatedRoleSelectForStaffGlobal(self.u, self.g, self.page + 1)
        embed = discord.Embed(
            title="👮 Choisir le rôle Staff", 
            description=f"**{len(self.roles)} rôles** disponibles • Page {self.page + 2}/{self.max_page + 1}\n\nCe rôle aura accès à **tous** les tickets.",
            color=C.PURPLE
        )
        await i.response.edit_message(embed=embed, view=v)
    
    async def go_back(self, i):
        v = TicketMainPanelV2(self.u, self.g)
        await v.render_to(i, edit=True)

