class SendPanelPaginatedView(LayoutView):
    """Sélecteur de salon paginé pour envoyer un panel de tickets.

    Phase 17 : converti de V1 View → V2 LayoutView pour éviter l'erreur
    `embeds field cannot be used when using MessageFlags.IS_COMPONENTS_V2`.
    Le panel parent (PanelEditViewV2) est V2, donc le child doit aussi être V2.
    """
    def __init__(self, u, g, pid, page=0):
        super().__init__(timeout=180)
        self.u = u
        self.g = g
        self.pid = pid
        self.page = page
        # Phase 17 : filtre les salons accessibles + tri par nom
        self.channels = sorted(
            [c for c in g.text_channels if c.permissions_for(g.me).view_channel],
            key=lambda c: (c.category.name if c.category else "ZZZ", c.position),
        )
        self.per_page = 23
        self.max_page = max(0, (len(self.channels) - 1) // self.per_page)
        self._build()

    async def interaction_check(self, i):
        return i.user.id == self.u.id

    def _build(self):
        self.clear_items()
        start = self.page * self.per_page
        end = start + self.per_page
        page_chs = self.channels[start:end]
        opts = [
            discord.SelectOption(
                label=f"# {c.name}"[:25],
                value=str(c.id),
                description=(c.category.name[:50] if c.category else "Sans catégorie"),
            )
            for c in page_chs
        ]

        items = [
            v2_title("📤 Envoyer le panel"),
            v2_subtitle(f"`{len(self.channels)}` salons accessibles · Page `{self.page+1}/{self.max_page+1}`"),
            v2_divider(),
            v2_body("Choisis le salon où le menu de création de tickets sera publié."),
            v2_divider(),
        ]

        if opts:
            select = Select(
                placeholder=f"Page {self.page+1}/{self.max_page+1} — Choisir le salon...",
                options=opts,
                custom_id=f"sppv2_select_{self.page}",
            )
            select.callback = self._select_cb
            items.append(discord.ui.ActionRow(select))
        else:
            items.append(v2_body("_Aucun salon accessible sur cette page._"))

        # Navigation pagination
        if self.max_page > 0:
            prev_btn = Button(
                label="◀️ Préc.",
                style=discord.ButtonStyle.secondary,
                disabled=(self.page == 0),
                custom_id="sppv2_prev",
            )
            prev_btn.callback = self._prev
            page_btn = Button(
                label=f"Page {self.page+1}/{self.max_page+1}",
                style=discord.ButtonStyle.secondary,
                disabled=True,
                custom_id="sppv2_pg",
            )
            next_btn = Button(
                label="Suiv. ▶️",
                style=discord.ButtonStyle.secondary,
                disabled=(self.page >= self.max_page),
                custom_id="sppv2_next",
            )
            next_btn.callback = self._next
            items.append(discord.ui.ActionRow(prev_btn, page_btn, next_btn))

        back_btn = Button(label="◀️ Retour", style=discord.ButtonStyle.secondary, custom_id="sppv2_back")
        back_btn.callback = self._back
        items.append(discord.ui.ActionRow(back_btn))

        self.add_item(v2_container(*items, color=Palette.ACCENT))

    async def render_to(self, interaction, *, edit=True):
        """V2 render — sans embed (V2 messages ne peuvent pas avoir d'embed)."""
        if edit:
            await interaction.response.edit_message(view=self, embed=None, attachments=[])
        else:
            await interaction.response.send_message(view=self, ephemeral=True)

    async def _prev(self, i):
        try:
            self.page -= 1
            self._build()
            await i.response.edit_message(view=self, embed=None, attachments=[])
        except Exception as ex:
            print(f"[SendPanel _prev] {ex}")
            try:
                if not i.response.is_done():
                    await i.response.defer()
            except Exception:
                pass

    async def _next(self, i):
        try:
            self.page += 1
            self._build()
            await i.response.edit_message(view=self, embed=None, attachments=[])
        except Exception as ex:
            print(f"[SendPanel _next] {ex}")
            try:
                if not i.response.is_done():
                    await i.response.defer()
            except Exception:
                pass

    async def _back(self, i):
        try:
            v = PanelEditViewV2(self.u, self.g, self.pid)
            await v.render_to(i, edit=True)
        except Exception as ex:
            print(f"[SendPanel _back] {ex}")
            try:
                if not i.response.is_done():
                    await i.response.send_message(f"❌ Erreur : `{ex}`", ephemeral=True)
            except Exception:
                pass

    async def _select_cb(self, i):
        # Phase 14 FIX : defer IMMÉDIAT pour éviter "Échec de l'interaction"
        # (ch.send peut prendre >3s, et l'interaction expire si on n'a pas ack)
        try:
            await i.response.defer(ephemeral=True)
        except (discord.InteractionResponded, discord.NotFound):
            pass

        try:
            ch = i.guild.get_channel(int(i.data['values'][0]))
            if not ch:
                return await i.followup.send("❌ Salon introuvable", ephemeral=True)

            # Vérifier les permissions du bot dans ce salon
            perms = ch.permissions_for(i.guild.me)
            if not (perms.send_messages and perms.embed_links):
                return await i.followup.send(
                    f"❌ Je n'ai pas les permissions pour envoyer un message ou des embeds dans {ch.mention}.\n"
                    "Vérifie que le bot a `Envoyer des messages` et `Intégrer des liens`.",
                    ephemeral=True,
                )

            c = await cfg(i.guild.id)
            pnl = c.get('ticket_panels', {}).get(self.pid, {})
            qs = pnl.get('questions', [])
            mx = pnl.get('max', 1)

            embed_title = pnl.get('embed_title', '').strip() or f"🎫 {pnl.get('name', 'Support')}"
            embed_desc = pnl.get('embed_description', '').strip() or "Cliquez sur le bouton ci-dessous pour créer un ticket."

            auto_info = ""
            if qs:
                auto_info += f"\n\n📝 Vous devrez répondre à **{len(qs)}** question(s)."
            auto_info += f"\n🔢 Maximum **{mx}** ticket(s) simultané(s)."

            full_desc = embed_desc + auto_info
            emb = discord.Embed(title=embed_title, description=full_desc, color=C.BLURPLE)

            embed_links = pnl.get('embed_links', '').strip()
            if embed_links:
                links_text = ""
                for line in embed_links.split('\n'):
                    line = line.strip()
                    if '|' in line:
                        parts = line.split('|', 1)
                        link_text = parts[0].strip()
                        link_url = parts[1].strip()
                        if link_url.startswith('http'):
                            links_text += f"[{link_text}]({link_url})\n"
                    elif line:
                        links_text += f"{line}\n"
                if links_text:
                    emb.add_field(name="🔗 Liens utiles", value=links_text.strip(), inline=False)

            sent_msg = await ch.send(embed=emb, view=TicketCreateView(self.pid))
            jump_url = f"https://discord.com/channels/{i.guild.id}/{ch.id}/{sent_msg.id}"
            await i.followup.send(
                f"✅ Panel envoyé dans {ch.mention} !\n[Voir le message]({jump_url})",
                ephemeral=True,
            )
        except discord.Forbidden as ex:
            print(f"[SendPanel _select_cb] Forbidden : {ex}")
            try:
                await i.followup.send(
                    f"❌ Permissions insuffisantes : `{ex}`",
                    ephemeral=True,
                )
            except Exception:
                pass
        except Exception as ex:
            print(f"[SendPanel _select_cb] {type(ex).__name__} : {ex}")
            import traceback; traceback.print_exc()
            try:
                await i.followup.send(
                    f"❌ Erreur : `{type(ex).__name__}: {ex}`",
                    ephemeral=True,
                )
            except Exception:
                pass

# Legacy compat
SendPanelView = SendPanelPaginatedView

