async def relay_discord_message(msg):
    """Relay un message vers les serveurs qui suivent ce salon"""
    try:
        channel_id = str(msg.channel.id)
        
        async with get_db() as db:
            async with db.execute('SELECT guild_id, data FROM guild_config') as cursor:
                async for row in cursor:
                    guild_id, data_str = row
                    if guild_id == msg.guild.id:
                        continue
                    
                    try:
                        data = json.loads(data_str) if data_str else {}
                        feeds = data.get('ads_discord_feeds', [])
                        dest_channel_id = data.get('ads_discord_channel', 0)
                        
                        is_followed = any(f['channel_id'] == channel_id for f in feeds)
                        if not is_followed or not dest_channel_id:
                            continue
                        
                        dest_guild = bot.get_guild(guild_id)
                        if not dest_guild:
                            continue
                        dest_channel = dest_guild.get_channel(dest_channel_id)
                        if not dest_channel:
                            continue
                        
                        # ═══════════════ EMBED DISCORD RELAY PROFESSIONNEL ═══════════════
                        e = discord.Embed(color=0x5865F2)
                        
                        # Auteur avec le nom du serveur
                        e.set_author(
                            name=f"📡 DISCORD • {msg.guild.name}",
                            icon_url=msg.guild.icon.url if msg.guild.icon else "https://discord.com/assets/847541504914fd33810e70a0ea73177e.ico"
                        )
                        
                        # Thumbnail avec avatar de l'auteur
                        if msg.author.display_avatar:
                            e.set_thumbnail(url=msg.author.display_avatar.url)
                        
                        # Info du message
                        e.add_field(
                            name="👤 Auteur",
                            value=f"**{msg.author.display_name}**",
                            inline=True
                        )
                        e.add_field(
                            name="📍 Salon",
                            value=f"#{msg.channel.name}",
                            inline=True
                        )
                        
                        # Contenu du message
                        content = msg.content[:1500] if msg.content else ""
                        if content:
                            e.add_field(
                                name="💬 Message",
                                value=content,
                                inline=False
                            )
                        
                        # Images
                        if msg.attachments:
                            for att in msg.attachments[:1]:
                                if att.content_type and att.content_type.startswith('image'):
                                    e.set_image(url=att.url)
                                    break
                        
                        e.set_footer(
                            text=f"Discord • {msg.guild.name}",
                            icon_url="https://discord.com/assets/847541504914fd33810e70a0ea73177e.ico"
                        )
                        e.timestamp = msg.created_at
                        
                        await webhook_send(dest_channel, 'discord_relay', embed=e)
                        
                    except:
                        continue
    except:
        pass

@bot.event
async def on_message(msg):
    if not msg.guild:
        return
    
    # ═══════════════ MESSAGES D'AIDE AUTOMATIQUES ═══════════════
    # Doit être appelé AVANT le filtre bot pour repositionner après les messages de bots
    # Mais on ignore le propre message du bot (éviter boucle infinie)
    if msg.author.id != bot.user.id:
        asyncio.create_task(handle_auto_help(msg))
    
    # Ignorer les bots pour le reste du traitement
    if msg.author.bot:
        return
    
    # Relay Discord - Vérifier si ce salon est suivi par d'autres serveurs
    await relay_discord_message(msg)
    
    # Mise à jour activité Realsy
    await update_realsy_activity(msg.guild.id, msg.author.id)
    
    # ═══════════════ SALON DE RÉCUPÉRATION D'ACTIVITÉ ═══════════════
    try:
        c = await cfg(msg.guild.id)
        stat_cfg = c.get('stat_config', {})
        recovery_ch_id = stat_cfg.get('recovery_channel', 0)

        # Si le message est dans le salon de récupération
        if recovery_ch_id and msg.channel.id == recovery_ch_id:
            await handle_recovery_message(msg, stat_cfg)
            return  # Ne pas traiter le reste
    except Exception as ex:
        print(f"[RECOVERY] Erreur vérification salon récupération: {ex}")
    
    # ═══════════════ TRACKING ACTIVITÉ MEMBRE ═══════════════
    await track_member_message(msg)

    # ═══════════════ AUTO-RÉACTIONS ═══════════════
    try:
        _ar_content = msg.content.lower().strip()
        if _ar_content and len(_ar_content) < 500:
            async with get_db() as _ar_db:
                async with _ar_db.execute(
                    'SELECT channel_id, trigger_type, trigger_text, emoji FROM auto_reactions WHERE guild_id=? AND enabled=1',
                    (msg.guild.id,)
                ) as _ar_cur:
                    _ar_rows = await _ar_cur.fetchall()

            for _ar_ch, _ar_type, _ar_trigger, _ar_emoji in _ar_rows:
                if _ar_ch and _ar_ch != msg.channel.id:
                    continue

                # Supporter les triggers multiples séparés par des virgules
                _ar_triggers = [t.strip() for t in _ar_trigger.split(',') if t.strip()]

                matched = False
                for _single_trigger in _ar_triggers:
                    if _ar_type == 'contains' and _single_trigger in _ar_content:
                        matched = True
                        break
                    elif _ar_type == 'startswith' and _ar_content.startswith(_single_trigger):
                        matched = True
                        break
                    elif _ar_type == 'exact' and _ar_content == _single_trigger:
                        matched = True
                        break

                if matched:
                    try:
                        await msg.add_reaction(_ar_emoji.strip())
                    except:
                        pass
    except:
        pass

    try:
        c = await cfg(msg.guild.id)
        ct = msg.content or ""
        chid = msg.channel.id
        gt = get_gif_type(msg)
        ag = c.get('image_allowed', [])
        iag = gt and gt in ag
        
        # ═══════════════ VÉRIFICATIONS D'IMMUNITÉ ═══════════════
        
        # 1. Salon immunisé = ignorer TOUTE l'automodération
        if await is_channel_immune(msg.guild.id, chid):
            # SAUF anti-phishing qui reste actif partout
            if c.get('anti_phishing'):
                f, d = check_phishing(ct)
                if f:
                    await msg.delete()
                    await send_log(msg.guild, 'anti_phishing', msg.author, msg, "Lien de phishing détecté", f"`{d}`")
                    await sanction(msg.author, c.get('phishing_action', 'delete'), 60, "Phishing", msg.guild)
            return
        
        # 2. Vérifier si c'est un ticket (immunité partielle)
        is_ticket = await is_ticket_channel(msg.channel)
        
        # 3. Vérifier immunité de l'utilisateur
        user_immune = await is_immune(msg.author, 'general', msg.channel)
        
        # ═══════════════ PROTECTIONS CRITIQUES (JAMAIS IGNORÉES) ═══════════════
        
        # Anti-phishing - TOUJOURS ACTIF pour TOUT LE MONDE
        if c.get('anti_phishing'):
            f, d = check_phishing(ct)
            if f:
                await msg.delete()
                await send_log(msg.guild, 'anti_phishing', msg.author, msg, "Lien de phishing détecté", f"`{d}`")
                dur = c.get('phishing_mute_duration', 60)
                await sanction(msg.author, c.get('phishing_action', 'delete'), dur, "Phishing", msg.guild)
                return

            # Vérifier les liens masqués en markdown [texte](url)
            f_mask, d_mask = check_masked_links(ct)
            if f_mask:
                await msg.delete()
                await send_log(msg.guild, 'anti_phishing', msg.author, msg, "Lien masqué détecté (phishing)", f"`{d_mask}`")
                dur = c.get('phishing_mute_duration', 60)
                await sanction(msg.author, c.get('phishing_action', 'delete'), dur, "Lien masqué phishing", msg.guild)
                return

            # Vérifier les URLs dans les embeds du message
            for emb in msg.embeds:
                for emb_url in [emb.url, getattr(emb.thumbnail, 'url', None), getattr(emb.image, 'url', None)]:
                    if emb_url:
                        f_emb, d_emb = check_phishing(emb_url)
                        if f_emb:
                            await msg.delete()
                            await send_log(msg.guild, 'anti_phishing', msg.author, msg, "Phishing dans embed", f"`{d_emb}`")
                            dur = c.get('phishing_mute_duration', 60)
                            await sanction(msg.author, c.get('phishing_action', 'delete'), dur, "Phishing embed", msg.guild)
                            return
        
        # Anti-scam - Actif même dans les tickets (protection contre les hacks)
        if c.get('anti_scam'):
            f, p = check_scam(ct)
            if f:
                await msg.delete()
                await send_log(msg.guild, 'anti_scam', msg.author, msg, "Message de scam détecté", f"`{p}`")
                dur = c.get('scam_mute_duration', 60)
                await sanction(msg.author, c.get('scam_action', 'mute'), dur, "Scam", msg.guild)
                return
        
        # Si utilisateur immunisé OU dans un ticket = ignorer les autres protections
        if user_immune or is_ticket:
            return  # Accès total (liens, images, etc.)
        
        # ═══════════════ PROTECTIONS STANDARD (IGNORÉES SI IMMUNISÉ) ═══════════════
        
        # Config salon spécifique (commandes uniquement, pas de messages, etc.)
        chcf = c.get('channel_configs', {}).get(str(chid))
        if chcf:
            # Vérifier les violations de config salon
            vio, vio_type = check_channel_cfg(msg, chcf)
            if vio:
                # Exception pour les GIFs autorisés globalement - ne pas bloquer si c'est un GIF autorisé
                if vio_type == "gifs" and iag:
                    pass  # GIF autorisé globalement, ne pas supprimer
                else:
                    try:
                        await msg.delete()
                    except discord.Forbidden:
                        pass  # Pas la permission de supprimer
                    except discord.NotFound:
                        pass  # Message déjà supprimé
                    except Exception as ex:
                        print(f"[CHANNEL_CFG] Erreur suppression: {ex}")
                    return
        
        # Anti-badwords
        if c.get('anti_badwords'):
            f, w = check_badwords(ct, c.get('badwords_list', []))
            if f:
                await msg.delete()
                await send_log(msg.guild, 'anti_badwords', msg.author, msg, "Mot interdit détecté", f"`{w}`")
                action = c.get('badwords_action', 'delete')
                dur = c.get('badwords_mute_duration', 5)
                await sanction(msg.author, action, dur, "Mot interdit", msg.guild)
                return

        # Anti-invite
        if c.get('anti_invite'):
            f, inv = check_invite(ct)
            if f:
                await msg.delete()
                await send_log(msg.guild, 'anti_invite', msg.author, msg, "Invitation Discord", f"`{inv}`")
                action = c.get('invite_action', 'delete')
                dur = c.get('invite_mute_duration', 5)
                await sanction(msg.author, action, dur, "Invitation Discord", msg.guild)
                return

        # Anti-link
        if c.get('anti_link') and not iag:
            if chid not in c.get('link_allowed_channels', []):
                f, url = check_link(ct, c.get('link_whitelist', []))
                if f:
                    await msg.delete()
                    await send_log(msg.guild, 'anti_link', msg.author, msg, "Lien non autorisé", f"`{url}`")
                    action = c.get('link_action', 'delete')
                    dur = c.get('link_mute_duration', 5)
                    await sanction(msg.author, action, dur, "Lien non autorisé", msg.guild)
                    return

        # Anti-image
        if c.get('anti_image') and not iag:
            if chid not in c.get('image_allowed_channels', []):
                bl = check_image(msg, c.get('image_allowed', []))
                if bl:
                    await msg.delete()
                    await send_log(msg.guild, 'anti_image', msg.author, msg, "Format non autorisé", f"`{', '.join(bl)}`")
                    action = c.get('image_action', 'delete')
                    dur = c.get('image_mute_duration', 5)
                    await sanction(msg.author, action, dur, "Format non autorisé", msg.guild)
                    return

        # Anti-spam
        if c.get('anti_spam'):
            if await check_spam(msg, c.get('spam_max', 5), c.get('spam_interval', 5)):
                await msg.delete()
                await send_log(msg.guild, 'anti_spam', msg.author, msg, "Spam détecté", None)
                dur = c.get('spam_mute_duration', 10)
                await sanction(msg.author, c.get('spam_action', 'mute'), dur, "Spam", msg.guild)
                return

        # Anti-caps
        if c.get('anti_caps'):
            if check_caps(ct, c.get('caps_percent', 70)):
                await msg.delete()
                await send_log(msg.guild, 'anti_caps', msg.author, msg, "Trop de majuscules", None)
                action = c.get('caps_action', 'delete')
                dur = c.get('caps_mute_duration', 5)
                await sanction(msg.author, action, dur, "Majuscules excessives", msg.guild)
                return

        # Anti-mass-mention (détecte @everyone/@here et spam de mentions)
        if c.get('anti_mass_mention'):
            max_mentions = c.get('mention_limit', 5)
            if check_mass_mention(msg, max_mentions):
                await msg.delete()
                mention_count = len(msg.mentions) + len(msg.role_mentions) + (1 if msg.mention_everyone else 0)
                await send_log(msg.guild, 'anti_mass_mention', msg.author, msg,
                              "Spam de mentions détecté", f"`{mention_count}` mentions")
                dur = c.get('mention_mute_duration', 10)
                await sanction(msg.author, c.get('mention_action', 'mute'), dur, "Mass mention", msg.guild)
                return

        # Anti-QRCode (détection de scams par QR code) - Actif pour tous
        if c.get('anti_qrcode'):
            is_qr_scam, qr_pattern = check_qr_code_scam(ct)
            if is_qr_scam:
                await msg.delete()
                await send_log(msg.guild, 'anti_qrcode', msg.author, msg,
                              "Scam QR Code détecté", f"Pattern: {qr_pattern}")
                dur = c.get('qrcode_mute_duration', 30)
                await sanction(msg.author, c.get('qrcode_action', 'mute'), dur, "Scam QR Code", msg.guild)
                return
        
        # Fichiers dangereux - Actif pour tous
        if msg.attachments:
            for att in msg.attachments:
                is_dangerous, ext = check_dangerous_file(att.filename)
                if is_dangerous:
                    await msg.delete()
                    await send_log(msg.guild, 'anti_phishing', msg.author, msg, 
                                  "Fichier dangereux détecté", f"Extension: {ext}")
                    warn_e = discord.Embed(color=0xE74C3C, description=f"⚠️ {msg.author.mention} a envoyé un fichier potentiellement dangereux (`{ext}`).\nLe fichier a été **supprimé** automatiquement.")
                    warn_e.set_footer(text="🛡️ Protection anti-phishing")
                    warn_msg = await webhook_send(msg.channel, 'protection', embed=warn_e)
                    if warn_msg:
                        async def _del_warn(m):
                            await asyncio.sleep(10)
                            try: await m.delete()
                            except: pass
                        asyncio.create_task(_del_warn(warn_msg))
                    return
        
    except: pass

