@bot.tree.command(name="afk", description="💤 Voir les membres AFK du serveur")
@app_commands.describe(jours="Nombre de jours d'inactivité minimum (défaut: 7)")
async def afk_cmd(i: discord.Interaction, jours: int = 7):
    """Commande /afk — Liste des membres inactifs"""
    ok, msg = await security_check(i, "afk")
    if not ok:
        return await i.response.send_message(msg, ephemeral=True)
    
    # Seuls les admins/owner peuvent voir la liste complète
    if not (i.user.guild_permissions.administrator or i.user.id == i.guild.owner_id):
        return await i.response.send_message("❌ Réservé aux administrateurs.", ephemeral=True)
    
    await i.response.defer(ephemeral=True)
    
    jours = max(1, min(jours, 365))
    cutoff = (now() - timedelta(days=jours)).replace(tzinfo=timezone.utc)
    afk_members = []
    
    try:
        async with get_db() as db:
            tracked = set()
            async with db.execute(
                'SELECT user_id, last_message, last_vocal, total_messages FROM activity_tracking WHERE guild_id=?',
                (i.guild.id,)
            ) as cursor:
                async for row in cursor:
                    uid = row[0]
                    tracked.add(uid)
                    la = None
                    for ts in [row[1], row[2]]:
                        if ts:
                            try:
                                dt = datetime.fromisoformat(ts).replace(tzinfo=timezone.utc)
                                if not la or dt > la: la = dt
                            except: pass
                    
                    if la and la < cutoff:
                        days_off = (now().replace(tzinfo=timezone.utc) - la).days
                        total_msg = row[3] if row[3] else 0
                        afk_members.append((uid, days_off, total_msg))
                    elif not la:
                        afk_members.append((uid, jours, 0))
            
            for m in i.guild.members:
                if not m.bot and m.id not in tracked and m.id != i.guild.owner_id:
                    days_since_join = (now().replace(tzinfo=timezone.utc) - m.joined_at.replace(tzinfo=timezone.utc)).days if m.joined_at else 999
                    afk_members.append((m.id, min(days_since_join, 999), 0))
    except Exception as ex:
        return await i.followup.send(f"❌ Erreur: {ex}", ephemeral=True)
    
    afk_members.sort(key=lambda x: x[1], reverse=True)
    
    # ─── Aucun membre AFK ───
    if not afk_members:
        empty_view = LayoutView(timeout=None)
        empty_items = []
        if i.guild.icon:
            empty_items.append(v2_section(
                v2_title(f"💤 AFK ({jours}j+)"),
                v2_body(f"🎉 Aucun membre inactif depuis **{jours}+ jours** !"),
                accessory=v2_thumb(i.guild.icon.url),
            ))
        else:
            empty_items.append(v2_title(f"💤 AFK ({jours}j+)"))
            empty_items.append(v2_body(f"🎉 Aucun membre inactif depuis **{jours}+ jours** !"))
        empty_view.add_item(v2_container(*empty_items, color=Palette.SUCCESS))
        return await i.followup.send(view=empty_view, ephemeral=True)

    # ─── Liste des AFK (max 45 affichés) ───
    afk_to_show = afk_members[:45]
    lines_out = []
    for idx, (uid, days, msgs) in enumerate(afk_to_show, 1):
        m = i.guild.get_member(uid)
        name = m.mention if m else f"`{uid}`"
        icon = "🔴" if days >= 30 else ("🟠" if days >= 14 else ("🟡" if days >= 7 else "⚪"))
        msg_txt = f" · `{msgs}` msgs" if msgs else ""
        lines_out.append(f"`{idx:>3}.` {icon} {name} — **{days}j**{msg_txt}")

    items_v2 = []
    if i.guild.icon:
        items_v2.append(v2_section(
            v2_title(f"💤 {len(afk_members)} membres AFK"),
            v2_body(f"Inactifs depuis **{jours}+ jours**"),
            accessory=v2_thumb(i.guild.icon.url),
        ))
    else:
        items_v2.append(v2_title(f"💤 {len(afk_members)} membres AFK"))
        items_v2.append(v2_subtitle(f"Inactifs depuis {jours}+ jours"))
    items_v2.append(v2_divider())
    items_v2.append(v2_body("\n".join(lines_out)))

    # Indication si plus de 45 membres
    if len(afk_members) > 45:
        items_v2.append(v2_divider())
        items_v2.append(v2_subtitle(f"+ {len(afk_members) - 45} autres membres non affichés"))

    items_v2.append(v2_divider())
    items_v2.append(v2_subtitle("🔴 30j+  ·  🟠 14j+  ·  🟡 7j+  ·  ⚪ < 7j"))

    view = LayoutView(timeout=None)
    view.add_item(v2_container(*items_v2, color=Palette.DANGER))
    await i.followup.send(view=view, ephemeral=True)

@bot.tree.command(name="stat", description="📊 Voir les statistiques d'activité d'un membre")
@app_commands.describe(membre="Le membre dont vous voulez voir les stats (vous par défaut)")
async def stat_cmd(i: discord.Interaction, membre: discord.Member = None):
    if not await check_command_channel(i, 'stat'):
        return

    target = membre or i.user
    if target.bot:
        return await i.response.send_message("❌ Les bots n'ont pas de statistiques", ephemeral=True)

    await i.response.defer()

    stats = await get_member_stats(i.guild, target, 7)
    items, _ = build_stat_v2_data(i.guild, target, stats, 7)

    # Génère le graphique synthèse et l'ajoute en MediaGallery
    file = None
    img = await generate_stat_graph(stats, 7, target.display_name)
    if img:
        file = discord.File(img, filename="stats.png")
        items.append(v2_divider())
        items.append(discord.ui.MediaGallery(
            discord.MediaGalleryItem(media="attachment://stats.png")
        ))

    view = StatV2View(i.user, i.guild, target, period=7)
    view.rebuild(items)

    if file:
        await i.followup.send(view=view, file=file)
    else:
        await i.followup.send(view=view)


def build_stat_v2_data(guild, member, stats, days):
    """Construit la liste d'items V2 + l'éventuelle pièce jointe (graphique).

    Renvoie (items_list, discord.File | None).
    """
    items: list = [
        v2_section(
            v2_title(f"📊 Statistiques de {member.display_name}"),
            v2_body(f"Période : **{days}** dernier{'s' if days > 1 else ''} jour{'s' if days > 1 else ''}"),
            accessory=v2_thumb(member.display_avatar.url if member.display_avatar else member.default_avatar.url),
        ),
        v2_divider(),
    ]

    # Stats principales
    vocal_time = stats['total_vocal_time']
    if vocal_time >= 3600:
        time_str = f"{vocal_time // 3600}h {(vocal_time % 3600) // 60}min"
    elif vocal_time >= 60:
        time_str = f"{vocal_time // 60}min {vocal_time % 60}s"
    else:
        time_str = f"{vocal_time}s"
    avg_messages = stats['total_messages'] / days if days > 0 else 0
    items.append(v2_body(
        f"💬 **Messages** · `{stats['total_messages']:,}`\n"
        f"🔊 **Temps vocal** · `{time_str}`\n"
        f"📈 **Moyenne** · `{avg_messages:.1f}` msg/jour"
    ))

    # Salons favoris
    items.append(v2_divider())
    fav_lines = []
    if stats['channels_messages']:
        top_ch_id = max(stats['channels_messages'], key=stats['channels_messages'].get)
        top_ch = guild.get_channel(top_ch_id)
        top_count = stats['channels_messages'][top_ch_id]
        fav_lines.append(f"📝 **Salon écrit favori** · {top_ch.mention if top_ch else '`Inconnu`'} (`{top_count}` messages)")
    else:
        fav_lines.append("📝 **Salon écrit favori** · _Aucune donnée_")

    if stats['channels_vocal']:
        top_vc_id = max(stats['channels_vocal'], key=stats['channels_vocal'].get)
        top_vc = guild.get_channel(top_vc_id)
        top_duration = stats['channels_vocal'][top_vc_id]
        if top_duration >= 3600:
            dur_str = f"{top_duration // 3600}h {(top_duration % 3600) // 60}min"
        elif top_duration >= 60:
            dur_str = f"{top_duration // 60}min"
        else:
            dur_str = f"{top_duration}s"
        fav_lines.append(f"🎤 **Salon vocal favori** · `{top_vc.name if top_vc else 'Inconnu'}` (`{dur_str}`)")
    else:
        fav_lines.append("🎤 **Salon vocal favori** · _Aucune donnée_")
    items.append(v2_body("\n".join(fav_lines)))

    # Dernière activité
    items.append(v2_divider())
    if stats['last_activity']:
        items.append(v2_body(f"🕐 **Dernière activité** · <t:{int(stats['last_activity'].timestamp())}:R>"))
    else:
        items.append(v2_body("🕐 **Dernière activité** · _Inconnue_"))

    # Message populaire
    if stats['most_popular_message']:
        mp = stats['most_popular_message']
        items.append(v2_divider())
        items.append(v2_title(f"⭐ Message populaire ({mp['reactions']} réactions)", level=3))
        items.append(v2_body(f"_« {mp['content']} »_\n[→ Voir le message]({mp['url']})"))

    # Le graphique est généré et ajouté par l'appelant (build_stat_v2_data est sync,
    # generate_stat_graph est async). Ce return ne fournit que les items texte.
    return items, None


class StatV2View(LayoutView):
    """Vue interactive des stats — boutons 7j/30j + graphique détaillé."""

    def __init__(self, user, guild, target, period: int = 7):
        super().__init__(timeout=300)
        self.user = user
        self.guild = guild
        self.target = target
        self.period = period

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.user.id:
            await interaction.response.send_message("❌ Ce panneau ne vous appartient pas", ephemeral=True)
            return False
        return True

    def rebuild(self, items: list):
        """Reconstruit le LayoutView avec les items + l'ActionRow de boutons."""
        self.clear_items()

        # Bouton 7j
        b7 = Button(
            label="📅 7 Jours",
            style=discord.ButtonStyle.primary,
            disabled=(self.period == 7),
            custom_id="stat_v2_7d",
        )
        b7.callback = self._cb_7d

        # Bouton 30j
        b30 = Button(
            label="📅 30 Jours",
            style=discord.ButtonStyle.primary,
            disabled=(self.period == 30),
            custom_id="stat_v2_30d",
        )
        b30.callback = self._cb_30d

        # Bouton graphique détaillé
        bg = Button(
            label="📈 Graphique Détaillé",
            style=discord.ButtonStyle.success,
            custom_id="stat_v2_graph",
        )
        bg.callback = self._cb_graph

        action_row = discord.ui.ActionRow(b7, b30, bg)

        # Container final = items du build + ActionRow à la fin
        self.add_item(v2_container(*items, action_row, color=Palette.ACCENT))

    async def _refresh(self, interaction: discord.Interaction):
        """Recharge les stats avec la nouvelle période et re-render."""
        await interaction.response.defer()
        stats = await get_member_stats(self.guild, self.target, self.period)
        items, file = build_stat_v2_data(self.guild, self.target, stats, self.period)

        # Générer le graphique synthèse
        img = await generate_stat_graph(stats, self.period, self.target.display_name)
        if img:
            file = discord.File(img, filename="stats.png")
            items.append(v2_divider())
            items.append(discord.ui.MediaGallery(
                discord.MediaGalleryItem(media="attachment://stats.png")
            ))

        self.rebuild(items)

        if file:
            try:
                await interaction.message.delete()
            except Exception:
                pass
            await interaction.followup.send(view=self, file=file)
        else:
            await interaction.message.edit(view=self, attachments=[])

    async def _cb_7d(self, interaction: discord.Interaction):
        self.period = 7
        await self._refresh(interaction)

    async def _cb_30d(self, interaction: discord.Interaction):
        self.period = 30
        await self._refresh(interaction)

    async def _cb_graph(self, interaction: discord.Interaction):
        await interaction.response.defer(ephemeral=True)
        img = await generate_detailed_stat_graph(self.guild, self.target, self.period)
        if not img:
            return await interaction.followup.send(
                "❌ Pas assez de données pour générer un graphique détaillé",
                ephemeral=True,
            )
        file = discord.File(img, filename="stats_detailed.png")
        view = LayoutView(timeout=None)
        view.add_item(v2_container(
            v2_title(f"📊 Statistiques détaillées — {self.target.display_name}"),
            v2_subtitle(f"Période : {self.period} jours · {self.guild.name}"),
            v2_divider(),
            discord.ui.MediaGallery(
                discord.MediaGalleryItem(media="attachment://stats_detailed.png")
            ),
            color=Palette.ACCENT,
        ))
        await interaction.followup.send(view=view, file=file, ephemeral=True)

async def get_member_stats(guild, member, days):
    """Récupère les statistiques d'un membre sur une période donnée"""
    stats = {
        'total_messages': 0,
        'total_vocal_time': 0,
        'channels_messages': {},  # {channel_id: count}
        'channels_vocal': {},  # {channel_id: duration}
        'messages_per_day': {},  # {date: count}
        'vocal_per_day': {},  # {date: duration}
        'most_popular_message': None,
        'first_activity': None,
        'last_activity': None
    }
    
    try:
        cutoff = now() - timedelta(days=days)
        cutoff_str = cutoff.isoformat()
        
        async with get_db() as db:
            # Récupérer les messages
            async with db.execute('''
                SELECT channel_id, message_id, created_at FROM member_activity 
                WHERE guild_id=? AND user_id=? AND activity_type='message' AND created_at >= ?
                ORDER BY created_at ASC
            ''', (guild.id, member.id, cutoff_str)) as cursor:
                async for row in cursor:
                    ch_id, msg_id, created_at = row
                    stats['total_messages'] += 1
                    
                    # Par salon
                    stats['channels_messages'][ch_id] = stats['channels_messages'].get(ch_id, 0) + 1
                    
                    # Par jour
                    try:
                        dt = datetime.fromisoformat(created_at)
                        date_key = dt.strftime('%Y-%m-%d')
                        stats['messages_per_day'][date_key] = stats['messages_per_day'].get(date_key, 0) + 1
                        
                        if not stats['first_activity'] or dt < stats['first_activity']:
                            stats['first_activity'] = dt
                        if not stats['last_activity'] or dt > stats['last_activity']:
                            stats['last_activity'] = dt
                    except:
                        pass
            
            # Récupérer les sessions vocales
            async with db.execute('''
                SELECT channel_id, duration, created_at FROM member_activity 
                WHERE guild_id=? AND user_id=? AND activity_type='vocal' AND created_at >= ?
                ORDER BY created_at ASC
            ''', (guild.id, member.id, cutoff_str)) as cursor:
                async for row in cursor:
                    ch_id, duration, created_at = row
                    stats['total_vocal_time'] += duration or 0
                    
                    # Par salon
                    stats['channels_vocal'][ch_id] = stats['channels_vocal'].get(ch_id, 0) + (duration or 0)
                    
                    # Par jour
                    try:
                        dt = datetime.fromisoformat(created_at)
                        date_key = dt.strftime('%Y-%m-%d')
                        stats['vocal_per_day'][date_key] = stats['vocal_per_day'].get(date_key, 0) + (duration or 0)
                        
                        if not stats['first_activity'] or dt < stats['first_activity']:
                            stats['first_activity'] = dt
                        if not stats['last_activity'] or dt > stats['last_activity']:
                            stats['last_activity'] = dt
                    except:
                        pass
        
        # Trouver le message le plus populaire (avec le plus de réactions)
        # On cherche dans les derniers messages du membre
        if stats['channels_messages']:
            top_channel_id = max(stats['channels_messages'], key=stats['channels_messages'].get)
            channel = guild.get_channel(top_channel_id)
            if channel:
                try:
                    async for msg in channel.history(limit=100):
                        if msg.author.id == member.id:
                            reaction_count = sum(r.count for r in msg.reactions) if msg.reactions else 0
                            if reaction_count > 0:
                                if not stats['most_popular_message'] or reaction_count > stats['most_popular_message']['reactions']:
                                    stats['most_popular_message'] = {
                                        'content': msg.content[:100] + "..." if len(msg.content) > 100 else msg.content,
                                        'reactions': reaction_count,
                                        'url': msg.jump_url
                                    }
                except:
                    pass
                    
    except Exception as ex:
        print(f"Erreur get_member_stats: {ex}")
    
    return stats

# create_stat_embed retiré : remplacé par build_stat_v2_data() en V2.


async def generate_stat_graph(stats, days, username):
    """Génère un graphique des statistiques"""
    try:
        if not stats['messages_per_day'] and not stats['vocal_per_day']:
            return None
        
        # Préparer les données pour tous les jours de la période
        dates = []
        messages = []
        vocal = []
        
        for i in range(days):
            dt = now() - timedelta(days=days-1-i)
            date_key = dt.strftime('%Y-%m-%d')
            dates.append(dt.strftime('%d/%m'))
            messages.append(stats['messages_per_day'].get(date_key, 0))
            vocal.append(stats['vocal_per_day'].get(date_key, 0) / 60)  # Convertir en minutes
        
        # Créer le graphique
        fig, ax1 = plt.subplots(figsize=(12, 5))
        fig.patch.set_facecolor('#2f3136')
        ax1.set_facecolor('#36393f')
        
        # Barres pour les messages
        x = range(len(dates))
        bars = ax1.bar([i - 0.2 for i in x], messages, 0.4, label='Messages', color='#5865F2', alpha=0.8)
        ax1.set_xlabel('Date', color='white', fontsize=10)
        ax1.set_ylabel('Messages', color='#5865F2', fontsize=10)
        ax1.tick_params(axis='y', labelcolor='#5865F2')
        ax1.tick_params(axis='x', colors='white')
        
        # Deuxième axe pour le vocal
        ax2 = ax1.twinx()
        bars2 = ax2.bar([i + 0.2 for i in x], vocal, 0.4, label='Vocal (min)', color='#57F287', alpha=0.8)
        ax2.set_ylabel('Minutes en vocal', color='#57F287', fontsize=10)
        ax2.tick_params(axis='y', labelcolor='#57F287')
        
        # Style
        ax1.set_xticks(x)
        ax1.set_xticklabels(dates, rotation=45, ha='right', fontsize=8)
        ax1.spines['bottom'].set_color('white')
        ax1.spines['left'].set_color('#5865F2')
        ax1.spines['top'].set_visible(False)
        ax2.spines['right'].set_color('#57F287')
        ax2.spines['top'].set_visible(False)
        
        # Titre
        plt.title(f'📊 Activité de {username}', color='white', fontsize=14, fontweight='bold', pad=15)
        
        # Légende
        fig.legend(loc='upper right', bbox_to_anchor=(0.98, 0.98), facecolor='#36393f', edgecolor='white', labelcolor='white')
        
        plt.tight_layout()
        
        # Sauvegarder
        buf = io.BytesIO()
        plt.savefig(buf, format='png', facecolor='#2f3136', edgecolor='none', dpi=100)
        buf.seek(0)
        plt.close(fig)
        
        return buf
        
    except Exception as ex:
        print(f"Erreur génération graphique: {ex}")
        return None

async def generate_detailed_stat_graph(guild, member, days):
    """Génère un graphique détaillé avec plusieurs visualisations"""
    try:
        stats = await get_member_stats(guild, member, days)
        
        if not stats['total_messages'] and not stats['total_vocal_time']:
            return None
        
        fig, axes = plt.subplots(2, 2, figsize=(14, 10))
        fig.patch.set_facecolor('#2f3136')
        
        # 1. Camembert des salons écrits (haut gauche)
        ax1 = axes[0, 0]
        ax1.set_facecolor('#2f3136')
        
        if stats['channels_messages']:
            # Top 5 salons
            sorted_channels = sorted(stats['channels_messages'].items(), key=lambda x: x[1], reverse=True)[:5]
            labels = []
            sizes = []
            for ch_id, count in sorted_channels:
                ch = guild.get_channel(ch_id)
                labels.append(f"#{ch.name[:15]}" if ch else f"#{ch_id}")
                sizes.append(count)
            
            colors = ['#5865F2', '#57F287', '#FEE75C', '#ED4245', '#9B59B6']
            ax1.pie(sizes, labels=labels, colors=colors[:len(sizes)], autopct='%1.1f%%',
                   textprops={'color': 'white', 'fontsize': 9})
            ax1.set_title('📝 Top Salons Écrits', color='white', fontsize=12, fontweight='bold')
        else:
            ax1.text(0.5, 0.5, 'Aucune donnée', ha='center', va='center', color='white', fontsize=12)
            ax1.set_title('📝 Top Salons Écrits', color='white', fontsize=12, fontweight='bold')
        
        # 2. Camembert des salons vocaux (haut droit)
        ax2 = axes[0, 1]
        ax2.set_facecolor('#2f3136')
        
        if stats['channels_vocal']:
            sorted_vocal = sorted(stats['channels_vocal'].items(), key=lambda x: x[1], reverse=True)[:5]
            labels = []
            sizes = []
            for ch_id, duration in sorted_vocal:
                ch = guild.get_channel(ch_id)
                labels.append(f"🔊 {ch.name[:15]}" if ch else f"🔊 {ch_id}")
                sizes.append(duration)
            
            colors = ['#57F287', '#5865F2', '#FEE75C', '#ED4245', '#9B59B6']
            ax2.pie(sizes, labels=labels, colors=colors[:len(sizes)], autopct='%1.1f%%',
                   textprops={'color': 'white', 'fontsize': 9})
            ax2.set_title('🎤 Top Salons Vocaux', color='white', fontsize=12, fontweight='bold')
        else:
            ax2.text(0.5, 0.5, 'Aucune donnée', ha='center', va='center', color='white', fontsize=12)
            ax2.set_title('🎤 Top Salons Vocaux', color='white', fontsize=12, fontweight='bold')
        
        # 3. Courbe d'activité messages (bas gauche)
        ax3 = axes[1, 0]
        ax3.set_facecolor('#36393f')
        
        dates = []
        messages = []
        for i in range(days):
            dt = now() - timedelta(days=days-1-i)
            date_key = dt.strftime('%Y-%m-%d')
            dates.append(dt.strftime('%d/%m'))
            messages.append(stats['messages_per_day'].get(date_key, 0))
        
        ax3.fill_between(range(len(dates)), messages, alpha=0.3, color='#5865F2')
        ax3.plot(range(len(dates)), messages, color='#5865F2', linewidth=2, marker='o', markersize=4)
        ax3.set_xlabel('Date', color='white', fontsize=10)
        ax3.set_ylabel('Messages', color='white', fontsize=10)
        ax3.set_title('💬 Messages par jour', color='white', fontsize=12, fontweight='bold')
        ax3.tick_params(colors='white')
        ax3.set_xticks(range(0, len(dates), max(1, len(dates)//7)))
        ax3.set_xticklabels([dates[i] for i in range(0, len(dates), max(1, len(dates)//7))], rotation=45, fontsize=8)
        ax3.spines['bottom'].set_color('white')
        ax3.spines['left'].set_color('white')
        ax3.spines['top'].set_visible(False)
        ax3.spines['right'].set_visible(False)
        ax3.grid(True, alpha=0.2, color='white')
        
        # 4. Courbe d'activité vocale (bas droit)
        ax4 = axes[1, 1]
        ax4.set_facecolor('#36393f')
        
        vocal = []
        for i in range(days):
            dt = now() - timedelta(days=days-1-i)
            date_key = dt.strftime('%Y-%m-%d')
            vocal.append(stats['vocal_per_day'].get(date_key, 0) / 60)  # En minutes
        
        ax4.fill_between(range(len(dates)), vocal, alpha=0.3, color='#57F287')
        ax4.plot(range(len(dates)), vocal, color='#57F287', linewidth=2, marker='o', markersize=4)
        ax4.set_xlabel('Date', color='white', fontsize=10)
        ax4.set_ylabel('Minutes', color='white', fontsize=10)
        ax4.set_title('🎤 Temps vocal par jour', color='white', fontsize=12, fontweight='bold')
        ax4.tick_params(colors='white')
        ax4.set_xticks(range(0, len(dates), max(1, len(dates)//7)))
        ax4.set_xticklabels([dates[i] for i in range(0, len(dates), max(1, len(dates)//7))], rotation=45, fontsize=8)
        ax4.spines['bottom'].set_color('white')
        ax4.spines['left'].set_color('white')
        ax4.spines['top'].set_visible(False)
        ax4.spines['right'].set_visible(False)
        ax4.grid(True, alpha=0.2, color='white')
        
        # Titre principal
        fig.suptitle(f'📊 Statistiques détaillées de {member.display_name}', 
                    color='white', fontsize=16, fontweight='bold', y=0.98)
        
        plt.tight_layout(rect=[0, 0, 1, 0.96])
        
        # Sauvegarder
        buf = io.BytesIO()
        plt.savefig(buf, format='png', facecolor='#2f3136', edgecolor='none', dpi=100)
        buf.seek(0)
        plt.close(fig)
        
        return buf
        
    except Exception as ex:
        print(f"Erreur génération graphique détaillé: {ex}")
        return None

