#                           🎁 TÂCHE AUTOMATIQUE GIVEAWAYS
# ═══════════════════════════════════════════════════════════════════════════════

@tasks.loop(seconds=30)
async def check_giveaways():
    """Vérifie et termine les giveaways expirés"""
    try:
        now_dt = now()
        
        async with get_db() as db:
            # Récupérer les giveaways à terminer
            async with db.execute(
                'SELECT id, guild_id, channel_id, message_id, title, prize, participants FROM giveaways WHERE ended=0 AND end_time <= ?',
                (now_dt.isoformat(),)
            ) as cursor:
                giveaways_to_end = []
                async for row in cursor:
                    giveaways_to_end.append(row)
            
            # Terminer chaque giveaway
            for gw_id, guild_id, channel_id, message_id, title, prize, participants_str in giveaways_to_end:
                try:
                    guild = bot.get_guild(guild_id)
                    if not guild:
                        continue
                    
                    channel = guild.get_channel(channel_id)
                    if not channel:
                        continue
                    
                    participants = json.loads(participants_str) if participants_str else []
                    
                    # Marquer comme terminé
                    await db.execute('UPDATE giveaways SET ended=1 WHERE id=?', (gw_id,))
                    
                    if not participants:
                        # Pas de participants
                        e = discord.Embed(color=0xE74C3C)
                        e.set_author(name="🎁 GIVEAWAY TERMINÉ", icon_url=guild.icon.url if guild.icon else None)
                        e.title = title
                        e.description = (
                            f"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n"
                            f"❌ **Aucun participant !**\n"
                            f"Le cadeau n'a pas pu être attribué.\n"
                            f"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━"
                        )
                        e.set_footer(text="Giveaway terminé")
                        e.timestamp = now()
                        
                        try:
                            await webhook_edit(channel, 'giveaway', message_id, embed=e, view=None)
                        except:
                            pass
                    else:
                        # Tirer un gagnant
                        import random
                        winner_id = random.choice(participants)
                        winner = guild.get_member(winner_id)
                        winner_txt = winner.mention if winner else f'<@{winner_id}>'
                        
                        e = discord.Embed(color=0xF1C40F)
                        e.set_author(name="🎁 GIVEAWAY TERMINÉ", icon_url=guild.icon.url if guild.icon else None)
                        e.title = title
                        e.description = (
                            f"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━\n"
                            f"🏆 **Gagnant :** {winner_txt}\n"
                            f"🎁 **Prix :** `{prize}`\n"
                            f"👥 **Participants :** `{len(participants)}`\n"
                            f"━━━━━━━━━━━━━━━━━━━━━━━━━━━━━━"
                        )
                        e.set_footer(text="🎉 Félicitations au gagnant !")
                        e.timestamp = now()
                        
                        try:
                            await webhook_edit(channel, 'giveaway', message_id, embed=e, view=None)
                            
                            win_e = discord.Embed(color=0xF1C40F)
                            win_e.set_author(name="🎉 GAGNANT ANNONCÉ !", icon_url=guild.icon.url if guild.icon else None)
                            win_e.description = (
                                f"Félicitations {winner_txt} !\n\n"
                                f"Tu as gagné **{title}** 🏆\n"
                                f"Prix : `{prize}`"
                            )
                            if winner and winner.display_avatar:
                                win_e.set_thumbnail(url=winner.display_avatar.url)
                            win_e.set_footer(text=f"Merci aux {len(participants)} participants !")
                            win_e.timestamp = now()
                            await webhook_send(channel, 'giveaway', embed=win_e)
                        except:
                            pass
                    
                except Exception as ex:
                    print(f"Erreur fin giveaway {gw_id}: {ex}")
            
            await db.commit()
            
    except Exception as ex:
        print(f"Erreur tâche giveaways: {ex}")

@check_giveaways.before_loop
async def before_check_giveaways():
    await bot.wait_until_ready()

# ═══════════════════════════════════════════════════════════════════════════════
#                           📨 TÂCHE AUTOMATIQUE MESSAGES PROGRAMMÉS
# ═══════════════════════════════════════════════════════════════════════════════

@tasks.loop(minutes=1)
async def check_scheduled_messages():
    """Vérifie et envoie les messages programmés"""
    try:
        now_dt = now()
        current_hour = now_dt.hour
        current_minute = now_dt.minute
        
        async with get_db() as db:
            # Récupérer tous les messages actifs
            async with db.execute(
                'SELECT id, guild_id, channel_id, title, description, color, image_url, footer, frequency, frequency_value, send_hour, send_minute, last_sent FROM scheduled_messages WHERE enabled=1'
            ) as cursor:
                messages = []
                async for row in cursor:
                    messages.append(row)
            
            for msg_id, guild_id, channel_id, title, description, color, image_url, footer, frequency, freq_val, send_hour, send_minute, last_sent_str in messages:
                try:
                    # Calculer l'intervalle minimum selon la fréquence
                    if frequency == 'minutes':
                        min_interval = timedelta(minutes=max(1, freq_val))
                    elif frequency == 'hourly':
                        min_interval = timedelta(hours=max(1, freq_val))
                    elif frequency == 'daily':
                        min_interval = timedelta(days=max(1, freq_val))
                    elif frequency == 'weekly':
                        min_interval = timedelta(weeks=max(1, freq_val))
                    else:
                        continue

                    # Pour daily/weekly: vérifier heure ET minute exactes
                    # Pour minutes/hourly: pas de gate horaire, on utilise seulement l'intervalle
                    if frequency in ('daily', 'weekly'):
                        if current_hour != send_hour or current_minute != send_minute:
                            continue

                    # Vérifier le dernier envoi (intervalle minimum)
                    if last_sent_str:
                        try:
                            last_sent = datetime.fromisoformat(last_sent_str)
                            if now_dt - last_sent < min_interval:
                                continue
                        except:
                            pass
                    
                    # Envoyer le message
                    guild = bot.get_guild(guild_id)
                    if not guild:
                        continue
                    
                    channel = guild.get_channel(channel_id)
                    if not channel:
                        continue
                    
                    # Créer l'embed
                    try:
                        embed_color = int(color.replace('#', ''), 16) if color else C.BLURPLE
                    except:
                        embed_color = C.BLURPLE
                    
                    e = discord.Embed(title=title, description=description, color=embed_color)
                    
                    if image_url:
                        e.set_image(url=image_url)
                    
                    if footer:
                        e.set_footer(text=footer)
                    
                    e.timestamp = now()
                    
                    await webhook_send(channel, 'auto_message', embed=e)
                    
                    # Mettre à jour last_sent
                    await db.execute(
                        'UPDATE scheduled_messages SET last_sent=? WHERE id=?',
                        (now_dt.isoformat(), msg_id)
                    )
                    
                except Exception as ex:
                    print(f"Erreur message programmé {msg_id}: {ex}")
            
            await db.commit()
            
    except Exception as ex:
        print(f"Erreur tâche messages programmés: {ex}")

@check_scheduled_messages.before_loop
async def before_check_scheduled_messages():
    await bot.wait_until_ready()

# ═══════════════════════════════════════════════════════════════════════════════
#                           📈 COMMANDES NIVEAU & BOUTIQUE
# ═══════════════════════════════════════════════════════════════════════════════

async def check_level_channel(i):
    """Vérifie si la commande peut être utilisée dans ce salon"""
    c = await cfg(i.guild.id)
    level_cfg = c.get('level_config', {})
    allowed = level_cfg.get('allowed_channels', [])
    
    if allowed and i.channel.id not in allowed:
        mentions = ", ".join([f"<#{ch}>" for ch in allowed[:3]])
        await i.response.send_message(f"❌ Cette commande n'est utilisable que dans: {mentions}", ephemeral=True)
        return False
    return True

def create_progress_bar(current, total, length=20):
    """Crée une barre de progression visuelle"""
    filled = int(length * current / total) if total > 0 else 0
    empty = length - filled
    return "█" * filled + "░" * empty

@bot.tree.command(name="level", description="📈 Voir votre progression de niveau")
@app_commands.describe(membre="Le membre dont vous voulez voir le niveau")
async def level_cmd(i: discord.Interaction, membre: discord.Member = None):
    # Vérifier le salon
    if not await check_level_channel(i):
        return

    # Vérifier si le système est activé
    c = await cfg(i.guild.id)
    level_cfg = c.get('level_config', {})
    if not level_cfg.get('enabled', False):
        return await i.response.send_message("❌ Le système de niveaux n'est pas activé", ephemeral=True)

    target = membre or i.user
    eco = await get_user_economy(i.guild.id, target.id)

    current_level = eco['level']
    current_xp = eco['xp']
    xp_progress = current_xp % 100 if current_level > 1 else current_xp
    xp_needed = 100
    progress_bar = create_progress_bar(xp_progress, xp_needed)
    percentage = int((xp_progress / xp_needed) * 100) if xp_needed > 0 else 0

    # Prochaine récompense de rôle
    async with get_db() as db:
        async with db.execute(
            'SELECT level, role_id FROM level_rewards WHERE guild_id=? AND level > ? ORDER BY level LIMIT 1',
            (i.guild.id, current_level)
        ) as cursor:
            next_reward = await cursor.fetchone()

    # ─── Construction du LayoutView V2 ───
    items = [
        v2_section(
            v2_title(f"📈 Niveau de {target.display_name}"),
            v2_body(f"🏆 Niveau **{current_level}**  ·  ✨ **{current_xp} XP**  ·  🪙 **{eco['coins']} pièces**"),
            accessory=v2_thumb(target.display_avatar.url),
        ),
        v2_divider(),
        v2_title(f"Progression — niveau {current_level + 1}", level=2),
        v2_body(f"`{progress_bar}` **{percentage}%**"),
        v2_subtitle(f"{xp_progress} / {xp_needed} XP avant le prochain niveau"),
    ]

    if next_reward:
        role = i.guild.get_role(next_reward[1])
        if role:
            items.append(v2_divider())
            items.append(v2_title("🎁 Prochain rôle débloqué", level=3))
            items.append(v2_body(f"Niveau **{next_reward[0]}** → {role.mention}"))

    items.append(v2_divider())
    items.append(v2_subtitle(f"Gain : {level_cfg.get('xp_per_message', 15)} XP par message"))

    view = LayoutView(timeout=None)
    view.add_item(v2_container(*items, color=Palette.PRIMARY))
    await i.response.send_message(view=view)

@bot.tree.command(name="shop", description="🛒 Ouvrir la boutique")
async def shop_cmd(i: discord.Interaction):
    # Vérifier le salon
    if not await check_level_channel(i):
        return

