class ShopV2View(LayoutView):
    """Boutique V2 — Container + ActionRow(Select) en un seul LayoutView."""

    def __init__(self, user, guild, items, coins):
        super().__init__(timeout=120)
        self.user = user
        self.guild = guild
        self.items = items
        self.coins = coins

        # Lignes d'affichage des articles (max 10 visibles)
        item_lines = []
        for idx, item in enumerate(items[:10]):
            role = guild.get_role(item.get('role_id', 0))
            price = item.get('price', 0)
            duration = item.get('duration', 3600)
            dur_txt = format_duration(duration)
            mark = "✅" if coins >= price else "❌"
            item_lines.append(
                f"{mark} **{role.name if role else '?'}** · `{price:,}` 🪙 · {dur_txt}"
            )

        # Options du Select (max 25 selon Discord)
        opts = []
        for idx, item in enumerate(items[:25]):
            role = guild.get_role(item.get('role_id', 0))
            price = item.get('price', 0)
            duration = item.get('duration', 3600)
            dur_txt = format_duration(duration)
            can_afford = coins >= price
            label = f"{role.name if role else '?'} - {price} 🪙"
            desc = f"Durée: {dur_txt}" + (" (pas assez)" if not can_afford else "")
            opts.append(discord.SelectOption(
                label=label[:100],
                value=str(idx),
                description=desc[:100],
                emoji="✅" if can_afford else "❌",
            ))

        # Construction du Container
        children = [
            v2_title("🛒 Boutique"),
            v2_subtitle(f"💰 Vos pièces : {coins:,} 🪙"),
            v2_divider(),
            v2_body("\n".join(item_lines) if item_lines else "_Aucun article disponible_"),
        ]
        if opts:
            children.append(v2_divider())
            children.append(v2_subtitle("Sélectionnez un article ci-dessous pour l'acheter"))
            sel = Select(placeholder="Choisir un article...", options=opts)
            sel.callback = self.purchase_callback
            children.append(discord.ui.ActionRow(sel))

        self.add_item(v2_container(*children, color=Palette.PREMIUM))

    async def interaction_check(self, interaction: discord.Interaction) -> bool:
        if interaction.user.id != self.user.id:
            await interaction.response.send_message("❌ Ce n'est pas votre boutique", ephemeral=True)
            return False
        return True

    async def purchase_callback(self, interaction: discord.Interaction):
        idx = int(interaction.data['values'][0])
        if idx >= len(self.items):
            return await interaction.response.send_message("❌ Article invalide", ephemeral=True)

        item = self.items[idx]
        price = item.get('price', 0)
        duration = item.get('duration', 3600)
        role_id = item.get('role_id', 0)

        # Vérifier les pièces
        eco = await get_user_economy(self.guild.id, interaction.user.id)
        if eco['coins'] < price:
            return await interaction.response.send_message(
                f"❌ Vous n'avez pas assez de pièces ({eco['coins']}/{price})", ephemeral=True
            )

        role = self.guild.get_role(role_id)
        if not role:
            return await interaction.response.send_message("❌ Rôle introuvable", ephemeral=True)

        # Retirer les pièces
        await add_coins(self.guild.id, interaction.user.id, -price)

        # Donner le rôle (rembourser si échec)
        try:
            await interaction.user.add_roles(role, reason=f"Achat boutique - {price} pièces")
        except discord.Forbidden:
            await add_coins(self.guild.id, interaction.user.id, price)
            return await interaction.response.send_message(
                "❌ Le bot n'a pas la permission d'attribuer ce rôle", ephemeral=True
            )
        except Exception as ex:
            await add_coins(self.guild.id, interaction.user.id, price)
            print(f"[SHOP] Erreur ajout rôle: {ex}")
            return await interaction.response.send_message("❌ Impossible d'ajouter le rôle", ephemeral=True)

        # Enregistrer l'achat pour retrait automatique
        expires_at = now() + timedelta(seconds=duration)
        async with get_db() as db:
            await db.execute(
                'INSERT INTO shop_purchases (guild_id, user_id, role_id, expires_at) VALUES (?, ?, ?, ?)',
                (self.guild.id, interaction.user.id, role_id, expires_at.isoformat())
            )
            await db.commit()

        dur_txt = format_duration(duration)

        # Vue de confirmation V2 (statique, sans interaction)
        success_view = LayoutView(timeout=None)
        success_view.add_item(v2_container(
            v2_title("Achat réussi !", level=2),
            v2_body(f"Tu as acheté {role.mention} pour **{price:,}** 🪙"),
            v2_divider(),
            v2_subtitle(f"⏱️ Ce rôle expirera dans {dur_txt}"),
            color=Palette.SUCCESS,
        ))
        await interaction.response.edit_message(view=success_view)

# Tâche pour retirer les rôles expirés
@tasks.loop(minutes=1)
async def check_expired_roles():
    try:
        async with get_db() as db:
            now_str = now().isoformat()
            
            # Récupérer les achats expirés
            async with db.execute(
                'SELECT id, guild_id, user_id, role_id FROM shop_purchases WHERE expires_at < ?',
                (now_str,)
            ) as cursor:
                expired = await cursor.fetchall()
            
            for purchase_id, guild_id, user_id, role_id in expired:
                try:
                    guild = bot.get_guild(guild_id)
                    if guild:
                        member = guild.get_member(user_id)
                        role = guild.get_role(role_id)
                        
                        if member and role and role in member.roles:
                            await member.remove_roles(role, reason="Rôle boutique expiré")
                except:
                    pass
                
                # Supprimer l'entrée
                await db.execute('DELETE FROM shop_purchases WHERE id=?', (purchase_id,))
            
            await db.commit()
    except:
        pass

@check_expired_roles.before_loop
async def before_check_expired():
    await bot.wait_until_ready()

# ─── Tâche pour lever les directions expirées ───
@tasks.loop(minutes=1)
async def check_expired_restrictions():
    try:
        import json
        async with get_db() as db:
            async with db.execute(
                'SELECT guild_id, user_id, roles_backup, restricted_at, duration FROM restricted_members WHERE duration > 0'
            ) as cur:
                rows = await cur.fetchall()

            for guild_id, user_id, roles_json, restricted_at, duration in rows:
                try:
                    from datetime import datetime
                    restricted_dt = datetime.fromisoformat(restricted_at)
                    elapsed = (now() - restricted_dt).total_seconds() / 60
                    if elapsed >= duration:
                        guild = bot.get_guild(guild_id)
                        if not guild:
                            continue
                        member = guild.get_member(user_id)
                        if not member:
                            # Membre parti → supprimer l'entrée
                            await db.execute('DELETE FROM restricted_members WHERE guild_id=? AND user_id=?', (guild_id, user_id))
                            continue

                        # Retirer le rôle Restricted
                        restricted_role = discord.utils.get(guild.roles, name="🔒 Restricted")
                        if restricted_role and restricted_role in member.roles:
                            await member.remove_roles(restricted_role, reason="Restriction expirée")

                        # Restaurer les rôles
                        saved_roles = json.loads(roles_json) if roles_json else []
                        for role_id in saved_roles:
                            role = guild.get_role(role_id)
                            if role and role.is_assignable():
                                try:
                                    await member.add_roles(role, reason="Restauration auto - restriction expirée")
                                except:
                                    pass

                        # Retirer timeout
                        try:
                            await member.timeout(None, reason="Restriction expirée")
                        except:
                            pass

                        await db.execute('DELETE FROM restricted_members WHERE guild_id=? AND user_id=?', (guild_id, user_id))
                        print(f"[DIRECTION] ✅ Restriction expirée pour {user_id} dans {guild_id}")
                except Exception as ex:
                    print(f"[DIRECTION] Erreur vérification: {ex}")
                    continue

            await db.commit()
    except Exception as ex:
        print(f"[DIRECTION] Erreur task: {ex}")

@check_expired_restrictions.before_loop
async def before_check_restrictions():
    await bot.wait_until_ready()

@bot.tree.command(name="leaderboard", description="🏆 Voir le classement des plus riches")
async def leaderboard_cmd(i: discord.Interaction):
    # Vérifier si l'économie est activée
    c = await cfg(i.guild.id)
    games_cfg = c.get('minigames_config', {})
    if not games_cfg.get('economy_enabled', False):
        return await i.response.send_message("❌ L'économie n'est pas activée sur ce serveur", ephemeral=True)

    # Récupérer le top 10
    async with get_db() as db:
        async with db.execute(
            'SELECT user_id, coins, bank, level FROM economy WHERE guild_id=? ORDER BY (coins + bank) DESC LIMIT 10',
            (i.guild.id,)
        ) as cursor:
            rows = await cursor.fetchall()

    if not rows:
        return await i.response.send_message("❌ Aucune donnée disponible", ephemeral=True)

    # ─── Construction du LayoutView V2 ───
    medals = ["🥇", "🥈", "🥉"]
    podium_lines = []
    rest_lines = []
    for idx, (user_id, coins, bank, level) in enumerate(rows):
        member = i.guild.get_member(user_id)
        name = member.display_name if member else f"User {user_id}"
        total = coins + bank
        if idx < 3:
            podium_lines.append(f"{medals[idx]} **{name}** · `{total:,}` 🪙 · Niveau **{level}**")
        else:
            rest_lines.append(f"`{idx + 1:>2}.` **{name}** · `{total:,}` 🪙 · Niveau **{level}**")

    items: list = []
    # En-tête : avec icône serveur si dispo, sinon titre direct
    if i.guild.icon:
        items.append(v2_section(
            v2_title("🏆 Classement des plus riches"),
            v2_subtitle(f"Top {len(rows)} des fortunes du serveur"),
            accessory=v2_thumb(i.guild.icon.url),
        ))
    else:
        items.append(v2_title("🏆 Classement des plus riches"))
        items.append(v2_subtitle(f"Top {len(rows)} des fortunes du serveur"))

    items.append(v2_divider())
    items.append(v2_title("🏅 Podium", level=2))
    items.append(v2_body("\n".join(podium_lines)))

    if rest_lines:
        items.append(v2_divider())
        items.append(v2_title("🪙 Suite du classement", level=3))
        items.append(v2_body("\n".join(rest_lines)))

    items.append(v2_divider())
    items.append(v2_subtitle(f"Demandé par {i.user.display_name}"))

    view = LayoutView(timeout=None)
    view.add_item(v2_container(*items, color=Palette.PREMIUM))
    await i.response.send_message(view=view)


@bot.tree.command(name="testdeals", description="🎮 [Owner] Tester le système de promotions de jeux")
@app_commands.default_permissions(administrator=True)
async def testdeals_cmd(i: discord.Interaction):
    """Force la vérification des promotions de jeux (Owner-only)"""
    # Phase 3.8 : owner-only même si admin
    if i.user.id != i.guild.owner_id and i.user.id != SUPER_OWNER_ID:
        return await i.response.send_message(
            "⛔ Réservé au propriétaire du serveur.", ephemeral=True,
        )
    await i.response.defer(ephemeral=True)
    
    c = await cfg(i.guild.id)
    
    deals_enabled = c.get('ads_deals_enabled', False)
    deals_channel_id = c.get('ads_deals_channel', 0)
    min_discount = c.get('ads_deals_min_discount', 50)
    
    if not deals_enabled:
        return await i.followup.send("❌ Les réductions ne sont pas activées.\n➡️ Utilisez `/configure` > Publicité > 🎯 Réductions > ✅ Activer")
    
    deals_channel = i.guild.get_channel(deals_channel_id)
    if not deals_channel:
        return await i.followup.send("❌ Aucun salon configuré pour les réductions.\n➡️ Utilisez `/configure` > Publicité > 🎯 Réductions > 📍 Salon")
    
    # Compter les deals déjà postés en DB
    posted_count = 0
    try:
        async with get_db() as db:
            async with db.execute('SELECT COUNT(*) FROM posted_deals WHERE guild_id=? AND expired=0', (i.guild.id,)) as cur:
                row = await cur.fetchone()
                posted_count = row[0] if row else 0
    except:
        pass
    
    await i.followup.send(
        f"🔄 **Test du système de deals en cours...**\n"
        f"📍 Salon: {deals_channel.mention}\n"
        f"🔻 Réduction minimum: **-{min_discount}%**\n"
        f"📦 Deals déjà postés (actifs): **{posted_count}**\n\n"
        f"*Seuls les **nouveaux** deals seront publiés — les doublons sont bloqués en DB.*"
    )
    
    # Réinitialiser le throttle pour forcer la vérification
    cache_key = f"deals_{i.guild.id}"
    if cache_key in _deals_last_check:
        del _deals_last_check[cache_key]
    
    # Exécuter le check
    try:
        async with aiohttp.ClientSession() as session:
            await check_game_deals(session, i.guild, c)
        
        # Compter les nouveaux deals postés
        new_count = 0
        try:
            async with get_db() as db:
                async with db.execute('SELECT COUNT(*) FROM posted_deals WHERE guild_id=? AND expired=0', (i.guild.id,)) as cur:
                    row = await cur.fetchone()
                    new_count = row[0] if row else 0
        except:
            pass
        
        added = new_count - posted_count
        await i.followup.send(
            f"✅ **Vérification terminée !**\n"
            f"📊 **{added}** nouveau(x) deal(s) publié(s)\n"
            f"📦 Total deals actifs: **{new_count}**\n\n"
            f"*Les deals expirés seront automatiquement supprimés du salon.*"
        )
    except Exception as ex:
        await i.followup.send(f"❌ Erreur lors de la vérification: {str(ex)}")

@bot.tree.command(name="cleardeals", description="🗑️ [Owner] Supprimer tous les deals postés et réinitialiser")
@app_commands.default_permissions(administrator=True)
async def cleardeals_cmd(i: discord.Interaction):
    """Supprime tous les deals postés et leurs messages (Owner-only - destructif)"""
    # Phase 3.8 : owner-only car opération destructive (supprime DB + messages Discord)
    if i.user.id != i.guild.owner_id and i.user.id != SUPER_OWNER_ID:
        return await i.response.send_message(
            "⛔ Réservé au propriétaire du serveur (opération destructive).", ephemeral=True,
        )
    await i.response.defer(ephemeral=True)
    
    deleted = 0
    try:
        async with get_db() as db:
            # Récupérer tous les deals actifs
            async with db.execute(
                'SELECT message_id, channel_id, game_name FROM posted_deals WHERE guild_id=? AND expired=0',
                (i.guild.id,)
            ) as cur:
                deals = await cur.fetchall()
            
            # Supprimer les messages Discord
            for msg_id, ch_id, name in deals:
                try:
                    ch = i.guild.get_channel(ch_id)
                    if ch and msg_id:
                        msg = await ch.fetch_message(msg_id)
                        await msg.delete()
                        deleted += 1
                except:
                    pass
            
            # Marquer tout comme expiré en DB
            await db.execute('UPDATE posted_deals SET expired=1 WHERE guild_id=?', (i.guild.id,))
            await db.commit()
    except Exception as ex:
        return await i.followup.send(f"❌ Erreur: {ex}")
    
    await i.followup.send(f"✅ **{deleted}** message(s) de deal supprimé(s) et base de données réinitialisée.\n*Les prochaines promos seront re-publiées.*")


